/* fh-data.js — Food Handler practice (FDA Food Code 2022 basics). 5 topics, all 6 languages.
   window.FH = { cats:[{id,name,blurb}], q:[{cat,a,q,o,e}] } */
window.FH = {"cats":[{"id":"hygiene","name":{"en":"Personal Hygiene & Health","es":"Higiene personal y salud","ru":"Личная гигиена и здоровье","tr":"Kişisel Hijyen ve Sağlık","hi":"व्यक्तिगत स्वच्छता और स्वास्थ्य","ar":"النظافة الشخصية والصحة"},"blurb":{"en":"Handwashing, gloves, no bare-hand contact, and when to stay home.","es":"Lavado de manos, guantes, sin contacto con las manos desnudas, y cuándo quedarse en casa.","ru":"Мытьё рук, перчатки, запрет голых рук и когда оставаться дома.","tr":"El yıkama, eldiven, çıplak elle temas yok ve ne zaman evde kalmalı.","hi":"हाथ धोना, दस्ताने, नंगे हाथ का संपर्क नहीं, और कब घर पर रहें।","ar":"غسل اليدين، والقفازات، وعدم الملامسة باليد العارية، ومتى تبقى في المنزل."}},{"id":"temp","name":{"en":"Time & Temperature","es":"Tiempo y temperatura","ru":"Время и температура","tr":"Zaman ve Sıcaklık","hi":"समय और तापमान","ar":"الوقت ودرجة الحرارة"},"blurb":{"en":"The danger zone, cooking, cooling, holding and thermometers.","es":"La zona de peligro, cocción, enfriamiento, conservación y termómetros.","ru":"Опасная зона, готовка, охлаждение, хранение и термометры.","tr":"Tehlikeli bölge, pişirme, soğutma, muhafaza ve termometreler.","hi":"खतरनाक क्षेत्र, पकाना, ठंडा करना, रखना और थर्मामीटर।","ar":"منطقة الخطر، والطهي، والتبريد، والحفظ، وموازين الحرارة."}},{"id":"crosscontam","name":{"en":"Cross-Contamination & Allergens","es":"Contaminación cruzada y alérgenos","ru":"Перекрёстное загрязнение и аллергены","tr":"Çapraz Bulaşma ve Alerjenler","hi":"क्रॉस-कॉन्टैमिनेशन और एलर्जेन","ar":"التلوث المتبادل ومسببات الحساسية"},"blurb":{"en":"Separation, storage order, and the major food allergens.","es":"Separación, orden de almacenamiento y los principales alérgenos.","ru":"Разделение, порядок хранения и основные пищевые аллергены.","tr":"Ayırma, depolama sırası ve başlıca gıda alerjenleri.","hi":"पृथक्करण, भंडारण क्रम, और प्रमुख खाद्य एलर्जेन।","ar":"الفصل، وترتيب التخزين، ومسببات الحساسية الغذائية الرئيسية."}},{"id":"illness","name":{"en":"Foodborne Illness","es":"Enfermedades transmitidas por alimentos","ru":"Пищевые заболевания","tr":"Gıda Kaynaklı Hastalıklar","hi":"खाद्यजनित बीमारी","ar":"الأمراض المنقولة بالغذاء"},"blurb":{"en":"The Big 6 pathogens, FAT TOM, symptoms and reporting.","es":"Los 6 grandes patógenos, FAT TOM, síntomas y notificación.","ru":"«Большая шестёрка» патогенов, FAT TOM, симптомы и отчётность.","tr":"Büyük 6 patojen, FAT TOM, belirtiler ve bildirim.","hi":"बिग 6 रोगाणु, FAT TOM, लक्षण और रिपोर्टिंग।","ar":"مسببات الأمراض الستة الكبرى، وFAT TOM، والأعراض والإبلاغ."}},{"id":"cleaning","name":{"en":"Cleaning, Receiving & Storage","es":"Limpieza, recepción y almacenamiento","ru":"Уборка, приёмка и хранение","tr":"Temizlik, Teslim Alma ve Depolama","hi":"सफाई, प्राप्ति और भंडारण","ar":"التنظيف والاستلام والتخزين"},"blurb":{"en":"Cleaning vs. sanitizing, the 3-sink method, receiving, FIFO and pests.","es":"Limpieza vs. desinfección, el método de 3 fregaderos, recepción, FIFO y plagas.","ru":"Уборка против дезинфекции, метод трёх моек, приёмка, FIFO и вредители.","tr":"Temizlik vs. sanitasyon, 3 evyeli yöntem, teslim alma, FIFO ve haşereler.","hi":"सफाई बनाम सैनिटाइज़िंग, 3-सिंक विधि, प्राप्ति, FIFO और कीट।","ar":"التنظيف مقابل التطهير، وطريقة الأحواض الثلاثة، والاستلام، وFIFO، والآفات."}}],"q":[{"cat":"hygiene","a":0,"q":{"en":"About how long should a food handler scrub their hands during proper handwashing?","es":"¿Aproximadamente cuánto tiempo debe restregarse las manos un manipulador de alimentos durante un lavado de manos adecuado?","ru":"Примерно сколько времени работник пищевого производства должен тереть руки при правильном мытье рук?","tr":"Bir gıda çalışanı doğru el yıkama sırasında ellerini yaklaşık ne kadar süre ovalamalıdır?","hi":"उचित हाथ धोने के दौरान एक फूड हैंडलर को लगभग कितनी देर तक अपने हाथ रगड़ने चाहिए?","ar":"ما المدة التقريبية التي ينبغي أن يفرك خلالها متداول الطعام يديه أثناء غسل اليدين بطريقة صحيحة؟"},"o":[{"en":"At least 20 seconds","es":"Al menos 20 segundos","ru":"Не менее 20 секунд","tr":"En az 20 saniye","hi":"कम से कम 20 सेकंड","ar":"20 ثانية على الأقل"},{"en":"About 5 seconds","es":"Aproximadamente 5 segundos","ru":"Около 5 секунд","tr":"Yaklaşık 5 saniye","hi":"लगभग 5 सेकंड","ar":"نحو 5 ثوانٍ"},{"en":"At least 2 minutes","es":"Al menos 2 minutos","ru":"Не менее 2 минут","tr":"En az 2 dakika","hi":"कम से कम 2 मिनट","ar":"دقيقتان على الأقل"},{"en":"Only until the soap is rinsed off","es":"Solo hasta que se enjuague el jabón","ru":"Только до тех пор, пока не смоется мыло","tr":"Yalnızca sabun durulanana kadar","hi":"केवल तब तक जब तक साबुन धुल न जाए","ar":"فقط حتى يُشطف الصابون"}],"e":{"en":"The whole handwashing process should take at least 20 seconds, with about 10 to 15 seconds of scrubbing with soap before rinsing and drying.","es":"Todo el proceso de lavado de manos debe durar al menos 20 segundos, con aproximadamente 10 a 15 segundos de restregado con jabón antes de enjuagar y secar.","ru":"Весь процесс мытья рук должен занимать не менее 20 секунд, при этом около 10–15 секунд нужно тереть руки с мылом перед ополаскиванием и высушиванием.","tr":"Tüm el yıkama süreci en az 20 saniye sürmeli; durulama ve kurulamadan önce yaklaşık 10 ila 15 saniye sabunla ovalama yapılmalıdır.","hi":"पूरी हाथ धोने की प्रक्रिया में कम से कम 20 सेकंड लगने चाहिए, जिसमें धोने और सुखाने से पहले लगभग 10 से 15 सेकंड साबुन के साथ रगड़ना शामिल है।","ar":"ينبغي أن تستغرق عملية غسل اليدين بأكملها 20 ثانية على الأقل، مع نحو 10 إلى 15 ثانية من الفرك بالصابون قبل الشطف والتجفيف."}},{"cat":"hygiene","a":2,"q":{"en":"Which of these should a food handler use to wash their hands?","es":"¿Cuál de estos debe usar un manipulador de alimentos para lavarse las manos?","ru":"Что из перечисленного работник пищевого производства должен использовать для мытья рук?","tr":"Bir gıda çalışanı ellerini yıkamak için bunlardan hangisini kullanmalıdır?","hi":"एक फूड हैंडलर को अपने हाथ धोने के लिए इनमें से किसका उपयोग करना चाहिए?","ar":"أيٌّ مما يلي ينبغي أن يستخدمه متداول الطعام لغسل يديه؟"},"o":[{"en":"Hand sanitizer alone","es":"Solo desinfectante de manos","ru":"Только дезинфицирующее средство для рук","tr":"Tek başına el dezenfektanı","hi":"केवल हैंड सैनिटाइज़र","ar":"معقم اليدين وحده"},{"en":"Cold water with no soap","es":"Agua fría sin jabón","ru":"Холодную воду без мыла","tr":"Sabunsuz soğuk su","hi":"बिना साबुन के ठंडा पानी","ar":"ماء بارد دون صابون"},{"en":"Soap and running warm water","es":"Jabón y agua corriente tibia","ru":"Мыло и проточную тёплую воду","tr":"Sabun ve akan ılık su","hi":"साबुन और बहता हुआ गुनगुना पानी","ar":"الصابون والماء الدافئ الجاري"},{"en":"A damp wiping cloth","es":"Un paño de limpieza húmedo","ru":"Влажную салфетку для протирания","tr":"Nemli bir silme bezi","hi":"एक नम पोंछने वाला कपड़ा","ar":"قطعة قماش مبللة للمسح"}],"e":{"en":"Proper handwashing requires soap and running warm water followed by drying; hand sanitizer is not a substitute for washing.","es":"El lavado de manos adecuado requiere jabón y agua corriente tibia, seguido del secado; el desinfectante de manos no sustituye el lavado.","ru":"Правильное мытьё рук требует мыла и проточной тёплой воды с последующим высушиванием; дезинфицирующее средство для рук не заменяет мытьё.","tr":"Doğru el yıkama, sabun ve akan ılık su ile yıkamayı ve ardından kurulamayı gerektirir; el dezenfektanı yıkamanın yerini tutmaz.","hi":"उचित हाथ धोने के लिए साबुन और बहते हुए गुनगुने पानी की आवश्यकता होती है, उसके बाद सुखाना; हैंड सैनिटाइज़र हाथ धोने का विकल्प नहीं है।","ar":"يتطلب غسل اليدين الصحيح الصابون والماء الدافئ الجاري يتبعه التجفيف؛ ومعقم اليدين ليس بديلاً عن الغسل."}},{"cat":"hygiene","a":1,"q":{"en":"A cook is about to prepare a salad that will be served without further cooking. What does the Food Code require?","es":"Un cocinero está a punto de preparar una ensalada que se servirá sin cocción posterior. ¿Qué exige el Código de Alimentos (Food Code)?","ru":"Повар собирается приготовить салат, который будет подан без дальнейшей тепловой обработки. Что требует Food Code (Пищевой кодекс)?","tr":"Bir aşçı, ek pişirme yapılmadan servis edilecek bir salata hazırlamak üzeredir. Gıda Kanunu (Food Code) ne gerektirir?","hi":"एक रसोइया एक ऐसा सलाद बनाने वाला है जिसे बिना और पकाए परोसा जाएगा। फूड कोड क्या आवश्यक मानता है?","ar":"يوشك طاهٍ على تحضير سلطة سيتم تقديمها دون طهي إضافي. ماذا يشترط قانون الغذاء (Food Code)؟"},"o":[{"en":"Bare hands are fine since the salad is fresh","es":"Las manos sin guantes están bien porque la ensalada es fresca","ru":"Голыми руками можно, ведь салат свежий","tr":"Salata taze olduğundan çıplak el kullanmak sorunsuzdur","hi":"चूंकि सलाद ताज़ा है, इसलिए नंगे हाथ ठीक हैं","ar":"لا بأس بملامسة اليدين العاريتين لأن السلطة طازجة"},{"en":"No bare-hand contact with the ready-to-eat food","es":"No tocar el alimento listo para comer con las manos descubiertas","ru":"Нельзя касаться готовых к употреблению продуктов голыми руками","tr":"Yemeye hazır gıdaya çıplak elle temas edilmemelidir","hi":"खाने के लिए तैयार भोजन के साथ नंगे हाथों का संपर्क नहीं","ar":"عدم ملامسة الطعام الجاهز للأكل باليدين العاريتين"},{"en":"Bare-hand contact is allowed if hands were just washed","es":"Se permite el contacto con las manos descubiertas si las manos se acaban de lavar","ru":"Касание голыми руками допустимо, если руки только что вымыли","tr":"Eller az önce yıkanmışsa çıplak elle temas edilebilir","hi":"अगर हाथ अभी-अभी धोए गए हों तो नंगे हाथों का संपर्क स्वीकार्य है","ar":"يُسمح بملامسة اليدين العاريتين إذا كانتا قد غُسلتا للتو"},{"en":"Only the person in charge may touch ready-to-eat food","es":"Solo la persona a cargo puede tocar el alimento listo para comer","ru":"Только ответственное лицо может касаться готовых к употреблению продуктов","tr":"Yemeye hazır gıdaya yalnızca sorumlu kişi dokunabilir","hi":"केवल प्रभारी व्यक्ति ही खाने के लिए तैयार भोजन को छू सकता है","ar":"يجوز للمسؤول وحده ملامسة الطعام الجاهز للأكل"}],"e":{"en":"Food handlers may not touch ready-to-eat food with bare hands; they must use gloves, tongs, deli paper, or other utensils.","es":"Los manipuladores de alimentos no pueden tocar los alimentos listos para comer con las manos descubiertas; deben usar guantes, pinzas, papel de charcutería u otros utensilios.","ru":"Работники пищевого производства не должны касаться готовых к употреблению продуктов голыми руками; они обязаны использовать перчатки, щипцы, специальную бумагу или другую утварь.","tr":"Gıda çalışanları yemeye hazır gıdaya çıplak elle dokunamaz; eldiven, maşa, deli kağıdı veya başka aletler kullanmalıdırlar.","hi":"फूड हैंडलर खाने के लिए तैयार भोजन को नंगे हाथों से नहीं छू सकते; उन्हें दस्ताने, चिमटे, डेली पेपर, या अन्य बर्तनों का उपयोग करना चाहिए।","ar":"لا يجوز لمتداولي الطعام ملامسة الطعام الجاهز للأكل باليدين العاريتين؛ بل يجب عليهم استخدام القفازات أو الملاقط أو ورق التغليف (deli paper) أو أدوات أخرى."}},{"cat":"hygiene","a":3,"q":{"en":"Which symptom requires a food handler to report to the person in charge AND typically stay home?","es":"¿Qué síntoma exige que un manipulador de alimentos lo reporte a la persona a cargo Y, por lo general, se quede en casa?","ru":"Какой симптом обязывает работника пищевого производства сообщить ответственному лицу И, как правило, остаться дома?","tr":"Hangi belirti, bir gıda çalışanının sorumlu kişiye bildirimde bulunmasını VE genellikle evde kalmasını gerektirir?","hi":"किस लक्षण के लिए एक फूड हैंडलर को प्रभारी व्यक्ति को रिपोर्ट करना AND आमतौर पर घर पर रहना आवश्यक है?","ar":"أيُّ عَرَض يُلزِم متداول الطعام بإبلاغ المسؤول، ويستوجب عادةً البقاء في المنزل؟"},"o":[{"en":"A mild headache","es":"Un dolor de cabeza leve","ru":"Лёгкая головная боль","tr":"Hafif bir baş ağrısı","hi":"हल्का सिरदर्द","ar":"صداع خفيف"},{"en":"A runny nose from allergies","es":"Goteo nasal por alergias","ru":"Насморк из-за аллергии","tr":"Alerjiye bağlı burun akıntısı","hi":"एलर्जी से बहती नाक","ar":"سيلان الأنف بسبب الحساسية"},{"en":"Feeling tired after a long shift","es":"Sentirse cansado después de un turno largo","ru":"Усталость после длинной смены","tr":"Uzun bir vardiyadan sonra yorgun hissetmek","hi":"लंबी शिफ्ट के बाद थकान महसूस करना","ar":"الشعور بالتعب بعد مناوبة طويلة"},{"en":"Vomiting or diarrhea","es":"Vómito o diarrea","ru":"Рвота или диарея","tr":"Kusma veya ishal","hi":"उल्टी या दस्त","ar":"التقيؤ أو الإسهال"}],"e":{"en":"Vomiting and diarrhea are reportable symptoms that require excluding the employee from the establishment until they are symptom-free as required.","es":"El vómito y la diarrea son síntomas que deben reportarse y que exigen excluir al empleado del establecimiento hasta que esté libre de síntomas según lo requerido.","ru":"Рвота и диарея — это симптомы, подлежащие обязательному уведомлению, которые требуют отстранения работника от заведения до тех пор, пока он не будет свободен от симптомов, как предписано.","tr":"Kusma ve ishal, bildirimi zorunlu belirtilerdir ve çalışanın gerekli süre boyunca belirtileri geçene kadar işletmeden uzaklaştırılmasını (hariç tutulmasını) gerektirir.","hi":"उल्टी और दस्त रिपोर्ट करने योग्य लक्षण हैं जिनके लिए कर्मचारी को आवश्यकतानुसार लक्षण-मुक्त होने तक प्रतिष्ठान से बाहर रखना आवश्यक है।","ar":"يُعدّ التقيؤ والإسهال من الأعراض الواجب الإبلاغ عنها، وهي تستوجب استبعاد الموظف من المنشأة إلى أن يتعافى من الأعراض وفق ما هو مطلوب."}},{"cat":"hygiene","a":1,"q":{"en":"How should a food handler wearing single-use gloves handle a small cut on a finger?","es":"¿Cómo debe manejar un manipulador de alimentos que usa guantes desechables un pequeño corte en un dedo?","ru":"Как работник пищевого производства, носящий одноразовые перчатки, должен поступить с небольшим порезом на пальце?","tr":"Tek kullanımlık eldiven giyen bir gıda çalışanı, parmağındaki küçük bir kesiği nasıl ele almalıdır?","hi":"एकल-उपयोग दस्ताने पहने हुए एक फूड हैंडलर को अपनी उंगली पर एक छोटे से कट को कैसे संभालना चाहिए?","ar":"كيف ينبغي لمتداول طعام يرتدي قفازات أحادية الاستخدام أن يتعامل مع جرح صغير في إصبعه؟"},"o":[{"en":"Just wash the cut and keep working bare-handed","es":"Solo lavar el corte y seguir trabajando con las manos descubiertas","ru":"Просто промыть порез и продолжать работать голыми руками","tr":"Sadece kesiği yıkayıp çıplak elle çalışmaya devam etmeli","hi":"बस कट को धोएं और नंगे हाथों से काम करते रहें","ar":"مجرد غسل الجرح والاستمرار في العمل باليدين العاريتين"},{"en":"Cover it with a bandage and a finger cot, then put a glove over it","es":"Cubrirlo con una venda y un dedil, y luego ponerse un guante encima","ru":"Закрыть его пластырем и напальчником, а затем надеть сверху перчатку","tr":"Yara bandı ve parmak kılıfı (finger cot) ile kapatıp üzerine eldiven giymeli","hi":"इसे एक पट्टी और एक फिंगर कॉट से ढकें, फिर उसके ऊपर एक दस्ताना पहनें","ar":"تغطيته بلاصق طبي وكُمّ إصبعي (finger cot)، ثم وضع قفاز فوقه"},{"en":"Cover it with a cloth napkin tucked into the glove","es":"Cubrirlo con una servilleta de tela metida dentro del guante","ru":"Закрыть его тканевой салфеткой, заправленной в перчатку","tr":"Eldivenin içine sıkıştırılmış bir kumaş peçeteyle kapatmalı","hi":"इसे दस्ताने में दबाए गए कपड़े के नैपकिन से ढकें","ar":"تغطيته بمنديل قماشي مثبَّت داخل القفاز"},{"en":"Leave it uncovered since the glove is enough","es":"Dejarlo descubierto porque el guante es suficiente","ru":"Оставить его открытым, ведь перчатки достаточно","tr":"Eldiven yeterli olduğundan açık bırakmalı","hi":"इसे खुला छोड़ दें क्योंकि दस्ताना ही काफी है","ar":"تركه مكشوفاً لأن القفاز كافٍ"}],"e":{"en":"Cuts or wounds on the hand must be covered with a waterproof bandage plus a finger cot and/or single-use glove to prevent contamination.","es":"Los cortes o heridas en la mano deben cubrirse con una venda impermeable más un dedil o un guante desechable para evitar la contaminación.","ru":"Порезы или раны на руке должны быть закрыты водонепроницаемым пластырем плюс напальчником и/или одноразовой перчаткой, чтобы предотвратить загрязнение.","tr":"El üzerindeki kesikler veya yaralar, kontaminasyonu önlemek için su geçirmez bir yara bandının yanı sıra bir parmak kılıfı ve/veya tek kullanımlık eldivenle kapatılmalıdır.","hi":"हाथ पर कट या घावों को संदूषण रोकने के लिए एक जलरोधक पट्टी के साथ एक फिंगर कॉट और/या एकल-उपयोग दस्ताने से ढका जाना चाहिए।","ar":"يجب تغطية الجروح أو الإصابات في اليد بلاصق طبي مقاوم للماء مع كُمّ إصبعي (finger cot) و/أو قفاز أحادي الاستخدام لمنع التلوث."}},{"cat":"hygiene","a":3,"q":{"en":"Why must food handlers wear an effective hair restraint while working with food?","es":"¿Por qué deben usar los manipuladores de alimentos una sujeción eficaz para el cabello mientras trabajan con alimentos?","ru":"Почему работники пищевого производства должны носить эффективное средство для фиксации волос во время работы с продуктами?","tr":"Gıda çalışanları neden gıdayla çalışırken etkili bir saç koruyucu (bone vb.) takmalıdır?","hi":"भोजन के साथ काम करते समय फूड हैंडलर को प्रभावी बाल अवरोधक क्यों पहनना चाहिए?","ar":"لماذا يجب على متداولي الطعام ارتداء غطاء فعّال للشعر أثناء العمل مع الطعام؟"},"o":[{"en":"Because hair restraints keep the kitchen cooler","es":"Porque las sujeciones para el cabello mantienen la cocina más fresca","ru":"Потому что средства для фиксации волос сохраняют прохладу на кухне","tr":"Saç koruyucular mutfağı serin tuttuğu için","hi":"क्योंकि बाल अवरोधक रसोई को ठंडा रखते हैं","ar":"لأن أغطية الشعر تُبقي المطبخ أكثر برودة"},{"en":"To replace the need for handwashing","es":"Para reemplazar la necesidad de lavarse las manos","ru":"Чтобы заменить необходимость мытья рук","tr":"El yıkama ihtiyacının yerini almak için","hi":"हाथ धोने की आवश्यकता को बदलने के लिए","ar":"لتحل محل الحاجة إلى غسل اليدين"},{"en":"Only to look professional for customers","es":"Solo para verse profesionales ante los clientes","ru":"Только чтобы выглядеть профессионально для клиентов","tr":"Sadece müşterilere karşı profesyonel görünmek için","hi":"केवल ग्राहकों के लिए पेशेवर दिखने के लिए","ar":"فقط ليبدو مظهرهم احترافياً أمام الزبائن"},{"en":"To keep hair from falling into food and to reduce touching the hair","es":"Para evitar que el cabello caiga en los alimentos y para reducir el contacto con el cabello","ru":"Чтобы волосы не попадали в продукты и чтобы реже трогать волосы","tr":"Saçın gıdaya düşmesini önlemek ve saça dokunmayı azaltmak için","hi":"बालों को भोजन में गिरने से रोकने और बालों को छूने को कम करने के लिए","ar":"لمنع تساقط الشعر في الطعام ولتقليل ملامسة الشعر"}],"e":{"en":"Hair restraints such as hats or nets keep hair out of food and discourage workers from touching their hair, which can contaminate hands.","es":"Las sujeciones para el cabello, como gorros o redecillas, mantienen el cabello fuera de los alimentos y desalientan a los trabajadores de tocarse el cabello, lo que puede contaminar las manos.","ru":"Средства для фиксации волос, такие как головные уборы или сетки, не позволяют волосам попадать в продукты и отбивают у работников желание трогать волосы, что может загрязнить руки.","tr":"Şapka veya file gibi saç koruyucular, saçı gıdadan uzak tutar ve çalışanların elleri kirletebilecek şekilde saçlarına dokunmalarını engeller.","hi":"टोपी या जाल जैसे बाल अवरोधक बालों को भोजन से बाहर रखते हैं और कर्मचारियों को अपने बालों को छूने से हतोत्साहित करते हैं, जो हाथों को दूषित कर सकता है।","ar":"تُبقي أغطية الشعر مثل القبعات أو الشبكات الشعرَ بعيداً عن الطعام وتثني العاملين عن ملامسة شعرهم، الأمر الذي قد يلوّث اليدين."}},{"cat":"hygiene","a":0,"q":{"en":"Which jewelry is generally permitted on the hands while preparing food?","es":"¿Qué joyería se permite generalmente en las manos al preparar alimentos?","ru":"Какие украшения обычно разрешено носить на руках при приготовлении пищи?","tr":"Gıda hazırlarken ellerde genellikle hangi takıya izin verilir?","hi":"भोजन तैयार करते समय हाथों पर आम तौर पर कौन से आभूषण की अनुमति है?","ar":"أيُّ نوع من المجوهرات يُسمح به عموماً على اليدين أثناء تحضير الطعام؟"},"o":[{"en":"A plain ring such as a wedding band","es":"Un anillo liso como una alianza de boda","ru":"Простое кольцо, например обручальное","tr":"Alyans gibi düz (taşsız) bir yüzük","hi":"एक सादी अंगूठी जैसे शादी का छल्ला","ar":"خاتم بسيط مثل خاتم الزواج"},{"en":"A ring with a raised stone setting","es":"Un anillo con una piedra en engaste elevado","ru":"Кольцо с выступающей вставкой-камнем","tr":"Kabartmalı taş yuvası olan bir yüzük","hi":"उभरे हुए पत्थर की सेटिंग वाली एक अंगूठी","ar":"خاتم بفص بارز مرصّع"},{"en":"A bracelet and a wristwatch","es":"Una pulsera y un reloj de muñeca","ru":"Браслет и наручные часы","tr":"Bir bilezik ve bir kol saati","hi":"एक कंगन और एक कलाई घड़ी","ar":"سوار وساعة معصم"},{"en":"No restrictions apply to hand jewelry","es":"No se aplican restricciones a la joyería de las manos","ru":"Никаких ограничений на украшения для рук нет","tr":"El takıları için herhangi bir kısıtlama yoktur","hi":"हाथ के आभूषणों पर कोई प्रतिबंध लागू नहीं होता","ar":"لا توجد قيود على مجوهرات اليد"}],"e":{"en":"A plain band may be worn, but other hand and arm jewelry like stoned rings, bracelets, and watches must be removed because they can harbor pathogens and fall into food.","es":"Se puede usar una alianza lisa, pero otra joyería de manos y brazos, como anillos con piedras, pulseras y relojes, debe quitarse porque puede albergar patógenos y caer en los alimentos.","ru":"Простое кольцо носить можно, но другие украшения для рук и запястий, такие как кольца с камнями, браслеты и часы, должны быть сняты, поскольку они могут служить рассадником патогенов и попадать в продукты.","tr":"Düz bir alyans takılabilir, ancak taşlı yüzükler, bilezikler ve saatler gibi diğer el ve kol takıları, patojen barındırabileceği ve gıdaya düşebileceği için çıkarılmalıdır.","hi":"एक सादा छल्ला पहना जा सकता है, लेकिन पत्थर जड़ी अंगूठियां, कंगन और घड़ियों जैसे अन्य हाथ और बांह के आभूषणों को हटाया जाना चाहिए क्योंकि वे रोगजनकों को आश्रय दे सकते हैं और भोजन में गिर सकते हैं।","ar":"يُسمح بارتداء خاتم بسيط، لكن يجب نزع مجوهرات اليد والذراع الأخرى كالخواتم المرصّعة والأساور والساعات لأنها قد تؤوي مسببات الأمراض وتسقط في الطعام."}},{"cat":"hygiene","a":2,"q":{"en":"Which activity is NOT allowed in food preparation areas?","es":"¿Qué actividad NO está permitida en las áreas de preparación de alimentos?","ru":"Какое действие НЕ разрешено в зонах приготовления пищи?","tr":"Gıda hazırlama alanlarında hangi etkinliğe izin verilmez?","hi":"भोजन तैयारी क्षेत्रों में कौन सी गतिविधि की अनुमति नहीं है?","ar":"أيُّ نشاط غير مسموح به في مناطق تحضير الطعام؟"},"o":[{"en":"Washing hands at the handwashing sink","es":"Lavarse las manos en el lavabo para lavado de manos","ru":"Мытьё рук в раковине для мытья рук","tr":"El yıkama lavabosunda el yıkamak","hi":"हाथ धोने के सिंक पर हाथ धोना","ar":"غسل اليدين في حوض غسل اليدين"},{"en":"Wearing a clean apron","es":"Usar un delantal limpio","ru":"Ношение чистого фартука","tr":"Temiz bir önlük giymek","hi":"एक साफ एप्रन पहनना","ar":"ارتداء مريلة نظيفة"},{"en":"Eating, smoking, or chewing gum","es":"Comer, fumar o masticar chicle","ru":"Приём пищи, курение или жевание жвачки","tr":"Yemek yemek, sigara içmek veya sakız çiğnemek","hi":"खाना, धूम्रपान, या च्युइंग गम चबाना","ar":"الأكل أو التدخين أو مضغ العلكة"},{"en":"Putting on single-use gloves","es":"Ponerse guantes desechables","ru":"Надевание одноразовых перчаток","tr":"Tek kullanımlık eldiven giymek","hi":"एकल-उपयोग दस्ताने पहनना","ar":"ارتداء قفازات أحادية الاستخدام"}],"e":{"en":"Eating, drinking from open containers, smoking, and chewing gum are prohibited in prep areas because they can transfer saliva and contaminants to food.","es":"Comer, beber de recipientes abiertos, fumar y masticar chicle están prohibidos en las áreas de preparación porque pueden transferir saliva y contaminantes a los alimentos.","ru":"Приём пищи, питьё из открытых ёмкостей, курение и жевание жвачки запрещены в зонах приготовления, поскольку они могут перенести слюну и загрязняющие вещества на продукты.","tr":"Yemek yemek, açık kaplardan içmek, sigara içmek ve sakız çiğnemek; tükürük ve kirleticileri gıdaya bulaştırabileceği için hazırlık alanlarında yasaktır.","hi":"भोजन तैयारी क्षेत्रों में खाना, खुले कंटेनरों से पीना, धूम्रपान और च्युइंग गम चबाना निषिद्ध है क्योंकि वे लार और संदूषकों को भोजन में स्थानांतरित कर सकते हैं।","ar":"يُحظر الأكل والشرب من حاويات مفتوحة والتدخين ومضغ العلكة في مناطق التحضير لأنها قد تنقل اللعاب والملوثات إلى الطعام."}},{"cat":"hygiene","a":3,"q":{"en":"What is the rule for a food handler's fingernails?","es":"¿Cuál es la regla para las uñas de un manipulador de alimentos?","ru":"Каково правило относительно ногтей работника пищевого производства?","tr":"Bir gıda çalışanının tırnaklarıyla ilgili kural nedir?","hi":"एक फूड हैंडलर के नाखूनों के लिए नियम क्या है?","ar":"ما القاعدة المتعلقة بأظافر متداول الطعام؟"},"o":[{"en":"Long nails are fine if gloves are never worn","es":"Las uñas largas están bien si nunca se usan guantes","ru":"Длинные ногти допустимы, если перчатки никогда не надеваются","tr":"Hiç eldiven giyilmiyorsa uzun tırnaklar sorunsuzdur","hi":"यदि दस्ताने कभी नहीं पहने जाते तो लंबे नाखून ठीक हैं","ar":"لا بأس بالأظافر الطويلة إذا لم تُرتدَ القفازات أبداً"},{"en":"Artificial nails are allowed at all food stations","es":"Las uñas artificiales se permiten en todas las estaciones de alimentos","ru":"Искусственные ногти разрешены на всех пищевых станциях","tr":"Tüm gıda istasyonlarında takma tırnaklara izin verilir","hi":"सभी भोजन स्टेशनों पर कृत्रिम नाखूनों की अनुमति है","ar":"يُسمح بالأظافر الاصطناعية في جميع محطات الطعام"},{"en":"Dark nail polish is preferred so chips are visible","es":"Se prefiere el esmalte de uñas oscuro para que las desconchaduras se vean","ru":"Тёмный лак предпочтительнее, чтобы сколы были заметны","tr":"Çatlaklar görünür olsun diye koyu renk oje tercih edilir","hi":"गहरी नेल पॉलिश को प्राथमिकता दी जाती है ताकि छीलन दिखाई दे","ar":"يُفضَّل طلاء الأظافر الداكن لكي تظهر القشور"},{"en":"Keep them clean, trimmed, and filed so edges are smooth","es":"Mantenerlas limpias, recortadas y limadas para que los bordes queden lisos","ru":"Держите их чистыми, подстриженными и подпиленными, чтобы края были гладкими","tr":"Kenarları pürüzsüz olacak şekilde temiz, kısa ve düzgün kesilmiş tutulmalı","hi":"उन्हें साफ, छंटे हुए, और घिसे हुए रखें ताकि किनारे चिकने हों","ar":"إبقاؤها نظيفة ومقصوصة ومبرَّدة بحيث تكون حوافها ملساء"}],"e":{"en":"Nails must be kept short, clean, and filed smooth; nail polish and artificial nails are not allowed when working with exposed food unless intact gloves are worn.","es":"Las uñas deben mantenerse cortas, limpias y limadas; no se permite el esmalte de uñas ni las uñas artificiales al trabajar con alimentos expuestos, a menos que se usen guantes intactos.","ru":"Ногти должны быть короткими, чистыми и подпиленными до гладкости; лак для ногтей и искусственные ногти не допускаются при работе с открытыми продуктами, если только не надеты целые перчатки.","tr":"Tırnaklar kısa, temiz ve pürüzsüz şekilde törpülenmiş tutulmalıdır; sağlam eldiven giyilmediği sürece açık gıdayla çalışırken oje ve takma tırnaklara izin verilmez.","hi":"नाखूनों को छोटा, साफ, और चिकना घिसा हुआ रखा जाना चाहिए; उजागर भोजन के साथ काम करते समय नेल पॉलिश और कृत्रिम नाखूनों की अनुमति नहीं है, जब तक कि सही-सलामत दस्ताने न पहने जाएं।","ar":"يجب إبقاء الأظافر قصيرة ونظيفة ومبرَّدة بحيث تكون ملساء؛ ولا يُسمح بطلاء الأظافر ولا بالأظافر الاصطناعية عند العمل مع الطعام المكشوف ما لم تُرتدَ قفازات سليمة."}},{"cat":"hygiene","a":1,"q":{"en":"A food handler finishes cutting raw chicken and now needs to prepare a fresh garnish. What should they do with their gloves?","es":"Un manipulador de alimentos termina de cortar pollo crudo y ahora necesita preparar una guarnición fresca. ¿Qué debe hacer con sus guantes?","ru":"Работник пищевого производства закончил резать сырую курицу и теперь должен приготовить свежий гарнир. Что он должен сделать со своими перчатками?","tr":"Bir gıda çalışanı çiğ tavuk doğramayı bitirir ve şimdi taze bir garnitür hazırlaması gerekir. Eldivenleriyle ne yapmalıdır?","hi":"एक फूड हैंडलर कच्चा चिकन काटना समाप्त करता है और अब उसे एक ताज़ा गार्निश तैयार करने की आवश्यकता है। उसे अपने दस्ताने के साथ क्या करना चाहिए?","ar":"ينتهي متداول طعام من تقطيع دجاج نيء وعليه الآن تحضير زينة طازجة. ماذا ينبغي أن يفعل بقفازاته؟"},"o":[{"en":"Keep the same gloves to save time","es":"Conservar los mismos guantes para ahorrar tiempo","ru":"Оставить те же перчатки, чтобы сэкономить время","tr":"Zaman kazanmak için aynı eldivenleri kullanmaya devam etmeli","hi":"समय बचाने के लिए वही दस्ताने रखें","ar":"إبقاء القفازات نفسها لتوفير الوقت"},{"en":"Remove the gloves, wash hands, and put on a new pair","es":"Quitarse los guantes, lavarse las manos y ponerse un par nuevo","ru":"Снять перчатки, вымыть руки и надеть новую пару","tr":"Eldivenleri çıkarmalı, ellerini yıkamalı ve yeni bir çift giymeli","hi":"दस्ताने हटाएं, हाथ धोएं, और एक नई जोड़ी पहनें","ar":"نزع القفازات وغسل اليدين وارتداء زوج جديد"},{"en":"Rinse the gloves under water and continue","es":"Enjuagar los guantes bajo el agua y continuar","ru":"Ополоснуть перчатки под водой и продолжить","tr":"Eldivenleri suyun altında durulayıp devam etmeli","hi":"दस्ताने को पानी के नीचे धोएं और जारी रखें","ar":"شطف القفازات تحت الماء والمتابعة"},{"en":"Wipe the gloves on a clean towel and continue","es":"Limpiar los guantes con una toalla limpia y continuar","ru":"Вытереть перчатки чистым полотенцем и продолжить","tr":"Eldivenleri temiz bir havluya silip devam etmeli","hi":"दस्ताने को एक साफ तौलिये पर पोंछें और जारी रखें","ar":"مسح القفازات بمنشفة نظيفة والمتابعة"}],"e":{"en":"Gloves are single-use; after handling raw poultry the worker must discard the gloves, wash hands, and don a new pair to avoid cross-contamination.","es":"Los guantes son desechables; después de manipular aves crudas, el trabajador debe desechar los guantes, lavarse las manos y ponerse un par nuevo para evitar la contaminación cruzada.","ru":"Перчатки одноразовые; после работы с сырой птицей работник должен выбросить перчатки, вымыть руки и надеть новую пару, чтобы избежать перекрёстного загрязнения.","tr":"Eldivenler tek kullanımlıktır; çalışan, çiğ kümes hayvanı işledikten sonra çapraz bulaşmayı önlemek için eldivenleri atmalı, ellerini yıkamalı ve yeni bir çift giymelidir.","hi":"दस्ताने एकल-उपयोग वाले होते हैं; कच्चे पोल्ट्री को संभालने के बाद कर्मचारी को क्रॉस-कॉन्टैमिनेशन से बचने के लिए दस्ताने को फेंक देना चाहिए, हाथ धोने चाहिए, और एक नई जोड़ी पहननी चाहिए।","ar":"القفازات أحادية الاستخدام؛ فبعد التعامل مع الدواجن النيئة يجب على العامل التخلص من القفازات وغسل اليدين وارتداء زوج جديد لتجنب التلوث المتبادل."}},{"cat":"hygiene","a":2,"q":{"en":"Before putting on a fresh pair of single-use gloves, a food handler should first do what?","es":"Antes de ponerse un par nuevo de guantes desechables, ¿qué debe hacer primero un manipulador de alimentos?","ru":"Прежде чем надеть свежую пару одноразовых перчаток, работник пищевого производства должен сначала сделать что?","tr":"Temiz bir çift tek kullanımlık eldiven giymeden önce, bir gıda çalışanı ilk olarak ne yapmalıdır?","hi":"एकल-उपयोग दस्ताने की एक नई जोड़ी पहनने से पहले, एक फूड हैंडलर को सबसे पहले क्या करना चाहिए?","ar":"قبل ارتداء زوج جديد من القفازات أحادية الاستخدام، ماذا ينبغي لمتداول الطعام أن يفعل أولاً؟"},"o":[{"en":"Apply hand lotion to the gloves","es":"Aplicar loción para manos a los guantes","ru":"Нанести лосьон для рук на перчатки","tr":"Eldivenlere el losyonu sürmeli","hi":"दस्ताने पर हैंड लोशन लगाएं","ar":"وضع مرطّب اليدين على القفازات"},{"en":"Rinse the gloves in sanitizer","es":"Enjuagar los guantes en desinfectante","ru":"Ополоснуть перчатки в дезинфицирующем средстве","tr":"Eldivenleri dezenfektanda durulamalı","hi":"दस्ताने को सैनिटाइज़र में धोएं","ar":"شطف القفازات في المطهّر"},{"en":"Wash and dry their hands","es":"Lavarse y secarse las manos","ru":"Вымыть и высушить руки","tr":"Ellerini yıkayıp kurulamalı","hi":"अपने हाथ धोएं और सुखाएं","ar":"غسل يديه وتجفيفهما"},{"en":"Blow into the gloves to open them","es":"Soplar dentro de los guantes para abrirlos","ru":"Подуть в перчатки, чтобы раскрыть их","tr":"Açmak için eldivenlerin içine üflemeli","hi":"दस्ताने खोलने के लिए उनमें फूंक मारें","ar":"النفخ في القفازات لفتحها"}],"e":{"en":"Hands must be washed and dried before gloving; gloves do not replace handwashing and can spread pathogens if put on over dirty hands.","es":"Las manos deben lavarse y secarse antes de ponerse los guantes; los guantes no reemplazan el lavado de manos y pueden propagar patógenos si se ponen sobre manos sucias.","ru":"Руки должны быть вымыты и высушены перед надеванием перчаток; перчатки не заменяют мытьё рук и могут распространять патогены, если их надеть на грязные руки.","tr":"Eldiven giymeden önce eller yıkanıp kurulanmalıdır; eldivenler el yıkamanın yerini tutmaz ve kirli ellerin üzerine giyilirse patojen yayabilir.","hi":"दस्ताने पहनने से पहले हाथों को धोया और सुखाया जाना चाहिए; दस्ताने हाथ धोने की जगह नहीं लेते और अगर गंदे हाथों पर पहने जाएं तो रोगजनकों को फैला सकते हैं।","ar":"يجب غسل اليدين وتجفيفهما قبل ارتداء القفازات؛ فالقفازات لا تحل محل غسل اليدين، وقد تنشر مسببات الأمراض إذا ارتُديت فوق يدين متسختين."}},{"cat":"hygiene","a":0,"q":{"en":"Which is one of the times a food handler is required to wash their hands?","es":"¿Cuál es uno de los momentos en que un manipulador de alimentos debe lavarse las manos?","ru":"Что является одним из случаев, когда работник пищевого производства обязан вымыть руки?","tr":"Bir gıda çalışanının ellerini yıkamasının gerektiği durumlardan biri hangisidir?","hi":"उन समयों में से एक कौन सा है जब एक फूड हैंडलर को अपने हाथ धोने की आवश्यकता होती है?","ar":"ما إحدى الحالات التي يُلزَم فيها متداول الطعام بغسل يديه؟"},"o":[{"en":"After using the restroom","es":"Después de usar el baño","ru":"После посещения туалета","tr":"Tuvaleti kullandıktan sonra","hi":"शौचालय का उपयोग करने के बाद","ar":"بعد استخدام دورة المياه"},{"en":"Once at the start of each shift only","es":"Solo una vez al inicio de cada turno","ru":"Только один раз в начале каждой смены","tr":"Yalnızca her vardiyanın başında bir kez","hi":"केवल हर शिफ्ट की शुरुआत में एक बार","ar":"مرة واحدة فقط في بداية كل مناوبة"},{"en":"Only after touching ready-to-eat food","es":"Solo después de tocar alimentos listos para comer","ru":"Только после касания готовых к употреблению продуктов","tr":"Yalnızca yemeye hazır gıdaya dokunduktan sonra","hi":"केवल खाने के लिए तैयार भोजन को छूने के बाद","ar":"فقط بعد ملامسة الطعام الجاهز للأكل"},{"en":"Only when hands look visibly dirty","es":"Solo cuando las manos se ven visiblemente sucias","ru":"Только когда руки выглядят явно грязными","tr":"Yalnızca eller gözle görülür şekilde kirli göründüğünde","hi":"केवल जब हाथ दिखाई देने वाले गंदे हों","ar":"فقط عندما تبدو اليدان متسختين بوضوح"}],"e":{"en":"Hands must be washed after using the restroom, and also after handling raw food, touching the face or body, taking out trash, and other contaminating activities.","es":"Las manos deben lavarse después de usar el baño, y también después de manipular alimentos crudos, tocarse la cara o el cuerpo, sacar la basura y otras actividades contaminantes.","ru":"Руки нужно мыть после посещения туалета, а также после работы с сырыми продуктами, касания лица или тела, выноса мусора и других загрязняющих действий.","tr":"Eller tuvaleti kullandıktan sonra; ayrıca çiğ gıda işledikten, yüze veya vücuda dokunduktan, çöp attıktan ve diğer kirletici faaliyetlerden sonra yıkanmalıdır.","hi":"शौचालय का उपयोग करने के बाद हाथ धोने चाहिए, और कच्चे भोजन को संभालने, चेहरे या शरीर को छूने, कचरा बाहर निकालने, और अन्य संदूषण करने वाली गतिविधियों के बाद भी।","ar":"يجب غسل اليدين بعد استخدام دورة المياه، وكذلك بعد التعامل مع الطعام النيء، وملامسة الوجه أو الجسم، وإخراج القمامة، وغير ذلك من الأنشطة الملوِّثة."}},{"cat":"hygiene","a":2,"q":{"en":"A food handler's doctor diagnoses them with hepatitis A. What must the establishment do?","es":"El médico de un manipulador de alimentos le diagnostica hepatitis A. ¿Qué debe hacer el establecimiento?","ru":"Врач работника пищевого производства диагностирует у него гепатит А. Что должно сделать заведение?","tr":"Bir gıda çalışanının doktoru, ona hepatit A teşhisi koyar. İşletme ne yapmalıdır?","hi":"एक फूड हैंडलर के डॉक्टर ने उन्हें हेपेटाइटिस A का निदान किया। प्रतिष्ठान को क्या करना चाहिए?","ar":"يُشخِّص طبيبٌ متداولَ طعام بالإصابة بالتهاب الكبد الوبائي A. ماذا يجب على المنشأة أن تفعل؟"},"o":[{"en":"Restrict them to washing dishes only","es":"Restringirlo a lavar platos únicamente","ru":"Ограничить его обязанности только мытьём посуды","tr":"Onu yalnızca bulaşık yıkamayla sınırlandırmalı","hi":"उन्हें केवल बर्तन धोने तक सीमित करें","ar":"قصر عمله على غسل الأطباق فقط"},{"en":"Allow them to work if they wear gloves","es":"Permitirle trabajar si usa guantes","ru":"Разрешить ему работать, если он носит перчатки","tr":"Eldiven giyerse çalışmasına izin vermeli","hi":"अगर वे दस्ताने पहनें तो उन्हें काम करने दें","ar":"السماح له بالعمل إذا ارتدى قفازات"},{"en":"Exclude the employee and notify the regulatory authority","es":"Excluir al empleado y notificar a la autoridad reguladora","ru":"Отстранить работника и уведомить регулирующий орган","tr":"Çalışanı işletmeden hariç tutmalı (uzaklaştırmalı) ve düzenleyici otoriteyi bilgilendirmeli","hi":"कर्मचारी को बाहर रखें और नियामक प्राधिकरण को सूचित करें","ar":"استبعاد الموظف وإخطار الجهة التنظيمية"},{"en":"Let them keep working until symptoms appear","es":"Dejarlo seguir trabajando hasta que aparezcan los síntomas","ru":"Позволить ему продолжать работать до появления симптомов","tr":"Belirtiler ortaya çıkana kadar çalışmaya devam etmesine izin vermeli","hi":"लक्षण प्रकट होने तक उन्हें काम करते रहने दें","ar":"تركه يواصل العمل إلى أن تظهر الأعراض"}],"e":{"en":"Hepatitis A is one of the Big 6; a diagnosed employee must be excluded from the establishment and the regulatory authority must be notified.","es":"La hepatitis A es una de los 6 grandes (Big 6); un empleado diagnosticado debe ser excluido del establecimiento y se debe notificar a la autoridad reguladora.","ru":"Гепатит А — один из «Большой шестёрки» (Big 6); работник с подтверждённым диагнозом должен быть отстранён от заведения, а регулирующий орган должен быть уведомлён.","tr":"Hepatit A, Büyük 6'dan (Big 6) biridir; teşhis konulan bir çalışan işletmeden hariç tutulmalı ve düzenleyici otorite bilgilendirilmelidir.","hi":"हेपेटाइटिस A Big 6 में से एक है; निदान किए गए कर्मचारी को प्रतिष्ठान से बाहर रखा जाना चाहिए और नियामक प्राधिकरण को सूचित किया जाना चाहिए।","ar":"التهاب الكبد الوبائي A هو أحد الستة الكبار (Big 6)؛ ويجب استبعاد الموظف المُشخَّص من المنشأة وإخطار الجهة التنظيمية."}},{"cat":"hygiene","a":0,"q":{"en":"Which set lists pathogens from the \"Big 6\" that food handlers must report to their manager?","es":"¿Qué conjunto enumera patógenos de los \"6 grandes\" (Big 6) que los manipuladores de alimentos deben reportar a su gerente?","ru":"В каком наборе перечислены патогены из «Большой шестёрки» (Big 6), о которых работники пищевого производства должны сообщать своему руководителю?","tr":"Hangi grup, gıda çalışanlarının yöneticilerine bildirmesi gereken \"Büyük 6\" (Big 6) patojenlerini listeler?","hi":"कौन सा समूह \"Big 6\" के उन रोगजनकों को सूचीबद्ध करता है जिन्हें फूड हैंडलर को अपने प्रबंधक को रिपोर्ट करना चाहिए?","ar":"أيُّ مجموعة تُدرِج مسببات أمراض من \"الستة الكبار\" (Big 6) التي يجب على متداولي الطعام الإبلاغ عنها لمديرهم؟"},"o":[{"en":"Norovirus, Hepatitis A, and Shigella","es":"Norovirus, Hepatitis A y Shigella","ru":"Норовирус, гепатит А и шигелла (Shigella)","tr":"Norovirüs, Hepatit A ve Shigella","hi":"नोरोवायरस, हेपेटाइटिस A, और शिगेला","ar":"نوروفيروس، والتهاب الكبد الوبائي A، والشيغيلا"},{"en":"Norovirus, Listeria, and botulism","es":"Norovirus, Listeria y botulismo","ru":"Норовирус, листерия (Listeria) и ботулизм","tr":"Norovirüs, Listeria ve botulizm","hi":"नोरोवायरस, लिस्टेरिया, और बोटुलिज़्म","ar":"نوروفيروس، والليستيريا، والتسمم الوشيقي (botulism)"},{"en":"Hepatitis A, Staphylococcus, and Listeria","es":"Hepatitis A, Staphylococcus y Listeria","ru":"Гепатит А, стафилококк (Staphylococcus) и листерия (Listeria)","tr":"Hepatit A, Stafilokok ve Listeria","hi":"हेपेटाइटिस A, स्टैफिलोकोकस, और लिस्टेरिया","ar":"التهاب الكبد الوبائي A، والمكورات العنقودية، والليستيريا"},{"en":"Salmonella, Listeria, and Clostridium perfringens","es":"Salmonella, Listeria y Clostridium perfringens","ru":"Сальмонелла (Salmonella), листерия (Listeria) и клостридия (Clostridium perfringens)","tr":"Salmonella, Listeria ve Clostridium perfringens","hi":"साल्मोनेला, लिस्टेरिया, और क्लोस्ट्रिडियम परफ्रिंजेंस","ar":"السالمونيلا، والليستيريا، والمطثية الحاطمة (Clostridium perfringens)"}],"e":{"en":"The Big 6 are Norovirus, Hepatitis A, Shigella spp., Shiga toxin-producing E. coli, nontyphoidal Salmonella, and Salmonella Typhi; Listeria and Staphylococcus are not on that reportable list.","es":"Los 6 grandes (Big 6) son Norovirus, Hepatitis A, Shigella spp., E. coli productora de toxina Shiga, Salmonella no tifoidea y Salmonella Typhi; Listeria y Staphylococcus no están en esa lista de reporte.","ru":"«Большая шестёрка» (Big 6) — это норовирус, гепатит А, Shigella spp., шига-токсин-продуцирующая E. coli, нетифоидная Salmonella и Salmonella Typhi; листерия и стафилококк не входят в этот список, подлежащий уведомлению.","tr":"Büyük 6; Norovirüs, Hepatit A, Shigella spp., Shiga toksini üreten E. coli, tifo dışı (nontyphoidal) Salmonella ve Salmonella Typhi'dir; Listeria ve Stafilokok bu bildirim listesinde yer almaz.","hi":"Big 6 हैं नोरोवायरस, हेपेटाइटिस A, शिगेला spp., शिगा टॉक्सिन उत्पन्न करने वाला E. coli, नॉनटाइफॉइडल साल्मोनेला, और साल्मोनेला टाइफी; लिस्टेरिया और स्टैफिलोकोकस उस रिपोर्ट करने योग्य सूची में नहीं हैं।","ar":"الستة الكبار هم: نوروفيروس، والتهاب الكبد الوبائي A، وأنواع الشيغيلا (Shigella spp.)، والإشريكية القولونية المنتجة لذيفان شيغا (Shiga toxin-producing E. coli)، والسالمونيلا غير التيفية (nontyphoidal Salmonella)، وسالمونيلا التيفية (Salmonella Typhi)؛ والليستيريا والمكورات العنقودية ليستا على تلك القائمة الواجب الإبلاغ عنها."}},{"cat":"hygiene","a":3,"q":{"en":"An employee reports a sore throat with a fever. If the operation serves a population that is NOT highly susceptible, what is the appropriate action?","es":"Un empleado reporta dolor de garganta con fiebre. Si la operación atiende a una población que NO es altamente susceptible, ¿cuál es la acción apropiada?","ru":"Работник сообщает о боли в горле с повышенной температурой. Если заведение обслуживает население, которое НЕ является высоковосприимчивым, каково правильное действие?","tr":"Bir çalışan ateşle birlikte boğaz ağrısı bildirir. İşletme, hassasiyeti yüksek OLMAYAN bir nüfusa hizmet veriyorsa, uygun eylem nedir?","hi":"एक कर्मचारी बुखार के साथ गले में खराश की रिपोर्ट करता है। यदि ऑपरेशन ऐसी आबादी को सेवा देता है जो अत्यधिक संवेदनशील नहीं है, तो उचित कार्रवाई क्या है?","ar":"يُبلِغ موظف عن التهاب في الحلق مصحوب بالحُمّى. إذا كانت المنشأة تخدم فئة من السكان غير شديدة التأثر، فما الإجراء المناسب؟"},"o":[{"en":"Exclude them from the establishment entirely","es":"Excluirlo del establecimiento por completo","ru":"Полностью отстранить его от заведения","tr":"Onu tamamen işletmeden hariç tutmak (uzaklaştırmak)","hi":"उन्हें पूरी तरह से प्रतिष्ठान से बाहर रखें","ar":"استبعاده من المنشأة تماماً"},{"en":"Take no action since a sore throat is minor","es":"No tomar ninguna acción porque un dolor de garganta es menor","ru":"Не предпринимать действий, поскольку боль в горле — это пустяк","tr":"Boğaz ağrısı önemsiz olduğundan hiçbir işlem yapmamak","hi":"कोई कार्रवाई न करें क्योंकि गले में खराश मामूली है","ar":"عدم اتخاذ أي إجراء لأن التهاب الحلق أمر بسيط"},{"en":"Send them to handle ready-to-eat food only","es":"Enviarlo a manipular únicamente alimentos listos para comer","ru":"Направить его работать только с готовыми к употреблению продуктами","tr":"Onu yalnızca yemeye hazır gıdayla ilgilenmesi için göndermek","hi":"उन्हें केवल खाने के लिए तैयार भोजन संभालने के लिए भेजें","ar":"إرساله للتعامل مع الطعام الجاهز للأكل فقط"},{"en":"Restrict them from working with exposed food and clean equipment","es":"Restringirlo de trabajar con alimentos expuestos y equipo limpio","ru":"Ограничить его от работы с открытыми продуктами и чистым оборудованием","tr":"Açık gıda ve temiz ekipmanla çalışmasını kısıtlamak","hi":"उन्हें उजागर भोजन और साफ उपकरणों के साथ काम करने से प्रतिबंधित करें","ar":"تقييد عمله بحيث لا يتعامل مع الطعام المكشوف والمعدات النظيفة"}],"e":{"en":"Sore throat with fever is a reportable symptom; in a non high-risk operation the employee is restricted from food and food-contact surfaces, while exclusion applies if serving a highly susceptible population.","es":"El dolor de garganta con fiebre es un síntoma que debe reportarse; en una operación de bajo riesgo el empleado queda restringido de los alimentos y las superficies de contacto con alimentos, mientras que la exclusión aplica si se atiende a una población altamente susceptible.","ru":"Боль в горле с температурой — это симптом, подлежащий уведомлению; в заведении с невысоким риском работника ограничивают от продуктов и поверхностей, контактирующих с пищей, тогда как отстранение применяется при обслуживании высоковосприимчивого населения.","tr":"Ateşle birlikte boğaz ağrısı bildirimi zorunlu bir belirtidir; yüksek riskli olmayan bir işletmede çalışan gıdadan ve gıdayla temas eden yüzeylerden kısıtlanır, hassasiyeti yüksek bir nüfusa hizmet veriliyorsa hariç tutma (uzaklaştırma) uygulanır.","hi":"बुखार के साथ गले में खराश एक रिपोर्ट करने योग्य लक्षण है; एक गैर-उच्च-जोखिम वाले ऑपरेशन में कर्मचारी को भोजन और भोजन-संपर्क सतहों से प्रतिबंधित किया जाता है, जबकि अत्यधिक संवेदनशील आबादी की सेवा करने पर बहिष्कार लागू होता है।","ar":"التهاب الحلق المصحوب بالحُمّى عَرَض واجب الإبلاغ عنه؛ ففي المنشأة غير عالية الخطورة يُقيَّد الموظف عن الطعام وأسطح ملامسة الطعام، بينما يُطبَّق الاستبعاد إذا كانت تخدم فئة شديدة التأثر."}},{"cat":"hygiene","a":1,"q":{"en":"Which condition requires EXCLUDING a food employee from the establishment rather than only restricting them?","es":"¿Qué condición exige EXCLUIR a un empleado de alimentos del establecimiento en lugar de solo restringirlo?","ru":"Какое состояние требует ОТСТРАНЕНИЯ работника пищевого производства от заведения, а не только его ограничения?","tr":"Hangi durum, bir gıda çalışanının yalnızca kısıtlanması yerine işletmeden HARİÇ TUTULMASINI (uzaklaştırılmasını) gerektirir?","hi":"किस स्थिति में एक फूड कर्मचारी को केवल प्रतिबंधित करने के बजाय प्रतिष्ठान से बाहर रखना (EXCLUDE) आवश्यक है?","ar":"أيُّ حالة تستوجب استبعاد موظف الطعام من المنشأة بدلاً من مجرد تقييده؟"},"o":[{"en":"A small covered cut on the arm","es":"Un pequeño corte cubierto en el brazo","ru":"Небольшой закрытый порез на руке","tr":"Kolda kapatılmış küçük bir kesik","hi":"बांह पर एक छोटा ढका हुआ कट","ar":"جرح صغير مغطى على الذراع"},{"en":"Jaundice with a recent onset","es":"Ictericia de aparición reciente","ru":"Желтуха недавнего возникновения","tr":"Yeni başlamış sarılık (jaundice)","hi":"हाल ही में शुरू हुआ पीलिया","ar":"اليرقان (الصُّفار) حديث الظهور"},{"en":"A clean bandage on a finger under a glove","es":"Una venda limpia en un dedo bajo un guante","ru":"Чистый пластырь на пальце под перчаткой","tr":"Eldiven altında bir parmaktaki temiz yara bandı","hi":"दस्ताने के नीचे उंगली पर एक साफ पट्टी","ar":"لاصق طبي نظيف على إصبع تحت قفاز"},{"en":"Wearing nail polish under intact gloves","es":"Usar esmalte de uñas bajo guantes intactos","ru":"Ношение лака для ногтей под целыми перчатками","tr":"Sağlam eldiven altında oje takmak","hi":"सही-सलामत दस्ताने के नीचे नेल पॉलिश पहनना","ar":"ارتداء طلاء أظافر تحت قفازات سليمة"}],"e":{"en":"Jaundice (yellowing of skin or eyes) of recent onset requires exclusion and reporting to the regulatory authority, as it may signal hepatitis A.","es":"La ictericia (coloración amarilla de la piel o los ojos) de aparición reciente exige la exclusión y el reporte a la autoridad reguladora, ya que puede indicar hepatitis A.","ru":"Желтуха (пожелтение кожи или глаз) недавнего возникновения требует отстранения и уведомления регулирующего органа, поскольку она может указывать на гепатит А.","tr":"Yeni başlayan sarılık (cilt veya gözlerin sararması), hepatit A'nın işareti olabileceğinden hariç tutma (uzaklaştırma) ve düzenleyici otoriteye bildirim gerektirir.","hi":"हाल ही में शुरू हुए पीलिया (त्वचा या आंखों का पीला पड़ना) के लिए बहिष्कार और नियामक प्राधिकरण को रिपोर्ट करना आवश्यक है, क्योंकि यह हेपेटाइटिस A का संकेत हो सकता है।","ar":"يستوجب اليرقان (اصفرار الجلد أو العينين) حديث الظهور الاستبعادَ والإبلاغ للجهة التنظيمية، إذ قد يشير إلى التهاب الكبد الوبائي A."}},{"cat":"hygiene","a":0,"q":{"en":"A food handler with an infected, pus-filled wound on the hand that cannot be properly covered should be:","es":"Un manipulador de alimentos con una herida infectada y llena de pus en la mano que no puede cubrirse adecuadamente debe ser:","ru":"Работник пищевого производства с инфицированной, наполненной гноем раной на руке, которую нельзя должным образом закрыть, должен быть:","tr":"Elinde, düzgünce kapatılamayan iltihaplı, irin dolu bir yarası olan bir gıda çalışanı:","hi":"हाथ पर एक संक्रमित, मवाद से भरे घाव वाले फूड हैंडलर को जिसे ठीक से ढका नहीं जा सकता, उसके साथ क्या किया जाना चाहिए:","ar":"متداول الطعام المصاب بجرح ملتهب مملوء بالقيح في اليد لا يمكن تغطيته بشكل سليم ينبغي أن:"},"o":[{"en":"Restricted or excluded from handling food until it is resolved or properly covered","es":"Restringido o excluido de manipular alimentos hasta que se resuelva o se cubra adecuadamente","ru":"Ограничен или отстранён от работы с продуктами до её заживления или надлежащего закрытия","tr":"Yara iyileşene veya düzgünce kapatılana kadar gıdayla ilgilenmesi kısıtlanmalı veya hariç tutulmalı (uzaklaştırılmalı)","hi":"इसके ठीक होने या ठीक से ढके जाने तक भोजन संभालने से प्रतिबंधित या बाहर रखा जाए","ar":"يُقيَّد أو يُستبعَد عن التعامل مع الطعام حتى يُشفى أو يُغطّى بشكل سليم"},{"en":"Allowed to continue if they wash hands more often","es":"Permitido continuar si se lava las manos con más frecuencia","ru":"Допущен к продолжению работы, если он чаще моет руки","tr":"Ellerini daha sık yıkarsa devam etmesine izin verilmeli","hi":"अगर वे अधिक बार हाथ धोएं तो जारी रखने की अनुमति दी जाए","ar":"يُسمح له بالاستمرار إذا غسل يديه أكثر تكراراً"},{"en":"Permitted to work as long as they wear two gloves","es":"Permitido trabajar siempre que use dos guantes","ru":"Допущен к работе при условии ношения двух перчаток","tr":"İki eldiven giydiği sürece çalışmasına izin verilmeli","hi":"जब तक वे दो दस्ताने पहनें तब तक काम करने की अनुमति दी जाए","ar":"يُسمح له بالعمل ما دام يرتدي قفازين"},{"en":"Moved to plating ready-to-eat desserts","es":"Trasladado a emplatar postres listos para comer","ru":"Переведён на сервировку готовых к употреблению десертов","tr":"Yemeye hazır tatlıları tabaklamaya kaydırılmalı","hi":"खाने के लिए तैयार मिठाइयां प्लेटिंग करने के लिए स्थानांतरित किया जाए","ar":"يُنقَل إلى تنسيق الحلويات الجاهزة للأكل"}],"e":{"en":"An infected wound on the hand or wrist that cannot be effectively covered is a reportable condition that requires restricting or excluding the employee from food handling.","es":"Una herida infectada en la mano o la muñeca que no puede cubrirse eficazmente es una condición que debe reportarse y que exige restringir o excluir al empleado de la manipulación de alimentos.","ru":"Инфицированная рана на руке или запястье, которую нельзя эффективно закрыть, — это состояние, подлежащее уведомлению, которое требует ограничения или отстранения работника от работы с продуктами.","tr":"El veya bilekte etkili bir şekilde kapatılamayan iltihaplı bir yara, çalışanın gıda işlemekten kısıtlanmasını veya hariç tutulmasını gerektiren, bildirimi zorunlu bir durumdur.","hi":"हाथ या कलाई पर एक संक्रमित घाव जिसे प्रभावी ढंग से ढका नहीं जा सकता, एक रिपोर्ट करने योग्य स्थिति है जिसके लिए कर्मचारी को भोजन संभालने से प्रतिबंधित या बाहर रखना आवश्यक है।","ar":"الجرح الملتهب في اليد أو المعصم الذي لا يمكن تغطيته بفعالية هو حالة واجبة الإبلاغ عنها تستوجب تقييد الموظف أو استبعاده عن تداول الطعام."}},{"cat":"hygiene","a":3,"q":{"en":"An employee is medically cleared to return after a Salmonella Typhi (typhoid fever) diagnosis. Why is this pathogen treated so strictly?","es":"Un empleado recibe el alta médica para regresar después de un diagnóstico de Salmonella Typhi (fiebre tifoidea). ¿Por qué se trata este patógeno con tanta rigurosidad?","ru":"Работник получил медицинское разрешение вернуться после диагноза Salmonella Typhi (брюшной тиф). Почему этот патоген рассматривается так строго?","tr":"Bir çalışan, Salmonella Typhi (tifo) teşhisinden sonra işe dönmek için tıbbi olarak onaylanır. Bu patojen neden bu kadar katı şekilde ele alınır?","hi":"एक कर्मचारी को साल्मोनेला टाइफी (टाइफॉइड बुखार) निदान के बाद वापस लौटने के लिए चिकित्सकीय रूप से मंजूरी दी जाती है। इस रोगजनक के साथ इतनी सख्ती से व्यवहार क्यों किया जाता है?","ar":"تتم الموافقة الطبية على عودة موظف بعد تشخيصه بسالمونيلا التيفية (Salmonella Typhi) (حمى التيفوئيد). لماذا يُعامَل هذا الممرض بهذه الصرامة؟"},"o":[{"en":"It is harmless once symptoms stop the same day","es":"Es inofensivo una vez que los síntomas cesan el mismo día","ru":"Он безвреден, как только симптомы прекращаются в тот же день","tr":"Belirtiler aynı gün durduğunda zararsızdır","hi":"लक्षण उसी दिन रुकने के बाद यह हानिरहित है","ar":"إنه غير ضار بمجرد توقف الأعراض في اليوم نفسه"},{"en":"It only affects raw meat, not the food handler","es":"Solo afecta la carne cruda, no al manipulador de alimentos","ru":"Он поражает только сырое мясо, а не работника","tr":"Yalnızca çiğ eti etkiler, gıda çalışanını değil","hi":"यह केवल कच्चे मांस को प्रभावित करता है, फूड हैंडलर को नहीं","ar":"إنه يؤثر فقط على اللحم النيء، لا على متداول الطعام"},{"en":"It cannot be transmitted by food handlers at all","es":"No puede ser transmitido por los manipuladores de alimentos en absoluto","ru":"Он вообще не может передаваться работниками пищевого производства","tr":"Gıda çalışanları tarafından kesinlikle bulaştırılamaz","hi":"इसे फूड हैंडलर द्वारा बिल्कुल भी प्रसारित नहीं किया जा सकता","ar":"لا يمكن أن ينتقل عن طريق متداولي الطعام على الإطلاق"},{"en":"It can be shed and spread to food for an extended period, so reinstatement needs medical documentation","es":"Puede excretarse y propagarse a los alimentos durante un período prolongado, por lo que la reincorporación requiere documentación médica","ru":"Он может выделяться и распространяться на продукты в течение длительного периода, поэтому для восстановления требуется медицинская документация","tr":"Uzun bir süre boyunca saçılıp gıdaya yayılabilir, bu yüzden işe iade tıbbi belgelendirme gerektirir","hi":"इसे एक लंबी अवधि तक बहाया और भोजन में फैलाया जा सकता है, इसलिए पुनर्बहाली के लिए चिकित्सा दस्तावेज़ की आवश्यकता होती है","ar":"يمكن أن يُطرَح وينتقل إلى الطعام لفترة ممتدة، لذا تتطلب إعادته توثيقاً طبياً"}],"e":{"en":"Salmonella Typhi is a Big 6 pathogen that can be shed for a long time; an excluded employee may only be reinstated with regulatory approval and medical documentation.","es":"Salmonella Typhi es un patógeno de los 6 grandes (Big 6) que puede excretarse durante mucho tiempo; un empleado excluido solo puede reincorporarse con la aprobación de la autoridad reguladora y documentación médica.","ru":"Salmonella Typhi — патоген из «Большой шестёрки» (Big 6), который может выделяться в течение длительного времени; отстранённый работник может быть восстановлен только с одобрения регулирующего органа и при наличии медицинской документации.","tr":"Salmonella Typhi, uzun süre saçılabilen bir Büyük 6 (Big 6) patojenidir; hariç tutulan bir çalışan yalnızca düzenleyici onay ve tıbbi belgelendirmeyle işe iade edilebilir.","hi":"साल्मोनेला टाइफी एक Big 6 रोगजनक है जिसे लंबे समय तक बहाया जा सकता है; एक बाहर रखे गए कर्मचारी को केवल नियामक अनुमोदन और चिकित्सा दस्तावेज़ के साथ पुनर्बहाल किया जा सकता है।","ar":"سالمونيلا التيفية (Salmonella Typhi) هي أحد مسببات الستة الكبار (Big 6) التي يمكن أن تُطرَح لفترة طويلة؛ ولا يجوز إعادة الموظف المُستبعَد إلا بموافقة الجهة التنظيمية وتوثيق طبي."}},{"cat":"temp","a":1,"q":{"en":"What is the temperature range commonly called the \"danger zone,\" where bacteria in food grow most rapidly?","es":"¿Cuál es el rango de temperatura comúnmente llamado \"zona de peligro\", donde las bacterias en los alimentos crecen más rápidamente?","ru":"Каков температурный диапазон, обычно называемый «опасной температурной зоной», в котором бактерии в продуктах размножаются наиболее быстро?","tr":"Gıdadaki bakterilerin en hızlı çoğaldığı, yaygın olarak \"tehlikeli sıcaklık bölgesi\" (danger zone) olarak adlandırılan sıcaklık aralığı nedir?","hi":"वह तापमान सीमा क्या है जिसे आमतौर पर \"खतरनाक तापमान क्षेत्र\" कहा जाता है, जहां भोजन में बैक्टीरिया सबसे तेज़ी से बढ़ते हैं?","ar":"ما نطاق درجات الحرارة الذي يُسمى عادةً \"منطقة الخطر الحرارية\"، حيث تنمو البكتيريا في الطعام بأسرع وتيرة؟"},"o":[{"en":"32°F to 100°F","es":"32°F a 100°F","ru":"32°F to 100°F","tr":"32°F ile 100°F arası","hi":"32°F से 100°F","ar":"32°F to 100°F"},{"en":"41°F to 135°F","es":"41°F a 135°F","ru":"41°F to 135°F","tr":"41°F ile 135°F arası","hi":"41°F से 135°F","ar":"41°F to 135°F"},{"en":"45°F to 140°F","es":"45°F a 140°F","ru":"45°F to 140°F","tr":"45°F ile 140°F arası","hi":"45°F से 140°F","ar":"45°F to 140°F"},{"en":"50°F to 120°F","es":"50°F a 120°F","ru":"50°F to 120°F","tr":"50°F ile 120°F arası","hi":"50°F से 120°F","ar":"50°F to 120°F"}],"e":{"en":"The FDA Food Code defines the temperature danger zone as 41°F to 135°F (5°C to 57°C), the range in which TCS foods support the fastest bacterial growth.","es":"El Código de Alimentos de la FDA define la zona de temperatura de peligro como 41°F a 135°F (5°C a 57°C), el rango en el que los alimentos TCS favorecen el crecimiento bacteriano más rápido.","ru":"FDA Food Code (Пищевой кодекс) определяет опасную температурную зону как диапазон от 41°F до 135°F (5°C–57°C) — диапазон, в котором TCS-продукты поддерживают самый быстрый рост бактерий.","tr":"FDA Gıda Kanunu (Food Code), tehlikeli sıcaklık bölgesini 41°F ile 135°F (5°C ile 57°C) olarak tanımlar; bu aralık, TCS gıdalarının en hızlı bakteriyel üremeyi desteklediği aralıktır.","hi":"FDA फूड कोड खतरनाक तापमान क्षेत्र को 41°F से 135°F (5°C से 57°C) के रूप में परिभाषित करता है, वह सीमा जिसमें TCS भोजन सबसे तेज़ बैक्टीरिया वृद्धि का समर्थन करते हैं।","ar":"يُعرّف قانون الغذاء الصادر عن FDA منطقة الخطر الحرارية بأنها 41°F to 135°F (5°C to 57°C)، وهي النطاق الذي تدعم فيه الأطعمة TCS أسرع نمو بكتيري."}},{"cat":"temp","a":1,"q":{"en":"Why do food handlers keep TCS foods out of the danger zone?","es":"¿Por qué los manipuladores de alimentos mantienen los alimentos TCS fuera de la zona de peligro?","ru":"Почему работники пищевого производства держат TCS-продукты вне опасной температурной зоны?","tr":"Gıda çalışanları neden TCS gıdaları tehlikeli sıcaklık bölgesinden uzak tutar?","hi":"फूड हैंडलर TCS भोजन को खतरनाक तापमान क्षेत्र से बाहर क्यों रखते हैं?","ar":"لماذا يُبقي متداولو الطعام أطعمة TCS خارج منطقة الخطر الحرارية؟"},"o":[{"en":"Cold temperatures destroy all bacteria instantly","es":"Las temperaturas frías destruyen todas las bacterias al instante","ru":"Холодные температуры мгновенно уничтожают все бактерии","tr":"Soğuk sıcaklıklar tüm bakterileri anında yok eder","hi":"ठंडा तापमान सभी बैक्टीरिया को तुरंत नष्ट कर देता है","ar":"تقضي درجات الحرارة المنخفضة على كل البكتيريا فوراً"},{"en":"Bacteria multiply fastest within that temperature range","es":"Las bacterias se multiplican más rápido dentro de ese rango de temperatura","ru":"Бактерии размножаются быстрее всего в этом температурном диапазоне","tr":"Bakteriler bu sıcaklık aralığında en hızlı çoğalır","hi":"उस तापमान सीमा के भीतर बैक्टीरिया सबसे तेज़ी से बढ़ते हैं","ar":"تتكاثر البكتيريا بأسرع وتيرة ضمن ذلك النطاق الحراري"},{"en":"Food loses flavor between 41°F and 135°F","es":"El alimento pierde sabor entre 41°F y 135°F","ru":"Продукты теряют вкус при температуре от 41°F до 135°F","tr":"Gıda, 41°F ile 135°F arasında lezzetini kaybeder","hi":"41°F और 135°F के बीच भोजन का स्वाद खो जाता है","ar":"يفقد الطعام نكهته بين 41°F و135°F"},{"en":"It is the range where freezing damages food cells","es":"Es el rango en el que la congelación daña las células del alimento","ru":"Это диапазон, в котором замораживание повреждает клетки продуктов","tr":"Donmanın gıda hücrelerine zarar verdiği aralıktır","hi":"यह वह सीमा है जहां जमने से भोजन कोशिकाएं क्षतिग्रस्त होती हैं","ar":"إنه النطاق الذي يُتلف فيه التجميد خلايا الطعام"}],"e":{"en":"Bacteria grow fastest between 41°F and 135°F, so limiting time in this range slows growth to safe levels rather than killing the bacteria outright.","es":"Las bacterias crecen más rápido entre 41°F y 135°F, por lo que limitar el tiempo en este rango ralentiza el crecimiento a niveles seguros en lugar de eliminar las bacterias por completo.","ru":"Бактерии растут быстрее всего при температуре от 41°F до 135°F, поэтому ограничение времени пребывания в этом диапазоне замедляет рост до безопасного уровня, а не убивает бактерии напрямую.","tr":"Bakteriler 41°F ile 135°F arasında en hızlı ürer, bu yüzden bu aralıkta geçirilen süreyi sınırlamak, bakterileri tamamen öldürmek yerine üremeyi güvenli seviyelere yavaşlatır.","hi":"बैक्टीरिया 41°F और 135°F के बीच सबसे तेज़ी से बढ़ते हैं, इसलिए इस सीमा में समय सीमित करने से बैक्टीरिया को सीधे मारने के बजाय वृद्धि को सुरक्षित स्तर तक धीमा कर दिया जाता है।","ar":"تنمو البكتيريا بأسرع وتيرة بين 41°F و135°F، لذا فإن الحد من الوقت في هذا النطاق يبطئ النمو إلى مستويات آمنة بدلاً من قتل البكتيريا تماماً."}},{"cat":"temp","a":2,"q":{"en":"What is the minimum internal cooking temperature for poultry, such as chicken or turkey?","es":"¿Cuál es la temperatura interna mínima de cocción para las aves, como el pollo o el pavo?","ru":"Какова минимальная внутренняя температура приготовления для птицы, такой как курица или индейка?","tr":"Tavuk veya hindi gibi kümes hayvanları için minimum iç pişirme sıcaklığı nedir?","hi":"पोल्ट्री, जैसे चिकन या टर्की, के लिए न्यूनतम आंतरिक खाना पकाने का तापमान क्या है?","ar":"ما الحد الأدنى لدرجة حرارة الطهي الداخلية للدواجن، مثل الدجاج أو الديك الرومي؟"},"o":[{"en":"155°F","es":"155°F","ru":"155°F","tr":"155°F","hi":"155°F","ar":"155°F"},{"en":"160°F","es":"160°F","ru":"160°F","tr":"160°F","hi":"160°F","ar":"160°F"},{"en":"165°F","es":"165°F","ru":"165°F","tr":"165°F","hi":"165°F","ar":"165°F"},{"en":"170°F","es":"170°F","ru":"170°F","tr":"170°F","hi":"170°F","ar":"170°F"}],"e":{"en":"Poultry must reach a minimum internal temperature of 165°F for less than 1 second under the FDA Food Code.","es":"Las aves deben alcanzar una temperatura interna mínima de 165°F durante menos de 1 segundo según el Código de Alimentos de la FDA.","ru":"Птица должна достичь минимальной внутренней температуры 165°F в течение менее 1 секунды согласно FDA Food Code (Пищевому кодексу).","tr":"FDA Gıda Kanunu (Food Code) uyarınca kümes hayvanları, 1 saniyeden kısa süreyle minimum 165°F iç sıcaklığa ulaşmalıdır.","hi":"FDA फूड कोड के तहत पोल्ट्री को 1 सेकंड से कम के लिए न्यूनतम आंतरिक तापमान 165°F तक पहुंचना चाहिए।","ar":"يجب أن تصل الدواجن إلى حد أدنى من درجة الحرارة الداخلية قدره 165°F لأقل من ثانية واحدة بموجب قانون الغذاء الصادر عن FDA."}},{"cat":"temp","a":3,"q":{"en":"Stuffed pasta, stuffed poultry, and other stuffed foods must be cooked to a minimum internal temperature of:","es":"La pasta rellena, las aves rellenas y otros alimentos rellenos deben cocinarse a una temperatura interna mínima de:","ru":"Фаршированная паста, фаршированная птица и другие фаршированные блюда должны быть приготовлены до минимальной внутренней температуры:","tr":"İçi doldurulmuş makarna, içi doldurulmuş kümes hayvanları ve diğer içi doldurulmuş gıdalar, minimum hangi iç sıcaklığa kadar pişirilmelidir?","hi":"भरवां पास्ता, भरवां पोल्ट्री, और अन्य भरवां भोजन को न्यूनतम आंतरिक तापमान तक पकाया जाना चाहिए:","ar":"يجب طهي المعكرونة المحشوة والدواجن المحشوة وغيرها من الأطعمة المحشوة إلى حد أدنى من درجة الحرارة الداخلية قدره:"},"o":[{"en":"145°F","es":"145°F","ru":"145°F","tr":"145°F","hi":"145°F","ar":"145°F"},{"en":"155°F","es":"155°F","ru":"155°F","tr":"155°F","hi":"155°F","ar":"155°F"},{"en":"160°F","es":"160°F","ru":"160°F","tr":"160°F","hi":"160°F","ar":"160°F"},{"en":"165°F","es":"165°F","ru":"165°F","tr":"165°F","hi":"165°F","ar":"165°F"}],"e":{"en":"Stuffed foods and stuffing containing TCS ingredients must reach 165°F for less than 1 second because the stuffing can shield bacteria from heat.","es":"Los alimentos rellenos y el relleno que contiene ingredientes TCS deben alcanzar 165°F durante menos de 1 segundo porque el relleno puede proteger a las bacterias del calor.","ru":"Фаршированные блюда и начинка, содержащая TCS-ингредиенты, должны достичь 165°F в течение менее 1 секунды, поскольку начинка может защищать бактерии от тепла.","tr":"İç dolgu, bakterileri ısıdan koruyabileceğinden, TCS içerikli içi doldurulmuş gıdalar ve dolgular 1 saniyeden kısa süreyle 165°F'ye ulaşmalıdır.","hi":"भरवां भोजन और TCS सामग्री वाली भराई को 1 सेकंड से कम के लिए 165°F तक पहुंचना चाहिए क्योंकि भराई बैक्टीरिया को गर्मी से बचा सकती है।","ar":"يجب أن تصل الأطعمة المحشوة والحشوات التي تحتوي على مكونات TCS إلى 165°F لأقل من ثانية واحدة لأن الحشوة قد تحمي البكتيريا من الحرارة."}},{"cat":"temp","a":2,"q":{"en":"What is the minimum internal cooking temperature for ground beef, such as hamburger patties?","es":"¿Cuál es la temperatura interna mínima de cocción para la carne molida de res, como las hamburguesas?","ru":"Какова минимальная внутренняя температура приготовления для говяжьего фарша, например для котлет для гамбургеров?","tr":"Hamburger köftesi gibi kıyma sığır eti için minimum iç pişirme sıcaklığı nedir?","hi":"कीमा बीफ, जैसे हैमबर्गर पैटीज़, के लिए न्यूनतम आंतरिक खाना पकाने का तापमान क्या है?","ar":"ما الحد الأدنى لدرجة حرارة الطهي الداخلية للحم البقري المفروم، مثل أقراص الهامبرغر؟"},"o":[{"en":"145°F","es":"145°F","ru":"145°F","tr":"145°F","hi":"145°F","ar":"145°F"},{"en":"150°F","es":"150°F","ru":"150°F","tr":"150°F","hi":"150°F","ar":"150°F"},{"en":"155°F","es":"155°F","ru":"155°F","tr":"155°F","hi":"155°F","ar":"155°F"},{"en":"165°F","es":"165°F","ru":"165°F","tr":"165°F","hi":"165°F","ar":"165°F"}],"e":{"en":"Ground (comminuted) meat must reach 155°F for 17 seconds, because grinding spreads surface bacteria throughout the meat.","es":"La carne molida (triturada) debe alcanzar 155°F durante 17 segundos, porque la molienda distribuye las bacterias de la superficie por toda la carne.","ru":"Измельчённое (фаршированное) мясо должно достичь 155°F в течение 17 секунд, поскольку измельчение распространяет поверхностные бактерии по всему мясу.","tr":"Kıyma yapma işlemi yüzeydeki bakterileri etin her yerine yaydığından, kıyılmış (parçalanmış) et 17 saniye boyunca 155°F'ye ulaşmalıdır.","hi":"कीमा (बारीक किया हुआ) मांस को 17 सेकंड के लिए 155°F तक पहुंचना चाहिए, क्योंकि कीमा बनाने से सतह के बैक्टीरिया पूरे मांस में फैल जाते हैं।","ar":"يجب أن يصل اللحم المفروم (المُجزَّأ) إلى 155°F لمدة 17 ثانية، لأن الفرم ينشر بكتيريا السطح في جميع أنحاء اللحم."}},{"cat":"temp","a":2,"q":{"en":"Fish (seafood), pork chops, and eggs cooked for immediate service must reach a minimum internal temperature of:","es":"El pescado (mariscos), las chuletas de cerdo y los huevos cocinados para servicio inmediato deben alcanzar una temperatura interna mínima de:","ru":"Рыба (морепродукты), свиные отбивные и яйца, приготовленные для немедленной подачи, должны достичь минимальной внутренней температуры:","tr":"Anında servis için pişirilen balık (deniz ürünleri), domuz pirzolası ve yumurtalar, minimum hangi iç sıcaklığa ulaşmalıdır?","hi":"तत्काल सेवा के लिए पकाई गई मछली (सीफूड), पोर्क चॉप्स, और अंडे न्यूनतम आंतरिक तापमान तक पहुंचने चाहिए:","ar":"يجب أن تصل الأسماك (المأكولات البحرية) وشرائح لحم الخنزير والبيض المطهوة للتقديم الفوري إلى حد أدنى من درجة الحرارة الداخلية قدره:"},"o":[{"en":"135°F","es":"135°F","ru":"135°F","tr":"135°F","hi":"135°F","ar":"135°F"},{"en":"140°F","es":"140°F","ru":"140°F","tr":"140°F","hi":"140°F","ar":"140°F"},{"en":"145°F","es":"145°F","ru":"145°F","tr":"145°F","hi":"145°F","ar":"145°F"},{"en":"155°F","es":"155°F","ru":"155°F","tr":"155°F","hi":"155°F","ar":"155°F"}],"e":{"en":"Seafood, intact pork, and eggs cooked to order for immediate service must reach 145°F for 15 seconds under the FDA Food Code.","es":"Los mariscos, el cerdo intacto y los huevos cocinados al momento para servicio inmediato deben alcanzar 145°F durante 15 segundos según el Código de Alimentos de la FDA.","ru":"Морепродукты, цельная свинина и яйца, приготовленные на заказ для немедленной подачи, должны достичь 145°F в течение 15 секунд согласно FDA Food Code (Пищевому кодексу).","tr":"FDA Gıda Kanunu (Food Code) uyarınca, anında servis için sipariş üzerine pişirilen deniz ürünleri, bütün (sağlam) domuz eti ve yumurtalar 15 saniye boyunca 145°F'ye ulaşmalıdır.","hi":"FDA फूड कोड के तहत तत्काल सेवा के लिए ऑर्डर पर पकाए गए सीफूड, सही-सलामत पोर्क, और अंडे 15 सेकंड के लिए 145°F तक पहुंचने चाहिए।","ar":"يجب أن تصل المأكولات البحرية ولحم الخنزير غير المفروم والبيض المطهو حسب الطلب للتقديم الفوري إلى 145°F لمدة 15 ثانية بموجب قانون الغذاء الصادر عن FDA."}},{"cat":"temp","a":0,"q":{"en":"A whole cut of beef roast is cooked to 145°F. What additional step does the FDA Food Code require?","es":"Un corte entero de carne de res asada se cocina a 145°F. ¿Qué paso adicional exige el Código de Alimentos de la FDA?","ru":"Цельный кусок говяжьей вырезки приготовлен до 145°F. Какой дополнительный шаг требует FDA Food Code (Пищевой кодекс)?","tr":"Bütün bir parça sığır rosto 145°F'ye kadar pişirilir. FDA Gıda Kanunu (Food Code) ek olarak hangi adımı gerektirir?","hi":"बीफ रोस्ट का एक पूरा टुकड़ा 145°F तक पकाया जाता है। FDA फूड कोड किस अतिरिक्त कदम की आवश्यकता मानता है?","ar":"تُطهى قطعة كاملة من شواء اللحم البقري إلى 145°F. ما الخطوة الإضافية التي يشترطها قانون الغذاء الصادر عن FDA؟"},"o":[{"en":"A 3-minute rest at or above that temperature","es":"Un reposo de 3 minutos a esa temperatura o por encima de ella","ru":"3-минутную выдержку при этой температуре или выше","tr":"Bu sıcaklıkta veya üzerinde 3 dakikalık bekleme (dinlendirme)","hi":"उस तापमान पर या उससे ऊपर 3 मिनट का विश्राम","ar":"إراحة لمدة 3 دقائق عند تلك الدرجة أو أعلى منها"},{"en":"An immediate ice-water bath","es":"Un baño de agua helada inmediato","ru":"Немедленную ванну с ледяной водой","tr":"Anında buzlu su banyosu","hi":"एक तत्काल बर्फ-पानी का स्नान","ar":"حمام بماء مثلج فوري"},{"en":"Reheating to 165°F","es":"Recalentar a 165°F","ru":"Повторный нагрев до 165°F","tr":"165°F'ye yeniden ısıtma","hi":"165°F तक पुनः गर्म करना","ar":"إعادة التسخين إلى 165°F"},{"en":"A 30-second rest before slicing","es":"Un reposo de 30 segundos antes de rebanar","ru":"30-секундную выдержку перед нарезкой","tr":"Dilimlemeden önce 30 saniyelik bekleme","hi":"काटने से पहले 30 सेकंड का विश्राम","ar":"إراحة لمدة 30 ثانية قبل التقطيع"}],"e":{"en":"Whole cuts of beef and pork cooked to 145°F require a 3-minute rest time, during which the temperature is maintained to ensure pathogen reduction.","es":"Los cortes enteros de res y cerdo cocinados a 145°F requieren un tiempo de reposo de 3 minutos, durante el cual se mantiene la temperatura para asegurar la reducción de patógenos.","ru":"Цельные куски говядины и свинины, приготовленные до 145°F, требуют 3-минутной выдержки, в течение которой температура поддерживается для обеспечения снижения количества патогенов.","tr":"145°F'ye pişirilen bütün parça sığır ve domuz eti, patojen azaltmayı sağlamak için sıcaklığın korunduğu 3 dakikalık bir dinlendirme süresi gerektirir.","hi":"145°F तक पकाए गए बीफ और पोर्क के पूरे टुकड़ों के लिए 3 मिनट के विश्राम समय की आवश्यकता होती है, जिसके दौरान रोगजनक कमी सुनिश्चित करने के लिए तापमान बनाए रखा जाता है।","ar":"تتطلب القطع الكاملة من اللحم البقري ولحم الخنزير المطهوة إلى 145°F وقت إراحة قدره 3 دقائق، يتم خلالها الحفاظ على درجة الحرارة لضمان تقليل مسببات الأمراض."}},{"cat":"temp","a":3,"q":{"en":"Previously cooked food that is being reheated for hot holding must reach what minimum internal temperature?","es":"Los alimentos previamente cocinados que se recalientan para mantenimiento en caliente deben alcanzar ¿qué temperatura interna mínima?","ru":"Ранее приготовленная пища, которую повторно разогревают для горячего хранения, должна достичь какой минимальной внутренней температуры?","tr":"Sıcak muhafaza için yeniden ısıtılan, daha önce pişirilmiş gıda hangi minimum iç sıcaklığa ulaşmalıdır?","hi":"पहले से पका हुआ भोजन जिसे हॉट होल्डिंग के लिए पुनः गर्म किया जा रहा है, उसे किस न्यूनतम आंतरिक तापमान तक पहुंचना चाहिए?","ar":"يجب أن يصل الطعام المطهو مسبقاً والذي يُعاد تسخينه للحفظ الساخن إلى أيِّ حد أدنى من درجة الحرارة الداخلية؟"},"o":[{"en":"135°F","es":"135°F","ru":"135°F","tr":"135°F","hi":"135°F","ar":"135°F"},{"en":"145°F","es":"145°F","ru":"145°F","tr":"145°F","hi":"145°F","ar":"145°F"},{"en":"155°F","es":"155°F","ru":"155°F","tr":"155°F","hi":"155°F","ar":"155°F"},{"en":"165°F","es":"165°F","ru":"165°F","tr":"165°F","hi":"165°F","ar":"165°F"}],"e":{"en":"Food reheated for hot holding must reach 165°F for 15 seconds to be safe.","es":"Los alimentos recalentados para mantenimiento en caliente deben alcanzar 165°F durante 15 segundos para ser seguros.","ru":"Пища, разогреваемая для горячего хранения, должна достичь 165°F в течение 15 секунд, чтобы быть безопасной.","tr":"Sıcak muhafaza için yeniden ısıtılan gıda, güvenli olması için 15 saniye boyunca 165°F'ye ulaşmalıdır.","hi":"हॉट होल्डिंग के लिए पुनः गर्म किए गए भोजन को सुरक्षित होने के लिए 15 सेकंड के लिए 165°F तक पहुंचना चाहिए।","ar":"يجب أن يصل الطعام المُعاد تسخينه للحفظ الساخن إلى 165°F لمدة 15 ثانية ليكون آمناً."}},{"cat":"temp","a":1,"q":{"en":"When reheating food for hot holding, the food must reach the required temperature within how many hours?","es":"Al recalentar alimentos para mantenimiento en caliente, el alimento debe alcanzar la temperatura requerida dentro de ¿cuántas horas?","ru":"При повторном разогреве пищи для горячего хранения пища должна достичь требуемой температуры в течение скольких часов?","tr":"Gıdayı sıcak muhafaza için yeniden ısıtırken, gıda gerekli sıcaklığa kaç saat içinde ulaşmalıdır?","hi":"हॉट होल्डिंग के लिए भोजन को पुनः गर्म करते समय, भोजन को कितने घंटों के भीतर आवश्यक तापमान तक पहुंचना चाहिए?","ar":"عند إعادة تسخين الطعام للحفظ الساخن، يجب أن يصل الطعام إلى درجة الحرارة المطلوبة في غضون كم ساعة؟"},"o":[{"en":"1 hour","es":"1 hora","ru":"1 hour","tr":"1 saat","hi":"1 घंटा","ar":"1 hour"},{"en":"2 hours","es":"2 horas","ru":"2 hours","tr":"2 saat","hi":"2 घंटे","ar":"2 hours"},{"en":"4 hours","es":"4 horas","ru":"4 hours","tr":"4 saat","hi":"4 घंटे","ar":"4 hours"},{"en":"6 hours","es":"6 horas","ru":"6 hours","tr":"6 saat","hi":"6 घंटे","ar":"6 hours"}],"e":{"en":"Reheating for hot holding must bring food to 165°F within 2 hours to minimize the time spent in the danger zone.","es":"El recalentamiento para mantenimiento en caliente debe llevar el alimento a 165°F dentro de 2 horas para minimizar el tiempo en la zona de peligro.","ru":"Повторный разогрев для горячего хранения должен довести пищу до 165°F в течение 2 часов, чтобы минимизировать время, проведённое в опасной температурной зоне.","tr":"Sıcak muhafaza için yeniden ısıtma, tehlikeli sıcaklık bölgesinde geçirilen süreyi en aza indirmek için gıdayı 2 saat içinde 165°F'ye getirmelidir.","hi":"हॉट होल्डिंग के लिए पुनः गर्म करने से खतरनाक तापमान क्षेत्र में बिताए गए समय को कम करने के लिए भोजन को 2 घंटे के भीतर 165°F तक लाना चाहिए।","ar":"يجب أن تُوصِل إعادة التسخين للحفظ الساخن الطعامَ إلى 165°F في غضون 2 hours لتقليل الوقت المُمضى في منطقة الخطر الحرارية."}},{"cat":"temp","a":2,"q":{"en":"What is the minimum temperature at which hot TCS foods must be held on a steam table or buffet line?","es":"¿Cuál es la temperatura mínima a la que deben mantenerse los alimentos TCS calientes en una mesa de vapor o línea de bufé?","ru":"Какова минимальная температура, при которой горячие TCS-продукты должны храниться на паровом столе или линии буфета?","tr":"Sıcak TCS gıdaların bir buharlı tezgahta veya açık büfe hattında tutulması gereken minimum sıcaklık nedir?","hi":"स्टीम टेबल या बुफे लाइन पर गर्म TCS भोजन को किस न्यूनतम तापमान पर रखा जाना चाहिए?","ar":"ما الحد الأدنى لدرجة الحرارة التي يجب عندها حفظ أطعمة TCS الساخنة على طاولة بخارية أو خط بوفيه؟"},"o":[{"en":"125°F","es":"125°F","ru":"125°F","tr":"125°F","hi":"125°F","ar":"125°F"},{"en":"130°F","es":"130°F","ru":"130°F","tr":"130°F","hi":"130°F","ar":"130°F"},{"en":"135°F","es":"135°F","ru":"135°F","tr":"135°F","hi":"135°F","ar":"135°F"},{"en":"145°F","es":"145°F","ru":"145°F","tr":"145°F","hi":"145°F","ar":"145°F"}],"e":{"en":"Hot TCS foods must be held at 135°F or above to stay out of the danger zone.","es":"Los alimentos TCS calientes deben mantenerse a 135°F o más para permanecer fuera de la zona de peligro.","ru":"Горячие TCS-продукты должны храниться при температуре 135°F или выше, чтобы оставаться вне опасной температурной зоны.","tr":"Sıcak TCS gıdalar, tehlikeli sıcaklık bölgesinin dışında kalmak için 135°F veya üzerinde tutulmalıdır.","hi":"गर्म TCS भोजन को खतरनाक तापमान क्षेत्र से बाहर रहने के लिए 135°F या उससे ऊपर रखा जाना चाहिए।","ar":"يجب حفظ أطعمة TCS الساخنة عند 135°F أو أعلى للبقاء خارج منطقة الخطر الحرارية."}},{"cat":"temp","a":1,"q":{"en":"What is the maximum temperature at which cold TCS foods may be held?","es":"¿Cuál es la temperatura máxima a la que pueden mantenerse los alimentos TCS fríos?","ru":"Какова максимальная температура, при которой могут храниться холодные TCS-продукты?","tr":"Soğuk TCS gıdaların tutulabileceği maksimum sıcaklık nedir?","hi":"ठंडे TCS भोजन को किस अधिकतम तापमान पर रखा जा सकता है?","ar":"ما الحد الأقصى لدرجة الحرارة التي يجوز عندها حفظ أطعمة TCS الباردة؟"},"o":[{"en":"38°F","es":"38°F","ru":"38°F","tr":"38°F","hi":"38°F","ar":"38°F"},{"en":"41°F","es":"41°F","ru":"41°F","tr":"41°F","hi":"41°F","ar":"41°F"},{"en":"45°F","es":"45°F","ru":"45°F","tr":"45°F","hi":"45°F","ar":"45°F"},{"en":"50°F","es":"50°F","ru":"50°F","tr":"50°F","hi":"50°F","ar":"50°F"}],"e":{"en":"Cold TCS foods must be held at 41°F or below to limit bacterial growth.","es":"Los alimentos TCS fríos deben mantenerse a 41°F o menos para limitar el crecimiento bacteriano.","ru":"Холодные TCS-продукты должны храниться при температуре 41°F или ниже, чтобы ограничить рост бактерий.","tr":"Soğuk TCS gıdalar, bakteriyel üremeyi sınırlamak için 41°F veya altında tutulmalıdır.","hi":"ठंडे TCS भोजन को बैक्टीरिया वृद्धि सीमित करने के लिए 41°F या उससे नीचे रखा जाना चाहिए।","ar":"يجب حفظ أطعمة TCS الباردة عند 41°F أو أقل للحد من النمو البكتيري."}},{"cat":"temp","a":1,"q":{"en":"During the first stage of cooling, hot food must be cooled from 135°F down to 70°F within how long?","es":"Durante la primera etapa de enfriamiento, el alimento caliente debe enfriarse de 135°F a 70°F en ¿cuánto tiempo?","ru":"На первом этапе охлаждения горячая пища должна быть охлаждена со 135°F до 70°F в течение какого времени?","tr":"Soğutmanın ilk aşamasında, sıcak gıda 135°F'den 70°F'ye ne kadar süre içinde soğutulmalıdır?","hi":"ठंडा करने के पहले चरण के दौरान, गर्म भोजन को 135°F से 70°F तक कितनी देर के भीतर ठंडा किया जाना चाहिए?","ar":"خلال المرحلة الأولى من التبريد، يجب تبريد الطعام الساخن من 135°F نزولاً إلى 70°F في غضون كم من الوقت؟"},"o":[{"en":"1 hour","es":"1 hora","ru":"1 hour","tr":"1 saat","hi":"1 घंटा","ar":"1 hour"},{"en":"2 hours","es":"2 horas","ru":"2 hours","tr":"2 saat","hi":"2 घंटे","ar":"2 hours"},{"en":"4 hours","es":"4 horas","ru":"4 hours","tr":"4 saat","hi":"4 घंटे","ar":"4 hours"},{"en":"6 hours","es":"6 horas","ru":"6 hours","tr":"6 saat","hi":"6 घंटे","ar":"6 hours"}],"e":{"en":"The FDA Food Code requires cooling from 135°F to 70°F within 2 hours during the first stage of the cooling process.","es":"El Código de Alimentos de la FDA exige enfriar de 135°F a 70°F dentro de 2 horas durante la primera etapa del proceso de enfriamiento.","ru":"FDA Food Code (Пищевой кодекс) требует охлаждения со 135°F до 70°F в течение 2 часов на первом этапе процесса охлаждения.","tr":"FDA Gıda Kanunu (Food Code), soğutma sürecinin ilk aşamasında 135°F'den 70°F'ye soğutmanın 2 saat içinde yapılmasını gerektirir.","hi":"FDA फूड कोड के अनुसार ठंडा करने की प्रक्रिया के पहले चरण के दौरान 135°F से 70°F तक 2 घंटे के भीतर ठंडा करना आवश्यक है।","ar":"يشترط قانون الغذاء الصادر عن FDA التبريد من 135°F إلى 70°F في غضون 2 hours خلال المرحلة الأولى من عملية التبريد."}},{"cat":"temp","a":2,"q":{"en":"After food reaches 70°F, it must be cooled from 70°F to 41°F within how many additional hours?","es":"Después de que el alimento alcanza 70°F, debe enfriarse de 70°F a 41°F dentro de ¿cuántas horas adicionales?","ru":"После того как пища достигает 70°F, она должна быть охлаждена с 70°F до 41°F в течение скольких дополнительных часов?","tr":"Gıda 70°F'ye ulaştıktan sonra, 70°F'den 41°F'ye kaç saat içinde daha soğutulmalıdır?","hi":"भोजन के 70°F तक पहुंचने के बाद, इसे 70°F से 41°F तक कितने अतिरिक्त घंटों के भीतर ठंडा किया जाना चाहिए?","ar":"بعد أن يصل الطعام إلى 70°F، يجب تبريده من 70°F إلى 41°F في غضون كم ساعة إضافية؟"},"o":[{"en":"2 hours","es":"2 horas","ru":"2 hours","tr":"2 saat","hi":"2 घंटे","ar":"2 hours"},{"en":"3 hours","es":"3 horas","ru":"3 hours","tr":"3 saat","hi":"3 घंटे","ar":"3 hours"},{"en":"4 hours","es":"4 horas","ru":"4 hours","tr":"4 saat","hi":"4 घंटे","ar":"4 hours"},{"en":"5 hours","es":"5 horas","ru":"5 hours","tr":"5 saat","hi":"5 घंटे","ar":"5 hours"}],"e":{"en":"The second cooling stage allows 4 additional hours to go from 70°F to 41°F, for a total of 6 hours of cooling time.","es":"La segunda etapa de enfriamiento permite 4 horas adicionales para pasar de 70°F a 41°F, para un total de 6 horas de tiempo de enfriamiento.","ru":"Второй этап охлаждения отводит 4 дополнительных часа на переход с 70°F до 41°F, что в сумме даёт 6 часов времени охлаждения.","tr":"İkinci soğutma aşaması, 70°F'den 41°F'ye geçmek için 4 saat daha süre tanır; bu da toplam 6 saatlik soğutma süresi demektir.","hi":"दूसरा ठंडा करने का चरण 70°F से 41°F तक जाने के लिए 4 अतिरिक्त घंटे की अनुमति देता है, कुल 6 घंटे के ठंडा करने के समय के लिए।","ar":"تتيح مرحلة التبريد الثانية 4 hours إضافية للانتقال من 70°F إلى 41°F، بإجمالي 6 hours من وقت التبريد."}},{"cat":"temp","a":2,"q":{"en":"Under the two-stage cooling rule, what is the maximum total time allowed to cool food from 135°F to 41°F?","es":"Según la regla de enfriamiento en dos etapas, ¿cuál es el tiempo total máximo permitido para enfriar el alimento de 135°F a 41°F?","ru":"Согласно двухэтапному правилу охлаждения, каково максимальное общее время, отведённое на охлаждение пищи со 135°F до 41°F?","tr":"İki aşamalı soğutma kuralı uyarınca, gıdayı 135°F'den 41°F'ye soğutmak için izin verilen maksimum toplam süre nedir?","hi":"दो-चरण ठंडा करने के नियम के तहत, भोजन को 135°F से 41°F तक ठंडा करने के लिए अनुमत अधिकतम कुल समय क्या है?","ar":"بموجب قاعدة التبريد ذات المرحلتين، ما الحد الأقصى لإجمالي الوقت المسموح به لتبريد الطعام من 135°F إلى 41°F؟"},"o":[{"en":"4 hours","es":"4 horas","ru":"4 hours","tr":"4 saat","hi":"4 घंटे","ar":"4 hours"},{"en":"5 hours","es":"5 horas","ru":"5 hours","tr":"5 saat","hi":"5 घंटे","ar":"5 hours"},{"en":"6 hours","es":"6 horas","ru":"6 hours","tr":"6 saat","hi":"6 घंटे","ar":"6 hours"},{"en":"8 hours","es":"8 horas","ru":"8 hours","tr":"8 saat","hi":"8 घंटे","ar":"8 hours"}],"e":{"en":"The total cooling time may not exceed 6 hours: 2 hours from 135°F to 70°F plus 4 hours from 70°F to 41°F.","es":"El tiempo total de enfriamiento no puede exceder las 6 horas: 2 horas de 135°F a 70°F más 4 horas de 70°F a 41°F.","ru":"Общее время охлаждения не может превышать 6 часов: 2 часа со 135°F до 70°F плюс 4 часа с 70°F до 41°F.","tr":"Toplam soğutma süresi 6 saati aşamaz: 135°F'den 70°F'ye 2 saat artı 70°F'den 41°F'ye 4 saat.","hi":"कुल ठंडा करने का समय 6 घंटे से अधिक नहीं हो सकता: 135°F से 70°F तक 2 घंटे और 70°F से 41°F तक 4 घंटे।","ar":"يجب ألا يتجاوز إجمالي وقت التبريد 6 hours: 2 hours من 135°F إلى 70°F زائد 4 hours من 70°F إلى 41°F."}},{"cat":"temp","a":2,"q":{"en":"Which of the following is NOT an approved method for thawing frozen TCS food?","es":"¿Cuál de los siguientes NO es un método aprobado para descongelar alimentos TCS congelados?","ru":"Какой из перечисленных методов НЕ является одобренным методом размораживания замороженных TCS-продуктов?","tr":"Aşağıdakilerden hangisi donmuş TCS gıdayı çözmek için onaylanmış bir yöntem DEĞİLDİR?","hi":"जमे हुए TCS भोजन को पिघलाने के लिए इनमें से कौन सी एक अनुमोदित विधि नहीं है?","ar":"أيٌّ مما يلي ليس طريقة معتمدة لإذابة الطعام المجمَّد من نوع TCS؟"},"o":[{"en":"In a refrigerator at 41°F or below","es":"En un refrigerador a 41°F o menos","ru":"В холодильнике при температуре 41°F или ниже","tr":"41°F veya altındaki bir buzdolabında","hi":"41°F या उससे नीचे रेफ्रिजरेटर में","ar":"في ثلاجة عند 41°F أو أقل"},{"en":"Under running water at 70°F or below","es":"Bajo agua corriente a 70°F o menos","ru":"Под проточной водой при температуре 70°F или ниже","tr":"70°F veya altındaki akan su altında","hi":"70°F या उससे नीचे बहते पानी के नीचे","ar":"تحت ماء جارٍ عند 70°F أو أقل"},{"en":"On a countertop at room temperature","es":"En una encimera a temperatura ambiente","ru":"На столешнице при комнатной температуре","tr":"Oda sıcaklığında bir tezgah üzerinde","hi":"कमरे के तापमान पर काउंटरटॉप पर","ar":"على سطح المنضدة في درجة حرارة الغرفة"},{"en":"In a microwave, then cooked immediately","es":"En un microondas, y luego cocinado de inmediato","ru":"В микроволновой печи с последующим немедленным приготовлением","tr":"Mikrodalgada, ardından hemen pişirilerek","hi":"माइक्रोवेव में, फिर तुरंत पकाया गया","ar":"في الميكروويف، ثم طهيه فوراً"}],"e":{"en":"Thawing at room temperature is never permitted because it lets the surface of the food sit in the danger zone; running water must be 70°F or below.","es":"Descongelar a temperatura ambiente nunca está permitido porque deja la superficie del alimento en la zona de peligro; el agua corriente debe estar a 70°F o menos.","ru":"Размораживание при комнатной температуре никогда не допускается, поскольку оно позволяет поверхности продукта находиться в опасной температурной зоне; проточная вода должна быть 70°F или ниже.","tr":"Oda sıcaklığında çözme asla izin verilmez çünkü gıdanın yüzeyinin tehlikeli sıcaklık bölgesinde kalmasına neden olur; akan su 70°F veya altında olmalıdır.","hi":"कमरे के तापमान पर पिघलाना कभी भी अनुमत नहीं है क्योंकि यह भोजन की सतह को खतरनाक तापमान क्षेत्र में बैठने देता है; बहता पानी 70°F या उससे नीचे होना चाहिए।","ar":"لا يُسمح بالإذابة في درجة حرارة الغرفة أبداً لأنها تترك سطح الطعام في منطقة الخطر الحرارية؛ ويجب أن يكون الماء الجاري عند 70°F أو أقل."}},{"cat":"temp","a":2,"q":{"en":"If thawing food under running water, the water temperature must be at or below:","es":"Si se descongela el alimento bajo agua corriente, la temperatura del agua debe ser igual o inferior a:","ru":"При размораживании продукта под проточной водой температура воды должна быть на уровне или ниже:","tr":"Gıda akan su altında çözülüyorsa, su sıcaklığı en fazla şu olmalıdır:","hi":"बहते पानी के नीचे भोजन पिघलाते समय, पानी का तापमान इस पर या उससे नीचे होना चाहिए:","ar":"إذا تم إذابة الطعام تحت ماء جارٍ، فيجب أن تكون درجة حرارة الماء عند أو دون:"},"o":[{"en":"41°F","es":"41°F","ru":"41°F","tr":"41°F","hi":"41°F","ar":"41°F"},{"en":"60°F","es":"60°F","ru":"60°F","tr":"60°F","hi":"60°F","ar":"60°F"},{"en":"70°F","es":"70°F","ru":"70°F","tr":"70°F","hi":"70°F","ar":"70°F"},{"en":"75°F","es":"75°F","ru":"75°F","tr":"75°F","hi":"75°F","ar":"75°F"}],"e":{"en":"Running-water thawing requires potable water at 70°F or below, flowing fast enough to wash food particles into the drain overflow.","es":"La descongelación con agua corriente requiere agua potable a 70°F o menos, fluyendo con la rapidez suficiente para arrastrar las partículas de alimento hacia el desagüe.","ru":"Размораживание проточной водой требует питьевой воды при температуре 70°F или ниже, текущей достаточно быстро, чтобы смывать частицы продукта в перелив сливного отверстия.","tr":"Akan suyla çözme, gıda parçacıklarını giderin taşma kanalına yıkayacak kadar hızlı akan, 70°F veya altında içme suyu gerektirir.","hi":"बहते-पानी से पिघलाने के लिए 70°F या उससे नीचे पीने योग्य पानी की आवश्यकता होती है, जो इतनी तेज़ी से बहता हो कि भोजन के कण नाली के अतिप्रवाह में बह जाएं।","ar":"تتطلب الإذابة بالماء الجاري ماءً صالحاً للشرب عند 70°F أو أقل، يتدفق بسرعة كافية لجرف جزيئات الطعام إلى فائض التصريف."}},{"cat":"temp","a":1,"q":{"en":"When calibrating a thermometer using the ice-point method, the thermometer should read:","es":"Al calibrar un termómetro usando el método de punto de hielo, el termómetro debe marcar:","ru":"При калибровке термометра методом точки таяния льда термометр должен показывать:","tr":"Buz noktası (ice-point) yöntemiyle bir termometre kalibre edilirken, termometre şunu göstermelidir:","hi":"आइस-पॉइंट विधि का उपयोग करके थर्मामीटर को कैलिब्रेट करते समय, थर्मामीटर को यह दिखाना चाहिए:","ar":"عند معايرة ميزان الحرارة باستخدام طريقة نقطة الثلج، ينبغي أن يقرأ الميزان:"},"o":[{"en":"28°F","es":"28°F","ru":"28°F","tr":"28°F","hi":"28°F","ar":"28°F"},{"en":"32°F","es":"32°F","ru":"32°F","tr":"32°F","hi":"32°F","ar":"32°F"},{"en":"34°F","es":"34°F","ru":"34°F","tr":"34°F","hi":"34°F","ar":"34°F"},{"en":"40°F","es":"40°F","ru":"40°F","tr":"40°F","hi":"40°F","ar":"40°F"}],"e":{"en":"In the ice-point (ice-water) method, a correctly calibrated thermometer reads 32°F, the freezing point of water.","es":"En el método de punto de hielo (agua con hielo), un termómetro correctamente calibrado marca 32°F, el punto de congelación del agua.","ru":"При методе точки таяния льда (ледяной воды) правильно откалиброванный термометр показывает 32°F — точку замерзания воды.","tr":"Buz noktası (buzlu su) yönteminde, doğru şekilde kalibre edilmiş bir termometre, suyun donma noktası olan 32°F'yi gösterir.","hi":"आइस-पॉइंट (आइस-वॉटर) विधि में, एक सही ढंग से कैलिब्रेट किया गया थर्मामीटर 32°F दिखाता है, जो पानी का जमने का बिंदु है।","ar":"في طريقة نقطة الثلج (الماء المثلج)، يقرأ ميزان الحرارة المُعايَر بشكل صحيح 32°F، وهي نقطة تجمد الماء."}},{"cat":"temp","a":1,"q":{"en":"Where should a food thermometer be inserted to take an accurate reading of a food's internal temperature?","es":"¿Dónde debe insertarse un termómetro de alimentos para obtener una lectura precisa de la temperatura interna de un alimento?","ru":"Куда следует вставлять пищевой термометр для точного измерения внутренней температуры продукта?","tr":"Bir gıdanın iç sıcaklığını doğru ölçmek için gıda termometresi nereye batırılmalıdır?","hi":"भोजन के आंतरिक तापमान की सटीक रीडिंग लेने के लिए एक फूड थर्मामीटर को कहां डाला जाना चाहिए?","ar":"أين ينبغي إدخال ميزان حرارة الطعام للحصول على قراءة دقيقة لدرجة الحرارة الداخلية للطعام؟"},"o":[{"en":"Near the surface of the food","es":"Cerca de la superficie del alimento","ru":"Рядом с поверхностью продукта","tr":"Gıdanın yüzeyine yakın bir yere","hi":"भोजन की सतह के पास","ar":"قرب سطح الطعام"},{"en":"In the thickest part of the food","es":"En la parte más gruesa del alimento","ru":"В самую толстую часть продукта","tr":"Gıdanın en kalın kısmına","hi":"भोजन के सबसे मोटे हिस्से में","ar":"في أكثف جزء من الطعام"},{"en":"Touching the bottom of the pan","es":"Tocando el fondo de la sartén","ru":"Касаясь дна кастрюли","tr":"Tencerenin dibine değecek şekilde","hi":"पैन के तल को छूते हुए","ar":"ملامساً لقاع الإناء"},{"en":"Just under the food's outer crust","es":"Justo debajo de la corteza exterior del alimento","ru":"Прямо под наружной корочкой продукта","tr":"Gıdanın dış kabuğunun hemen altına","hi":"भोजन की बाहरी परत के ठीक नीचे","ar":"تحت القشرة الخارجية للطعام مباشرة"}],"e":{"en":"The thermometer stem should be placed in the thickest part of the food, away from bone, fat, or the container, to read the true internal temperature.","es":"El vástago del termómetro debe colocarse en la parte más gruesa del alimento, lejos del hueso, la grasa o el recipiente, para leer la verdadera temperatura interna.","ru":"Стержень термометра следует помещать в самую толстую часть продукта, вдали от кости, жира или стенок ёмкости, чтобы измерить истинную внутреннюю температуру.","tr":"Termometre çubuğu, gerçek iç sıcaklığı okumak için kemikten, yağdan veya kaptan uzakta, gıdanın en kalın kısmına yerleştirilmelidir.","hi":"थर्मामीटर का तना भोजन के सबसे मोटे हिस्से में, हड्डी, वसा, या कंटेनर से दूर रखा जाना चाहिए, ताकि सही आंतरिक तापमान पढ़ा जा सके।","ar":"ينبغي وضع ساق ميزان الحرارة في أكثف جزء من الطعام، بعيداً عن العظم أو الدهن أو الحاوية، لقراءة درجة الحرارة الداخلية الحقيقية."}},{"cat":"temp","a":1,"q":{"en":"Which of the following is a TCS (potentially hazardous) food that requires time and temperature control for safety?","es":"¿Cuál de los siguientes es un alimento TCS (potencialmente peligroso) que requiere control de tiempo y temperatura para su seguridad?","ru":"Что из перечисленного является TCS-продуктом (потенциально опасным продуктом), требующим контроля времени и температуры для безопасности?","tr":"Aşağıdakilerden hangisi, güvenlik için zaman ve sıcaklık kontrolü gerektiren bir TCS (potansiyel olarak tehlikeli) gıdadır?","hi":"इनमें से कौन सा एक TCS (संभावित रूप से खतरनाक) भोजन है जिसे सुरक्षा के लिए समय और तापमान नियंत्रण की आवश्यकता होती है?","ar":"أيٌّ مما يلي يُعدّ طعاماً من نوع TCS (يُحتمل أن يكون خطراً) يتطلب التحكم في الوقت ودرجة الحرارة للسلامة؟"},"o":[{"en":"Dry white rice","es":"Arroz blanco seco","ru":"Сухой белый рис","tr":"Kuru beyaz pirinç","hi":"सूखा सफेद चावल","ar":"الأرز الأبيض الجاف"},{"en":"Cut cantaloupe","es":"Melón cantalupo cortado","ru":"Нарезанная дыня канталупа","tr":"Kesilmiş kavun (cantaloupe)","hi":"कटा हुआ खरबूजा (कैंटालूप)","ar":"شمام مقطَّع"},{"en":"Whole raw onions","es":"Cebollas crudas enteras","ru":"Цельный сырой лук","tr":"Bütün çiğ soğan","hi":"साबुत कच्चे प्याज","ar":"بصل نيء كامل"},{"en":"Plain saltine crackers","es":"Galletas saladas tipo saltine simples","ru":"Простые крекеры (солёное печенье)","tr":"Sade tuzlu kraker","hi":"सादे साल्टीन क्रैकर्स","ar":"مقرمشات سالتين عادية"}],"e":{"en":"Cut melons such as cantaloupe are TCS foods because their moisture and neutral pH support rapid bacterial growth once cut.","es":"Los melones cortados, como el cantalupo, son alimentos TCS porque su humedad y su pH neutro favorecen el crecimiento bacteriano rápido una vez cortados.","ru":"Нарезанные дыни, такие как канталупа, являются TCS-продуктами, поскольку их влажность и нейтральный pH поддерживают быстрый рост бактерий после нарезки.","tr":"Kavun gibi kesilmiş kavunlar, kesildikten sonra nem ve nötr pH değerleri hızlı bakteriyel üremeyi desteklediğinden TCS gıdalardır.","hi":"कैंटालूप जैसे कटे हुए खरबूजे TCS भोजन हैं क्योंकि उनकी नमी और तटस्थ pH कटने के बाद तेज़ी से बैक्टीरिया वृद्धि का समर्थन करते हैं।","ar":"يُعدّ الشمام المقطَّع كالكنتالوب طعاماً من نوع TCS لأن رطوبته ودرجة حموضته المتعادلة (pH) تدعمان النمو البكتيري السريع بمجرد تقطيعه."}},{"cat":"temp","a":2,"q":{"en":"If TCS food is held using time alone as a control (no temperature control) starting at 41°F or below, it must be served or discarded within:","es":"Si un alimento TCS se mantiene usando solo el tiempo como control (sin control de temperatura) comenzando a 41°F o menos, debe servirse o desecharse dentro de:","ru":"Если TCS-продукт хранится с использованием только времени в качестве контроля (без контроля температуры) начиная с 41°F или ниже, он должен быть подан или выброшен в течение:","tr":"TCS gıda, 41°F veya altında başlayarak yalnızca zaman kontrol olarak kullanılarak (sıcaklık kontrolü olmadan) tutuluyorsa, ne kadar süre içinde servis edilmeli veya atılmalıdır?","hi":"यदि TCS भोजन को केवल समय को नियंत्रण के रूप में उपयोग करते हुए (कोई तापमान नियंत्रण नहीं) 41°F या उससे नीचे शुरू करते हुए रखा जाता है, तो इसे इसके भीतर परोसा या फेंका जाना चाहिए:","ar":"إذا حُفظ طعام TCS باستخدام الوقت وحده كوسيلة تحكم (دون التحكم في درجة الحرارة) بدءاً من 41°F أو أقل، فيجب تقديمه أو التخلص منه في غضون:"},"o":[{"en":"2 hours","es":"2 horas","ru":"2 hours","tr":"2 saat","hi":"2 घंटे","ar":"2 hours"},{"en":"4 hours","es":"4 horas","ru":"4 hours","tr":"4 saat","hi":"4 घंटे","ar":"4 hours"},{"en":"6 hours","es":"6 horas","ru":"6 hours","tr":"6 saat","hi":"6 घंटे","ar":"6 hours"},{"en":"8 hours","es":"8 horas","ru":"8 hours","tr":"8 saat","hi":"8 घंटे","ar":"8 hours"}],"e":{"en":"Cold TCS food held under the time-as-a-public-health-control method may be kept up to 6 hours if it starts at 41°F or below and does not exceed 70°F, after which it must be discarded.","es":"El alimento TCS frío mantenido bajo el método del tiempo como control de salud pública puede conservarse hasta 6 horas si comienza a 41°F o menos y no excede los 70°F, tras lo cual debe desecharse.","ru":"Холодный TCS-продукт, хранимый по методу «время как мера общественного здоровья», может храниться до 6 часов, если он начинается с 41°F или ниже и не превышает 70°F, после чего он должен быть выброшен.","tr":"Zaman-halk sağlığı kontrolü yöntemiyle tutulan soğuk TCS gıda, 41°F veya altında başlıyor ve 70°F'yi aşmıyorsa 6 saate kadar tutulabilir; bu süreden sonra atılmalıdır.","hi":"समय-को-जन-स्वास्थ्य-नियंत्रण-के-रूप-में विधि के तहत रखे गए ठंडे TCS भोजन को 6 घंटे तक रखा जा सकता है यदि यह 41°F या उससे नीचे शुरू होता है और 70°F से अधिक नहीं होता है, उसके बाद इसे फेंक देना चाहिए।","ar":"يمكن الاحتفاظ بطعام TCS البارد المحفوظ بطريقة الوقت كوسيلة تحكم في الصحة العامة حتى 6 hours إذا بدأ عند 41°F أو أقل ولم يتجاوز 70°F، وبعدها يجب التخلص منه."}},{"cat":"crosscontam","a":1,"q":{"en":"What does cross-contamination mean in a food service operation?","es":"¿Qué significa la contaminación cruzada en una operación de servicio de alimentos?","ru":"Что означает перекрёстное загрязнение в работе предприятия общественного питания?","tr":"Bir gıda servisi işletmesinde çapraz bulaşma ne anlama gelir?","hi":"फूड सर्विस ऑपरेशन में क्रॉस-कॉन्टैमिनेशन का क्या अर्थ है?","ar":"ماذا يعني التلوث المتبادل في عملية خدمة الطعام؟"},"o":[{"en":"Cooking a food to the wrong internal temperature","es":"Cocinar un alimento a la temperatura interna incorrecta","ru":"Приготовление продукта до неправильной внутренней температуры","tr":"Bir gıdayı yanlış iç sıcaklığa pişirmek","hi":"भोजन को गलत आंतरिक तापमान तक पकाना","ar":"طهي طعام إلى درجة حرارة داخلية خاطئة"},{"en":"The transfer of harmful microorganisms or substances from one surface or food to another","es":"La transferencia de microorganismos o sustancias dañinas de una superficie o alimento a otro","ru":"Перенос вредных микроорганизмов или веществ с одной поверхности или продукта на другой","tr":"Zararlı mikroorganizmaların veya maddelerin bir yüzeyden ya da gıdadan diğerine geçmesi","hi":"हानिकारक सूक्ष्मजीवों या पदार्थों का एक सतह या भोजन से दूसरे में स्थानांतरण","ar":"انتقال الكائنات الدقيقة الضارة أو المواد الضارة من سطح أو طعام إلى آخر"},{"en":"Storing food past its expiration date","es":"Almacenar alimentos pasada su fecha de vencimiento","ru":"Хранение продукта по истечении срока годности","tr":"Gıdayı son kullanma tarihinden sonra saklamak","hi":"भोजन को उसकी समाप्ति तिथि के बाद संग्रहीत करना","ar":"تخزين الطعام بعد تاريخ انتهاء صلاحيته"},{"en":"Leaving food in the temperature danger zone too long","es":"Dejar el alimento demasiado tiempo en la zona de temperatura de peligro","ru":"Слишком долгое нахождение продукта в опасной температурной зоне","tr":"Gıdayı tehlikeli sıcaklık bölgesinde çok uzun süre bırakmak","hi":"भोजन को खतरनाक तापमान क्षेत्र में बहुत देर तक छोड़ना","ar":"ترك الطعام في منطقة الخطر الحرارية لمدة طويلة جداً"}],"e":{"en":"Cross-contamination is the transfer of pathogens, allergens, or other harmful substances from one food, surface, or person to another.","es":"La contaminación cruzada es la transferencia de patógenos, alérgenos u otras sustancias dañinas de un alimento, superficie o persona a otro.","ru":"Перекрёстное загрязнение — это перенос патогенов, аллергенов или других вредных веществ с одного продукта, поверхности или человека на другой.","tr":"Çapraz bulaşma, patojenlerin, alerjenlerin veya diğer zararlı maddelerin bir gıdadan, yüzeyden ya da kişiden diğerine geçmesidir.","hi":"क्रॉस-कॉन्टैमिनेशन रोगजनकों, एलर्जन, या अन्य हानिकारक पदार्थों का एक भोजन, सतह, या व्यक्ति से दूसरे में स्थानांतरण है।","ar":"التلوث المتبادل هو انتقال مسببات الأمراض أو مسببات الحساسية أو غيرها من المواد الضارة من طعام أو سطح أو شخص إلى آخر."}},{"cat":"crosscontam","a":2,"q":{"en":"When storing raw chicken and a tray of fresh salad greens in the same refrigerator, where should each be placed?","es":"Al almacenar pollo crudo y una bandeja de hojas frescas para ensalada en el mismo refrigerador, ¿dónde debe colocarse cada uno?","ru":"При хранении сырой курицы и подноса со свежей зеленью для салата в одном холодильнике где следует размещать каждый продукт?","tr":"Çiğ tavuk ile bir tepsi taze salata yeşilliğini aynı buzdolabında saklarken, her biri nereye yerleştirilmelidir?","hi":"कच्चे चिकन और ताज़ी सलाद पत्तियों की एक ट्रे को एक ही रेफ्रिजरेटर में संग्रहीत करते समय, प्रत्येक को कहां रखा जाना चाहिए?","ar":"عند تخزين دجاج نيء وصينية من أوراق سلطة طازجة في الثلاجة نفسها، أين ينبغي وضع كلٍّ منهما؟"},"o":[{"en":"Salad greens on a lower shelf and raw chicken on a higher shelf","es":"Las hojas para ensalada en un estante más bajo y el pollo crudo en un estante más alto","ru":"Зелень для салата на нижней полке, а сырую курицу на верхней","tr":"Salata yeşillikleri alt rafa, çiğ tavuk üst rafa","hi":"सलाद पत्तियां निचली शेल्फ पर और कच्चा चिकन ऊंची शेल्फ पर","ar":"أوراق السلطة على رف أسفل والدجاج النيء على رف أعلى"},{"en":"Both items on the same shelf as long as they are wrapped","es":"Ambos artículos en el mismo estante siempre que estén envueltos","ru":"Оба продукта на одной полке, если они упакованы","tr":"Sarılı oldukları sürece her ikisi de aynı rafa","hi":"दोनों वस्तुएं एक ही शेल्फ पर जब तक वे लपेटी हुई हों","ar":"كلا الصنفين على الرف نفسه ما داما مغلَّفين"},{"en":"Raw chicken on a lower shelf and salad greens on a higher shelf","es":"El pollo crudo en un estante más bajo y las hojas para ensalada en un estante más alto","ru":"Сырую курицу на нижней полке, а зелень для салата на верхней","tr":"Çiğ tavuk alt rafa, salata yeşillikleri üst rafa","hi":"कच्चा चिकन निचली शेल्फ पर और सलाद पत्तियां ऊंची शेल्फ पर","ar":"الدجاج النيء على رف أسفل وأوراق السلطة على رف أعلى"},{"en":"Raw chicken in the door and salad greens in the back","es":"El pollo crudo en la puerta y las hojas para ensalada al fondo","ru":"Сырую курицу в дверце, а зелень для салата в глубине","tr":"Çiğ tavuk kapağa, salata yeşillikleri arkaya","hi":"कच्चा चिकन दरवाज़े में और सलाद पत्तियां पीछे","ar":"الدجاج النيء في الباب وأوراق السلطة في الخلف"}],"e":{"en":"Ready-to-eat foods like salad greens are stored above raw meats so that juices from the raw chicken cannot drip onto and contaminate them.","es":"Los alimentos listos para comer, como las hojas para ensalada, se almacenan por encima de las carnes crudas para que los jugos del pollo crudo no puedan gotear sobre ellos y contaminarlos.","ru":"Готовые к употреблению продукты, такие как зелень для салата, хранятся выше сырого мяса, чтобы соки от сырой курицы не могли капать на них и загрязнять их.","tr":"Salata yeşillikleri gibi yemeye hazır gıdalar, çiğ tavuğun sularının üzerlerine damlayıp onları kirletememesi için çiğ etlerin üzerinde saklanır.","hi":"सलाद पत्तियों जैसे खाने के लिए तैयार भोजन को कच्चे मांस के ऊपर संग्रहीत किया जाता है ताकि कच्चे चिकन का रस उन पर टपक कर उन्हें दूषित न कर सके।","ar":"تُخزَّن الأطعمة الجاهزة للأكل كأوراق السلطة فوق اللحوم النيئة بحيث لا يمكن لعصارة الدجاج النيء أن تقطر عليها وتلوثها."}},{"cat":"crosscontam","a":1,"q":{"en":"In a cooler holding several raw products, which item should be stored on the BOTTOM shelf?","es":"En una cámara de refrigeración que contiene varios productos crudos, ¿qué artículo debe almacenarse en el estante INFERIOR?","ru":"В холодильной камере, где хранятся несколько сырых продуктов, какой продукт следует хранить на НИЖНЕЙ полке?","tr":"Birkaç çiğ ürün bulunan bir soğutucuda, hangi ürün EN ALT rafta saklanmalıdır?","hi":"कई कच्चे उत्पादों को रखने वाले एक कूलर में, किस वस्तु को सबसे निचली (BOTTOM) शेल्फ पर संग्रहीत किया जाना चाहिए?","ar":"في مبرّد يحفظ عدة منتجات نيئة، أيُّ صنف ينبغي تخزينه على الرف السفلي؟"},"o":[{"en":"Raw whole-muscle beef steaks","es":"Filetes de res de músculo entero crudos","ru":"Сырые цельномышечные говяжьи стейки","tr":"Bütün kas dokulu çiğ sığır bifteği","hi":"कच्चे साबुत-मांसपेशी बीफ स्टेक","ar":"شرائح لحم بقري كاملة العضل"},{"en":"Raw poultry","es":"Aves crudas","ru":"Сырую птицу","tr":"Çiğ kümes hayvanı (tavuk vb.)","hi":"कच्ची पोल्ट्री","ar":"دواجن نيئة"},{"en":"Raw fish","es":"Pescado crudo","ru":"Сырую рыбу","tr":"Çiğ balık","hi":"कच्ची मछली","ar":"سمك نيء"},{"en":"Raw ground beef","es":"Carne molida de res cruda","ru":"Сырой говяжий фарш","tr":"Çiğ kıyma sığır eti","hi":"कच्चा कीमा बीफ","ar":"لحم بقري مفروم نيء"}],"e":{"en":"Raw poultry has the highest minimum internal cooking temperature (165°F), so it is stored on the bottom to prevent its juices from dripping onto foods cooked to lower temperatures.","es":"Las aves crudas tienen la temperatura interna mínima de cocción más alta (165°F), por lo que se almacenan en la parte inferior para evitar que sus jugos goteen sobre alimentos que se cocinan a temperaturas más bajas.","ru":"Сырая птица имеет самую высокую минимальную внутреннюю температуру приготовления (165°F), поэтому она хранится внизу, чтобы её соки не капали на продукты, готовящиеся при более низких температурах.","tr":"Çiğ kümes hayvanları en yüksek minimum iç pişirme sıcaklığına (165°F) sahiptir, bu yüzden sularının daha düşük sıcaklıklarda pişirilen gıdaların üzerine damlamasını önlemek için en alta yerleştirilir.","hi":"कच्ची पोल्ट्री का सबसे ऊंचा न्यूनतम आंतरिक खाना पकाने का तापमान (165°F) होता है, इसलिए इसे सबसे नीचे संग्रहीत किया जाता है ताकि इसका रस कम तापमान पर पकाए जाने वाले भोजन पर न टपके।","ar":"للدواجن النيئة أعلى حد أدنى من درجة حرارة الطهي الداخلية (165°F)، لذا تُخزَّن في الأسفل لمنع عصارتها من القطر على الأطعمة التي تُطهى عند درجات حرارة أقل."}},{"cat":"crosscontam","a":1,"q":{"en":"Listing from the TOP shelf down, what is the correct top-to-bottom storage order based on minimum cooking temperature?","es":"Enumerando desde el estante SUPERIOR hacia abajo, ¿cuál es el orden de almacenamiento correcto de arriba hacia abajo según la temperatura mínima de cocción?","ru":"Перечисляя от ВЕРХНЕЙ полки вниз, каков правильный порядок хранения сверху вниз на основе минимальной температуры приготовления?","tr":"En ÜST raftan aşağıya doğru sıralandığında, minimum pişirme sıcaklığına göre doğru üstten alta saklama sırası nedir?","hi":"सबसे ऊपरी (TOP) शेल्फ से नीचे की ओर सूचीबद्ध करते हुए, न्यूनतम खाना पकाने के तापमान के आधार पर ऊपर-से-नीचे संग्रहण का सही क्रम क्या है?","ar":"بدءاً من الرف العلوي نزولاً، ما الترتيب الصحيح للتخزين من الأعلى إلى الأسفل بناءً على الحد الأدنى لدرجة حرارة الطهي؟"},"o":[{"en":"Poultry; ground meat; whole beef and pork; seafood; ready-to-eat food","es":"Aves; carne molida; res y cerdo enteros; mariscos; alimentos listos para comer","ru":"Птица; фарш; цельная говядина и свинина; морепродукты; готовые к употреблению продукты","tr":"Kümes hayvanı; kıyma et; bütün sığır ve domuz; deniz ürünleri; yemeye hazır gıda","hi":"पोल्ट्री; कीमा मांस; साबुत बीफ और पोर्क; सीफूड; खाने के लिए तैयार भोजन","ar":"الدواجن؛ اللحم المفروم؛ اللحم البقري ولحم الخنزير الكاملان؛ المأكولات البحرية؛ الطعام الجاهز للأكل"},{"en":"Ready-to-eat food; seafood; whole beef and pork; ground meat; poultry","es":"Alimentos listos para comer; mariscos; res y cerdo enteros; carne molida; aves","ru":"Готовые к употреблению продукты; морепродукты; цельная говядина и свинина; фарш; птица","tr":"Yemeye hazır gıda; deniz ürünleri; bütün sığır ve domuz; kıyma et; kümes hayvanı","hi":"खाने के लिए तैयार भोजन; सीफूड; साबुत बीफ और पोर्क; कीमा मांस; पोल्ट्री","ar":"الطعام الجاهز للأكل؛ المأكولات البحرية؛ اللحم البقري ولحم الخنزير الكاملان؛ اللحم المفروم؛ الدواجن"},{"en":"Ready-to-eat food; poultry; ground meat; whole beef and pork; seafood","es":"Alimentos listos para comer; aves; carne molida; res y cerdo enteros; mariscos","ru":"Готовые к употреблению продукты; птица; фарш; цельная говядина и свинина; морепродукты","tr":"Yemeye hazır gıda; kümes hayvanı; kıyma et; bütün sığır ve domuz; deniz ürünleri","hi":"खाने के लिए तैयार भोजन; पोल्ट्री; कीमा मांस; साबुत बीफ और पोर्क; सीफूड","ar":"الطعام الجاهز للأكل؛ الدواجن؛ اللحم المفروم؛ اللحم البقري ولحم الخنزير الكاملان؛ المأكولات البحرية"},{"en":"Seafood; ready-to-eat food; whole beef and pork; ground meat; poultry","es":"Mariscos; alimentos listos para comer; res y cerdo enteros; carne molida; aves","ru":"Морепродукты; готовые к употреблению продукты; цельная говядина и свинина; фарш; птица","tr":"Deniz ürünleri; yemeye hazır gıda; bütün sığır ve domuz; kıyma et; kümes hayvanı","hi":"सीफूड; खाने के लिए तैयार भोजन; साबुत बीफ और पोर्क; कीमा मांस; पोल्ट्री","ar":"المأكولات البحرية؛ الطعام الجاهز للأكل؛ اللحم البقري ولحم الخنزير الكاملان؛ اللحم المفروم؛ الدواجن"}],"e":{"en":"Foods are stacked by minimum cooking temperature: ready-to-eat on top, then seafood (145°F), whole cuts of beef/pork (145°F), ground meat (155°F), and poultry (165°F) on the bottom.","es":"Los alimentos se apilan según la temperatura mínima de cocción: los listos para comer arriba, luego los mariscos (145°F), los cortes enteros de res/cerdo (145°F), la carne molida (155°F) y las aves (165°F) en la parte inferior.","ru":"Продукты складываются по минимальной температуре приготовления: готовые к употреблению наверху, затем морепродукты (145°F), цельные куски говядины/свинины (145°F), фарш (155°F) и птица (165°F) внизу.","tr":"Gıdalar minimum pişirme sıcaklığına göre istiflenir: en üstte yemeye hazır gıda, ardından deniz ürünleri (145°F), bütün parça sığır/domuz (145°F), kıyma et (155°F) ve en altta kümes hayvanı (165°F).","hi":"भोजन को न्यूनतम खाना पकाने के तापमान के अनुसार रखा जाता है: खाने के लिए तैयार सबसे ऊपर, फिर सीफूड (145°F), बीफ/पोर्क के साबुत टुकड़े (145°F), कीमा मांस (155°F), और पोल्ट्री (165°F) सबसे नीचे।","ar":"تُرتَّب الأطعمة حسب الحد الأدنى لدرجة حرارة الطهي: الطعام الجاهز للأكل في الأعلى، ثم المأكولات البحرية (145°F)، فالقطع الكاملة من اللحم البقري/الخنزير (145°F)، فاللحم المفروم (155°F)، والدواجن (165°F) في الأسفل."}},{"cat":"crosscontam","a":0,"q":{"en":"A cook uses the same cutting board for raw chicken and then for slicing fresh tomatoes without any steps in between. What did the cook fail to do?","es":"Un cocinero usa la misma tabla de cortar para pollo crudo y luego para rebanar tomates frescos sin ningún paso intermedio. ¿Qué dejó de hacer el cocinero?","ru":"Повар использует одну и ту же разделочную доску для сырой курицы, а затем для нарезки свежих помидоров без каких-либо действий между этими операциями. Что повар не сделал?","tr":"Bir aşçı, aynı kesme tahtasını önce çiğ tavuk için kullanır ve ardından arada hiçbir adım atmadan taze domates dilimlemek için kullanır. Aşçı neyi yapmayı ihmal etmiştir?","hi":"एक रसोइया कच्चे चिकन के लिए और फिर बीच में कोई कदम उठाए बिना ताज़े टमाटर काटने के लिए एक ही कटिंग बोर्ड का उपयोग करता है। रसोइया क्या करने में विफल रहा?","ar":"يستخدم طاهٍ لوح التقطيع نفسه للدجاج النيء ثم لتقطيع طماطم طازجة دون أي خطوات بينهما. ماذا أغفل الطاهي فعله؟"},"o":[{"en":"Wash, rinse, and sanitize the cutting board between tasks","es":"Lavar, enjuagar y desinfectar la tabla de cortar entre tareas","ru":"Не вымыл, не ополоснул и не продезинфицировал разделочную доску между операциями","tr":"Görevler arasında kesme tahtasını yıkamayı, durulamayı ve sanitize etmeyi","hi":"कार्यों के बीच कटिंग बोर्ड को धोना, खंगालना, और सैनिटाइज़ करना","ar":"غسل لوح التقطيع وشطفه وتطهيره بين المهمتين"},{"en":"Wear gloves while cutting the tomatoes","es":"Usar guantes mientras cortaba los tomates","ru":"Не надел перчатки во время нарезки помидоров","tr":"Domatesleri keserken eldiven giymeyi","hi":"टमाटर काटते समय दस्ताने पहनना","ar":"ارتداء قفازات أثناء تقطيع الطماطم"},{"en":"Chill the tomatoes before cutting them","es":"Enfriar los tomates antes de cortarlos","ru":"Не охладил помидоры перед нарезкой","tr":"Domatesleri kesmeden önce soğutmayı","hi":"टमाटर काटने से पहले उन्हें ठंडा करना","ar":"تبريد الطماطم قبل تقطيعها"},{"en":"Use a sharper knife for the tomatoes","es":"Usar un cuchillo más afilado para los tomates","ru":"Не использовал более острый нож для помидоров","tr":"Domatesler için daha keskin bir bıçak kullanmayı","hi":"टमाटर के लिए एक तेज़ चाकू का उपयोग करना","ar":"استخدام سكين أحدّ للطماطم"}],"e":{"en":"Equipment and surfaces must be cleaned and sanitized between handling raw animal foods and ready-to-eat foods to prevent cross-contamination.","es":"El equipo y las superficies deben limpiarse y desinfectarse entre la manipulación de alimentos de origen animal crudos y los alimentos listos para comer para evitar la contaminación cruzada.","ru":"Оборудование и поверхности должны быть очищены и продезинфицированы между работой с сырыми продуктами животного происхождения и готовыми к употреблению продуктами, чтобы предотвратить перекрёстное загрязнение.","tr":"Çapraz bulaşmayı önlemek için ekipman ve yüzeyler, çiğ hayvansal gıdaları ve yemeye hazır gıdaları işleme arasında temizlenip sanitize edilmelidir.","hi":"क्रॉस-कॉन्टैमिनेशन रोकने के लिए कच्चे पशु भोजन और खाने के लिए तैयार भोजन को संभालने के बीच उपकरणों और सतहों को साफ और सैनिटाइज़ किया जाना चाहिए।","ar":"يجب تنظيف المعدات والأسطح وتطهيرها بين التعامل مع الأطعمة الحيوانية النيئة والأطعمة الجاهزة للأكل لمنع التلوث المتبادل."}},{"cat":"crosscontam","a":3,"q":{"en":"Why do many kitchens use color-coded cutting boards (for example, red, green, and yellow)?","es":"¿Por qué muchas cocinas usan tablas de cortar codificadas por colores (por ejemplo, roja, verde y amarilla)?","ru":"Почему многие кухни используют разделочные доски с цветовой маркировкой (например, красные, зелёные и жёлтые)?","tr":"Birçok mutfak neden renk kodlu kesme tahtaları (örneğin kırmızı, yeşil ve sarı) kullanır?","hi":"कई रसोई रंग-कोडित कटिंग बोर्ड (उदाहरण के लिए, लाल, हरा, और पीला) का उपयोग क्यों करती हैं?","ar":"لماذا تستخدم العديد من المطابخ ألواح تقطيع مرمَّزة بالألوان (مثل الأحمر والأخضر والأصفر)؟"},"o":[{"en":"To make the kitchen look more organized for inspectors","es":"Para que la cocina se vea más organizada ante los inspectores","ru":"Чтобы кухня выглядела более организованной для инспекторов","tr":"Mutfağı denetçilere daha düzenli göstermek için","hi":"रसोई को निरीक्षकों के लिए अधिक व्यवस्थित दिखाने के लिए","ar":"لجعل المطبخ يبدو أكثر تنظيماً أمام المفتشين"},{"en":"To match boards to specific chefs on the line","es":"Para asignar las tablas a chefs específicos en la línea","ru":"Чтобы закрепить доски за конкретными поварами на линии","tr":"Tahtaları hattaki belirli aşçılarla eşleştirmek için","hi":"लाइन पर विशिष्ट शेफ से बोर्ड का मिलान करने के लिए","ar":"لمطابقة الألواح مع طهاة محددين على خط العمل"},{"en":"To indicate which boards have been sanitized most recently","es":"Para indicar qué tablas se han desinfectado más recientemente","ru":"Чтобы указать, какие доски были продезинфицированы последними","tr":"Hangi tahtaların en son sanitize edildiğini göstermek için","hi":"यह इंगित करने के लिए कि किन बोर्डों को सबसे हाल ही में सैनिटाइज़ किया गया है","ar":"للإشارة إلى الألواح التي تم تطهيرها مؤخراً"},{"en":"To dedicate specific boards to specific food types and reduce cross-contamination","es":"Para dedicar tablas específicas a tipos de alimentos específicos y reducir la contaminación cruzada","ru":"Чтобы выделить определённые доски для определённых видов продуктов и снизить перекрёстное загрязнение","tr":"Belirli tahtaları belirli gıda türlerine ayırmak ve çapraz bulaşmayı azaltmak için","hi":"विशिष्ट बोर्डों को विशिष्ट भोजन प्रकारों के लिए समर्पित करने और क्रॉस-कॉन्टैमिनेशन कम करने के लिए","ar":"لتخصيص ألواح محددة لأنواع طعام محددة وتقليل التلوث المتبادل"}],"e":{"en":"Color-coding assigns boards to particular food categories (such as raw poultry or produce) so the same surface is not used across food types that could cross-contaminate.","es":"La codificación por colores asigna las tablas a categorías de alimentos específicas (como aves crudas o productos agrícolas) para que la misma superficie no se use entre tipos de alimentos que podrían contaminarse de forma cruzada.","ru":"Цветовая маркировка закрепляет доски за конкретными категориями продуктов (такими как сырая птица или овощи), чтобы одна и та же поверхность не использовалась для разных видов продуктов, которые могли бы вызвать перекрёстное загрязнение.","tr":"Renk kodlaması, tahtaları belirli gıda kategorilerine (çiğ kümes hayvanı veya sebze gibi) atar, böylece aynı yüzey çapraz bulaşmaya yol açabilecek gıda türleri arasında kullanılmaz.","hi":"रंग-कोडिंग बोर्डों को विशेष भोजन श्रेणियों (जैसे कच्ची पोल्ट्री या उपज) को सौंपती है ताकि एक ही सतह का उपयोग उन भोजन प्रकारों में न किया जाए जो क्रॉस-कॉन्टैमिनेट कर सकते हैं।","ar":"يخصص الترميز اللوني الألواحَ لفئات طعام معينة (كالدواجن النيئة أو المنتجات الطازجة) بحيث لا يُستخدم السطح نفسه عبر أنواع طعام قد تتسبب في التلوث المتبادل."}},{"cat":"crosscontam","a":0,"q":{"en":"Which list correctly names all nine major food allergens (the \"Big 9\") recognized in the United States?","es":"¿Qué lista nombra correctamente los nueve principales alérgenos alimentarios (los \"9 grandes\" / Big 9) reconocidos en los Estados Unidos?","ru":"В каком списке правильно названы все девять основных пищевых аллергенов («Большая девятка», Big 9), признанных в Соединённых Штатах?","tr":"Hangi liste, Amerika Birleşik Devletleri'nde tanınan dokuz büyük gıda alerjeninin (\"Büyük 9\") tamamını doğru şekilde adlandırır?","hi":"कौन सी सूची संयुक्त राज्य अमेरिका में मान्यता प्राप्त सभी नौ प्रमुख खाद्य एलर्जन (\"Big 9\") को सही ढंग से नाम देती है?","ar":"أيُّ قائمة تُسمّي بشكل صحيح جميع مسببات الحساسية الغذائية الرئيسية التسعة (\"التسعة الكبار\" Big 9) المُعتَرَف بها في الولايات المتحدة؟"},"o":[{"en":"Milk, eggs, fish, crustacean shellfish, tree nuts, peanuts, wheat, soybeans, sesame","es":"Leche, huevos, pescado, mariscos crustáceos, frutos secos de árbol, maní (cacahuates), trigo, soya, sésamo (ajonjolí)","ru":"Молоко, яйца, рыба, ракообразные, древесные орехи, арахис, пшеница, соя, кунжут","tr":"Süt, yumurta, balık, kabuklu deniz hayvanları (crustacean), ağaç kuruyemişleri, yer fıstığı, buğday, soya fasulyesi, susam","hi":"दूध, अंडे, मछली, क्रस्टेशियन शेलफिश, ट्री नट्स, मूंगफली, गेहूं, सोयाबीन, तिल","ar":"الحليب، البيض، السمك، القشريات، المكسرات الشجرية، الفول السوداني، القمح، فول الصويا، السمسم"},{"en":"Milk, eggs, fish, crustacean shellfish, tree nuts, peanuts, wheat, soybeans, corn","es":"Leche, huevos, pescado, mariscos crustáceos, frutos secos de árbol, maní (cacahuates), trigo, soya, maíz","ru":"Молоко, яйца, рыба, ракообразные, древесные орехи, арахис, пшеница, соя, кукуруза","tr":"Süt, yumurta, balık, kabuklu deniz hayvanları (crustacean), ağaç kuruyemişleri, yer fıstığı, buğday, soya fasulyesi, mısır","hi":"दूध, अंडे, मछली, क्रस्टेशियन शेलफिश, ट्री नट्स, मूंगफली, गेहूं, सोयाबीन, मक्का","ar":"الحليب، البيض، السمك، القشريات، المكسرات الشجرية، الفول السوداني، القمح، فول الصويا، الذرة"},{"en":"Milk, eggs, fish, mollusk shellfish, tree nuts, peanuts, wheat, soybeans, sesame","es":"Leche, huevos, pescado, mariscos moluscos, frutos secos de árbol, maní (cacahuates), trigo, soya, sésamo (ajonjolí)","ru":"Молоко, яйца, рыба, моллюски, древесные орехи, арахис, пшеница, соя, кунжут","tr":"Süt, yumurta, balık, yumuşakça deniz hayvanları (mollusk), ağaç kuruyemişleri, yer fıstığı, buğday, soya fasulyesi, susam","hi":"दूध, अंडे, मछली, मोलस्क शेलफिश, ट्री नट्स, मूंगफली, गेहूं, सोयाबीन, तिल","ar":"الحليب، البيض، السمك، الرخويات، المكسرات الشجرية، الفول السوداني، القمح، فول الصويا، السمسم"},{"en":"Milk, eggs, fish, crustacean shellfish, tree nuts, peanuts, gluten, soybeans, sesame","es":"Leche, huevos, pescado, mariscos crustáceos, frutos secos de árbol, maní (cacahuates), gluten, soya, sésamo (ajonjolí)","ru":"Молоко, яйца, рыба, ракообразные, древесные орехи, арахис, глютен, соя, кунжут","tr":"Süt, yumurta, balık, kabuklu deniz hayvanları (crustacean), ağaç kuruyemişleri, yer fıstığı, glüten, soya fasulyesi, susam","hi":"दूध, अंडे, मछली, क्रस्टेशियन शेलफिश, ट्री नट्स, मूंगफली, ग्लूटेन, सोयाबीन, तिल","ar":"الحليب، البيض، السمك، القشريات، المكسرات الشجرية، الفول السوداني، الغلوتين، فول الصويا، السمسم"}],"e":{"en":"The Big 9 are milk, eggs, fish, crustacean shellfish, tree nuts, peanuts, wheat, soybeans, and sesame; sesame became the ninth major allergen effective January 1, 2023.","es":"Los 9 grandes (Big 9) son leche, huevos, pescado, mariscos crustáceos, frutos secos de árbol, maní (cacahuates), trigo, soya y sésamo (ajonjolí); el sésamo se convirtió en el noveno alérgeno principal a partir del 1 de enero de 2023.","ru":"«Большая девятка» (Big 9) — это молоко, яйца, рыба, ракообразные, древесные орехи, арахис, пшеница, соя и кунжут; кунжут стал девятым основным аллергеном с 1 января 2023 года.","tr":"Büyük 9; süt, yumurta, balık, kabuklu deniz hayvanları (crustacean), ağaç kuruyemişleri, yer fıstığı, buğday, soya fasulyesi ve susamdır; susam, 1 Ocak 2023 itibarıyla dokuzuncu büyük alerjen olmuştur.","hi":"Big 9 हैं दूध, अंडे, मछली, क्रस्टेशियन शेलफिश, ट्री नट्स, मूंगफली, गेहूं, सोयाबीन, और तिल; तिल 1 जनवरी 2023 से प्रभावी नौवां प्रमुख एलर्जन बन गया।","ar":"التسعة الكبار (Big 9) هي: الحليب، والبيض، والسمك، والقشريات، والمكسرات الشجرية، والفول السوداني، والقمح، وفول الصويا، والسمسم؛ وقد أصبح السمسم مسبب الحساسية الرئيسي التاسع اعتباراً من January 1, 2023."}},{"cat":"crosscontam","a":2,"q":{"en":"Which food was added as the ninth major food allergen in the United States, effective January 1, 2023?","es":"¿Qué alimento se agregó como el noveno alérgeno alimentario principal en los Estados Unidos, a partir del 1 de enero de 2023?","ru":"Какой продукт был добавлен как девятый основной пищевой аллерген в Соединённых Штатах, вступивший в силу с 1 января 2023 года?","tr":"Amerika Birleşik Devletleri'nde 1 Ocak 2023 itibarıyla dokuzuncu büyük gıda alerjeni olarak eklenen gıda hangisidir?","hi":"1 जनवरी 2023 से प्रभावी, संयुक्त राज्य अमेरिका में नौवें प्रमुख खाद्य एलर्जन के रूप में कौन सा भोजन जोड़ा गया?","ar":"أيُّ طعام أُضيف بوصفه مسبب الحساسية الغذائية الرئيسي التاسع في الولايات المتحدة، اعتباراً من January 1, 2023؟"},"o":[{"en":"Corn","es":"Maíz","ru":"Кукуруза","tr":"Mısır","hi":"मक्का","ar":"الذرة"},{"en":"Mustard","es":"Mostaza","ru":"Горчица","tr":"Hardal","hi":"सरसों","ar":"الخردل"},{"en":"Sesame","es":"Sésamo (ajonjolí)","ru":"Кунжут","tr":"Susam","hi":"तिल","ar":"السمسم"},{"en":"Celery","es":"Apio","ru":"Сельдерей","tr":"Kereviz","hi":"अजवाइन (सेलरी)","ar":"الكرفس"}],"e":{"en":"Under the FASTER Act, sesame became the ninth major food allergen requiring declaration, effective January 1, 2023.","es":"Bajo la Ley FASTER (FASTER Act), el sésamo (ajonjolí) se convirtió en el noveno alérgeno alimentario principal que requiere declaración, a partir del 1 de enero de 2023.","ru":"Согласно Закону FASTER Act, кунжут стал девятым основным пищевым аллергеном, требующим декларирования, вступившим в силу с 1 января 2023 года.","tr":"FASTER Yasası uyarınca susam, 1 Ocak 2023 itibarıyla beyan edilmesi gereken dokuzuncu büyük gıda alerjeni olmuştur.","hi":"FASTER अधिनियम के तहत, तिल 1 जनवरी 2023 से प्रभावी, घोषणा की आवश्यकता वाला नौवां प्रमुख खाद्य एलर्जन बन गया।","ar":"بموجب قانون FASTER، أصبح السمسم مسبب الحساسية الغذائية الرئيسي التاسع الواجب الإعلان عنه، اعتباراً من January 1, 2023."}},{"cat":"crosscontam","a":1,"q":{"en":"What is allergen cross-contact?","es":"¿Qué es el contacto cruzado con alérgenos?","ru":"Что такое перекрёстный контакт с аллергеном?","tr":"Alerjen çapraz teması nedir?","hi":"एलर्जेन क्रॉस-कॉन्टैक्ट क्या है?","ar":"ما هو التلامس المتبادل لمسببات الحساسية؟"},"o":[{"en":"When an allergen is intentionally added to a recipe as an ingredient","es":"Cuando un alérgeno se agrega intencionalmente a una receta como ingrediente","ru":"Когда аллерген намеренно добавляется в рецепт в качестве ингредиента","tr":"Bir alerjenin tarife bilerek bir malzeme olarak eklenmesi","hi":"जब किसी एलर्जेन को जानबूझकर एक सामग्री के रूप में रेसिपी में मिलाया जाता है","ar":"عندما يُضاف أحد مسببات الحساسية عمداً إلى وصفة كأحد المكونات"},{"en":"When an allergen unintentionally transfers from a food containing it to a food that does not","es":"Cuando un alérgeno se transfiere de forma no intencional de un alimento que lo contiene a un alimento que no lo contiene","ru":"Когда аллерген непреднамеренно переносится из продукта, содержащего его, в продукт, который его не содержит","tr":"Bir alerjenin, onu içeren bir gıdadan içermeyen bir gıdaya istemeden geçmesi","hi":"जब कोई एलर्जेन अनजाने में उसे रखने वाले भोजन से ऐसे भोजन में स्थानांतरित हो जाता है जिसमें वह नहीं होता","ar":"عندما ينتقل أحد مسببات الحساسية بشكل غير مقصود من طعام يحتوي عليه إلى طعام لا يحتوي عليه"},{"en":"When a guest is allergic to more than one food at the same time","es":"Cuando un comensal es alérgico a más de un alimento al mismo tiempo","ru":"Когда у гостя одновременно аллергия более чем на один продукт","tr":"Bir misafirin aynı anda birden fazla gıdaya alerjisinin olması","hi":"जब किसी मेहमान को एक ही समय में एक से अधिक भोजन से एलर्जी होती है","ar":"عندما يكون لدى الضيف حساسية تجاه أكثر من طعام واحد في الوقت نفسه"},{"en":"When two allergens chemically react inside a cooked dish","es":"Cuando dos alérgenos reaccionan químicamente dentro de un platillo cocinado","ru":"Когда два аллергена химически реагируют внутри приготовленного блюда","tr":"İki alerjenin pişmiş bir yemeğin içinde kimyasal olarak tepkimeye girmesi","hi":"जब पके हुए व्यंजन के अंदर दो एलर्जेन रासायनिक रूप से प्रतिक्रिया करते हैं","ar":"عندما يتفاعل مسبّبان للحساسية كيميائياً داخل طبق مطبوخ"}],"e":{"en":"Allergen cross-contact occurs when an allergen is unintentionally transferred to a food that is supposed to be free of that allergen, which can trigger a serious reaction.","es":"El contacto cruzado con alérgenos ocurre cuando un alérgeno se transfiere de forma no intencional a un alimento que se supone debe estar libre de ese alérgeno, lo que puede desencadenar una reacción grave.","ru":"Перекрёстный контакт с аллергеном происходит, когда аллерген непреднамеренно переносится в продукт, который должен быть свободен от этого аллергена, что может вызвать серьёзную реакцию.","tr":"Alerjen çapraz teması, bir alerjenin o alerjeni içermemesi gereken bir gıdaya istemeden geçmesiyle oluşur ve bu durum ciddi bir reaksiyonu tetikleyebilir.","hi":"एलर्जेन क्रॉस-कॉन्टैक्ट तब होता है जब कोई एलर्जेन अनजाने में ऐसे भोजन में स्थानांतरित हो जाता है जिसमें वह एलर्जेन नहीं होना चाहिए, जो एक गंभीर प्रतिक्रिया को ट्रिगर कर सकता है।","ar":"يحدث التلامس المتبادل لمسببات الحساسية عندما ينتقل أحد مسببات الحساسية بشكل غير مقصود إلى طعام يُفترض أن يكون خالياً من ذلك المسبّب، وهو ما قد يُحدث رد فعل تحسسياً خطيراً."}},{"cat":"crosscontam","a":2,"q":{"en":"A guest with a shrimp allergy is served a salad, then notices it contains shrimp. What is the correct response?","es":"A un comensal con alergia al camarón se le sirve una ensalada y luego nota que contiene camarón. ¿Cuál es la respuesta correcta?","ru":"Гостю с аллергией на креветки подали салат, после чего он замечает, что в нём есть креветки. Каким должен быть правильный ответ?","tr":"Karides alerjisi olan bir misafire salata servis ediliyor, ardından misafir salatada karides olduğunu fark ediyor. Doğru tepki nedir?","hi":"झींगा (shrimp) से एलर्जी वाले एक मेहमान को सलाद परोसा जाता है, फिर वह देखता है कि उसमें झींगा है। सही प्रतिक्रिया क्या है?","ar":"يُقدَّم سلطة لضيف لديه حساسية من الجمبري، ثم يلاحظ أنها تحتوي على جمبري. ما هو الإجراء الصحيح؟"},"o":[{"en":"Pick the shrimp off the salad and return the same plate to the guest","es":"Quitar el camarón de la ensalada y devolver el mismo plato al comensal","ru":"Снять креветки с салата и вернуть гостю ту же тарелку","tr":"Karidesleri salatadan ayıklayıp aynı tabağı misafire geri vermek","hi":"सलाद से झींगा निकाल दें और वही प्लेट मेहमान को वापस कर दें","ar":"انتزاع الجمبري من السلطة وإعادة الطبق نفسه إلى الضيف"},{"en":"Add extra dressing to mask any remaining shrimp residue","es":"Agregar más aderezo para enmascarar cualquier residuo de camarón que quede","ru":"Добавить дополнительную заправку, чтобы скрыть оставшиеся следы креветок","tr":"Kalan karides kalıntısını gizlemek için fazladan sos eklemek","hi":"बचे हुए झींगा के अवशेष को छिपाने के लिए अतिरिक्त ड्रेसिंग मिला दें","ar":"إضافة مزيد من الصلصة لإخفاء أي بقايا جمبري متبقية"},{"en":"Prepare a completely new salad with clean utensils and a clean surface","es":"Preparar una ensalada completamente nueva con utensilios limpios y una superficie limpia","ru":"Приготовить совершенно новый салат, используя чистую посуду и чистую поверхность","tr":"Temiz mutfak aletleri ve temiz bir yüzeyle tamamen yeni bir salata hazırlamak","hi":"साफ बर्तनों और साफ सतह के साथ पूरी तरह से एक नया सलाद तैयार करें","ar":"تحضير سلطة جديدة تماماً باستخدام أدوات نظيفة وسطح نظيف"},{"en":"Rinse the shrimp off and re-plate the salad","es":"Enjuagar el camarón y volver a emplatar la ensalada","ru":"Смыть креветки и заново выложить салат на тарелку","tr":"Karidesleri durulayıp salatayı yeniden tabağa koymak","hi":"झींगा को धोकर निकाल दें और सलाद को फिर से प्लेट करें","ar":"شطف الجمبري من السلطة وإعادة تقديمها في الطبق"}],"e":{"en":"Simply removing an allergen from a finished dish does not make it safe, because allergen residue remains; a fresh dish must be made with clean equipment.","es":"Simplemente retirar un alérgeno de un platillo terminado no lo hace seguro, porque queda residuo del alérgeno; se debe preparar un platillo nuevo con equipo limpio.","ru":"Простое удаление аллергена из готового блюда не делает его безопасным, поскольку остаются следы аллергена; необходимо приготовить свежее блюдо с использованием чистого оборудования.","tr":"Bir alerjeni bitmiş bir yemekten sadece çıkarmak onu güvenli hale getirmez, çünkü alerjen kalıntısı kalır; temiz ekipmanla yeni bir yemek yapılmalıdır.","hi":"किसी तैयार व्यंजन से एलर्जेन को केवल हटा देने से वह सुरक्षित नहीं हो जाता, क्योंकि एलर्जेन का अवशेष बना रहता है; साफ उपकरण के साथ एक ताज़ा व्यंजन बनाना चाहिए।","ar":"مجرد إزالة مسبب الحساسية من طبق جاهز لا يجعله آمناً، لأن بقايا المسبب تظل موجودة؛ يجب تحضير طبق جديد باستخدام معدات نظيفة."}},{"cat":"crosscontam","a":0,"q":{"en":"Which practice best helps prevent allergen cross-contact when preparing a meal for a guest with a food allergy?","es":"¿Cuál práctica ayuda mejor a prevenir el contacto cruzado con alérgenos al preparar una comida para un comensal con alergia alimentaria?","ru":"Какая практика лучше всего помогает предотвратить перекрёстный контакт с аллергеном при приготовлении блюда для гостя с пищевой аллергией?","tr":"Gıda alerjisi olan bir misafire yemek hazırlarken alerjen çapraz temasını önlemeye en çok hangi uygulama yardımcı olur?","hi":"किसी खाद्य एलर्जी वाले मेहमान के लिए भोजन तैयार करते समय एलर्जेन क्रॉस-कॉन्टैक्ट को रोकने में कौन सी प्रथा सबसे अधिक मदद करती है?","ar":"أي ممارسة تساعد بشكل أفضل على منع التلامس المتبادل لمسببات الحساسية عند تحضير وجبة لضيف لديه حساسية غذائية؟"},"o":[{"en":"Use freshly cleaned and sanitized equipment and separate, dedicated utensils","es":"Usar equipo recién limpiado y desinfectado, y utensilios separados y exclusivos","ru":"Использовать свежевымытое и продезинфицированное оборудование и отдельную, выделенную посуду","tr":"Yeni temizlenmiş ve dezenfekte edilmiş ekipman ile ayrı, özel mutfak aletleri kullanmak","hi":"ताज़ा साफ किए और सैनिटाइज़ किए गए उपकरण तथा अलग, समर्पित बर्तनों का उपयोग करें","ar":"استخدام معدات نظيفة ومطهَّرة حديثاً وأدوات منفصلة ومخصّصة"},{"en":"Cook the allergen-free meal at a slightly higher temperature","es":"Cocinar la comida libre de alérgenos a una temperatura ligeramente más alta","ru":"Готовить блюдо без аллергена при немного более высокой температуре","tr":"Alerjensiz yemeği biraz daha yüksek sıcaklıkta pişirmek","hi":"एलर्जेन-मुक्त भोजन को थोड़े अधिक तापमान पर पकाएं","ar":"طهي الوجبة الخالية من مسبب الحساسية عند درجة حرارة أعلى قليلاً"},{"en":"Prepare the meal last, after all other orders, on the same surfaces","es":"Preparar la comida al final, después de todos los demás pedidos, en las mismas superficies","ru":"Готовить блюдо последним, после всех остальных заказов, на тех же поверхностях","tr":"Yemeği diğer tüm siparişlerden sonra, en son, aynı yüzeylerde hazırlamak","hi":"भोजन को सबसे आखिर में, सभी अन्य ऑर्डर के बाद, उन्हीं सतहों पर तैयार करें","ar":"تحضير الوجبة في النهاية، بعد جميع الطلبات الأخرى، على الأسطح نفسها"},{"en":"Use the same fryer oil but a new basket","es":"Usar el mismo aceite de la freidora pero una canasta nueva","ru":"Использовать то же масло для фритюра, но новую корзину","tr":"Aynı kızartma yağını ama yeni bir sepet kullanmak","hi":"उसी फ्रायर के तेल का उपयोग करें लेकिन एक नई टोकरी का","ar":"استخدام زيت القلي نفسه لكن مع سلة جديدة"}],"e":{"en":"Cleaning and sanitizing equipment and using separate utensils prevents allergen residue from transferring; shared fryer oil and shared surfaces can still carry allergens.","es":"Limpiar y desinfectar el equipo y usar utensilios separados evita que el residuo del alérgeno se transfiera; el aceite de freidora compartido y las superficies compartidas todavía pueden contener alérgenos.","ru":"Очистка и дезинфекция оборудования, а также использование отдельной посуды предотвращают перенос следов аллергена; общее масло для фритюра и общие поверхности всё равно могут содержать аллергены.","tr":"Ekipmanı temizleyip dezenfekte etmek ve ayrı mutfak aletleri kullanmak alerjen kalıntısının geçmesini önler; ortak kızartma yağı ve ortak yüzeyler hâlâ alerjen taşıyabilir.","hi":"उपकरण को साफ और सैनिटाइज़ करना तथा अलग बर्तनों का उपयोग करना एलर्जेन अवशेष को स्थानांतरित होने से रोकता है; साझा फ्रायर तेल और साझा सतहें फिर भी एलर्जेन ले जा सकती हैं।","ar":"يمنع تنظيف المعدات وتطهيرها واستخدام أدوات منفصلة انتقال بقايا مسبب الحساسية؛ أما زيت القلي المشترك والأسطح المشتركة فقد تظل تحمل مسببات الحساسية."}},{"cat":"crosscontam","a":2,"q":{"en":"Why is clear communication with the guest and kitchen important when handling a food allergy order?","es":"¿Por qué es importante la comunicación clara con el comensal y la cocina al manejar un pedido con alergia alimentaria?","ru":"Почему чёткое общение с гостем и кухней важно при обработке заказа с учётом пищевой аллергии?","tr":"Bir gıda alerjisi siparişini ele alırken misafir ve mutfakla net iletişim neden önemlidir?","hi":"खाद्य एलर्जी वाले ऑर्डर को संभालते समय मेहमान और रसोई के साथ स्पष्ट संवाद क्यों महत्वपूर्ण है?","ar":"لماذا يُعد التواصل الواضح مع الضيف والمطبخ أمراً مهماً عند التعامل مع طلب يتعلق بحساسية غذائية؟"},"o":[{"en":"It allows the kitchen to charge extra for the special order","es":"Permite que la cocina cobre extra por el pedido especial","ru":"Это позволяет кухне взимать дополнительную плату за специальный заказ","tr":"Mutfağın özel sipariş için ekstra ücret almasını sağlar","hi":"यह रसोई को विशेष ऑर्डर के लिए अतिरिक्त शुल्क लेने की अनुमति देता है","ar":"لأنه يتيح للمطبخ فرض رسوم إضافية على الطلب الخاص"},{"en":"It speeds up ticket times during a rush","es":"Acelera los tiempos de los pedidos durante una hora pico","ru":"Это ускоряет время обработки заказов в час пик","tr":"Yoğunluk sırasında sipariş sürelerini hızlandırır","hi":"यह व्यस्त समय के दौरान टिकट का समय तेज़ कर देता है","ar":"لأنه يسرّع أوقات الطلبات أثناء الازدحام"},{"en":"It ensures the allergen is correctly identified and avoided throughout preparation and service","es":"Garantiza que el alérgeno se identifique correctamente y se evite durante toda la preparación y el servicio","ru":"Это гарантирует, что аллерген будет правильно определён и исключён на всех этапах приготовления и подачи","tr":"Alerjenin doğru şekilde tespit edilip hazırlık ve servis boyunca önlenmesini sağlar","hi":"यह सुनिश्चित करता है कि एलर्जेन की सही पहचान हो और तैयारी तथा सर्विस के दौरान उससे बचा जाए","ar":"لأنه يضمن تحديد مسبب الحساسية بشكل صحيح وتجنّبه طوال التحضير والتقديم"},{"en":"It is only necessary when the restaurant serves alcohol","es":"Solo es necesaria cuando el restaurante sirve alcohol","ru":"Это необходимо только тогда, когда в ресторане подают алкоголь","tr":"Yalnızca restoran alkol servis ettiğinde gereklidir","hi":"यह केवल तभी आवश्यक है जब रेस्तरां शराब परोसता है","ar":"لأنه ضروري فقط عندما يقدّم المطعم الكحول"}],"e":{"en":"Accurate communication between the guest, server, and kitchen ensures everyone knows the allergen so it is identified and kept out of the meal at every step.","es":"La comunicación precisa entre el comensal, el mesero y la cocina garantiza que todos conozcan el alérgeno para que se identifique y se mantenga fuera de la comida en cada paso.","ru":"Точное общение между гостем, официантом и кухней гарантирует, что все знают об аллергене, поэтому он определяется и не попадает в блюдо на каждом этапе.","tr":"Misafir, garson ve mutfak arasındaki doğru iletişim, herkesin alerjeni bilmesini, böylece her aşamada tespit edilip yemeğin dışında tutulmasını sağlar.","hi":"मेहमान, सर्वर और रसोई के बीच सटीक संवाद यह सुनिश्चित करता है कि सभी को एलर्जेन के बारे में पता हो ताकि हर चरण पर इसकी पहचान की जाए और इसे भोजन से बाहर रखा जाए।","ar":"يضمن التواصل الدقيق بين الضيف والنادل والمطبخ معرفة الجميع بمسبب الحساسية بحيث يتم تحديده وإبقاؤه خارج الوجبة في كل خطوة."}},{"cat":"crosscontam","a":1,"q":{"en":"Which of the following is an example of PHYSICAL contamination?","es":"¿Cuál de los siguientes es un ejemplo de contaminación FÍSICA?","ru":"Что из перечисленного является примером ФИЗИЧЕСКОГО загрязнения?","tr":"Aşağıdakilerden hangisi FİZİKSEL bulaşmaya bir örnektir?","hi":"निम्नलिखित में से कौन सा भौतिक (PHYSICAL) संदूषण का उदाहरण है?","ar":"أي مما يلي يُعد مثالاً على التلوث الفيزيائي؟"},"o":[{"en":"Salmonella bacteria on raw chicken","es":"Bacterias de Salmonella en pollo crudo","ru":"Бактерии сальмонеллы на сырой курице","tr":"Çiğ tavuktaki Salmonella bakterisi","hi":"कच्चे चिकन पर साल्मोनेला (Salmonella) बैक्टीरिया","ar":"بكتيريا السالمونيلا على الدجاج النيء"},{"en":"A piece of broken glass or metal shaving in a dish","es":"Un trozo de vidrio roto o una viruta de metal en un platillo","ru":"Кусок битого стекла или металлической стружки в блюде","tr":"Bir yemekteki kırık cam parçası veya metal talaşı","hi":"किसी व्यंजन में टूटे हुए कांच का टुकड़ा या धातु की छीलन","ar":"قطعة زجاج مكسور أو رقاقة معدنية في طبق"},{"en":"Cleaning sanitizer sprayed onto food","es":"Desinfectante de limpieza rociado sobre la comida","ru":"Чистящее дезинфицирующее средство, распылённое на еду","tr":"Gıdaya püskürtülen temizlik dezenfektanı","hi":"भोजन पर छिड़का गया सफाई का सैनिटाइज़र","ar":"رشّ مطهِّر التنظيف على الطعام"},{"en":"A norovirus transferred by an ill employee","es":"Un norovirus transferido por un empleado enfermo","ru":"Норовирус, переданный больным сотрудником","tr":"Hasta bir çalışan tarafından geçirilen norovirüs","hi":"किसी बीमार कर्मचारी द्वारा स्थानांतरित नोरोवायरस (norovirus)","ar":"فيروس نوروفيروس ينتقل عن طريق موظف مريض"}],"e":{"en":"Physical contamination involves foreign objects such as glass, metal, bone fragments, or hair getting into food.","es":"La contaminación física implica objetos extraños como vidrio, metal, fragmentos de hueso o cabello que llegan a la comida.","ru":"Физическое загрязнение связано с попаданием в пищу посторонних предметов, таких как стекло, металл, осколки костей или волосы.","tr":"Fiziksel bulaşma, cam, metal, kemik parçaları veya saç gibi yabancı cisimlerin gıdaya karışmasını içerir.","hi":"भौतिक संदूषण में कांच, धातु, हड्डी के टुकड़े या बाल जैसी बाहरी वस्तुओं का भोजन में चले जाना शामिल है।","ar":"يتضمن التلوث الفيزيائي وجود أجسام غريبة مثل الزجاج أو المعدن أو شظايا العظم أو الشعر في الطعام."}},{"cat":"crosscontam","a":2,"q":{"en":"A bottle of degreaser is stored on a shelf directly above a pan of prepared coleslaw, and some drips into the food. This is an example of which type of contamination?","es":"Una botella de desengrasante se almacena en un estante directamente arriba de una bandeja de ensalada de col preparada, y algo gotea dentro de la comida. ¿Esto es un ejemplo de qué tipo de contaminación?","ru":"Бутылка обезжиривателя хранится на полке прямо над лотком с готовым салатом из капусты, и часть средства капает в еду. Это пример какого типа загрязнения?","tr":"Bir şişe yağ çözücü, hazırlanmış lahana salatası tavasının tam üstündeki rafa konuluyor ve bir miktarı gıdaya damlıyor. Bu hangi tür bulaşmaya örnektir?","hi":"डीग्रीज़र की एक बोतल तैयार कोलस्लॉ के पैन के ठीक ऊपर एक शेल्फ पर रखी है, और कुछ भोजन में टपक जाता है। यह किस प्रकार के संदूषण का उदाहरण है?","ar":"تُخزَّن زجاجة مزيل شحوم على رفّ مباشرة فوق صينية سلطة كرنب مُحضَّرة، وتتسرّب بعض منها إلى الطعام. هذا مثال على أي نوع من التلوث؟"},"o":[{"en":"Biological","es":"Biológica","ru":"Биологического","tr":"Biyolojik","hi":"जैविक","ar":"بيولوجي"},{"en":"Physical","es":"Física","ru":"Физического","tr":"Fiziksel","hi":"भौतिक","ar":"فيزيائي"},{"en":"Chemical","es":"Química","ru":"Химического","tr":"Kimyasal","hi":"रासायनिक","ar":"كيميائي"},{"en":"Allergenic","es":"Alérgena","ru":"Аллергенного","tr":"Alerjenik","hi":"एलर्जेनिक","ar":"تحسسي"}],"e":{"en":"Chemical contamination occurs when substances like cleaners, sanitizers, or pesticides get into food; chemicals must be stored below and away from food.","es":"La contaminación química ocurre cuando sustancias como limpiadores, desinfectantes o pesticidas llegan a la comida; los químicos deben almacenarse por debajo y lejos de los alimentos.","ru":"Химическое загрязнение происходит, когда в пищу попадают такие вещества, как чистящие средства, дезинфектанты или пестициды; химикаты следует хранить ниже еды и отдельно от неё.","tr":"Kimyasal bulaşma, temizleyiciler, dezenfektanlar veya böcek ilaçları gibi maddelerin gıdaya karışmasıyla oluşur; kimyasallar gıdanın altında ve uzağında saklanmalıdır.","hi":"रासायनिक संदूषण तब होता है जब क्लीनर, सैनिटाइज़र या कीटनाशक जैसे पदार्थ भोजन में चले जाते हैं; रसायनों को भोजन के नीचे और उससे दूर रखा जाना चाहिए।","ar":"يحدث التلوث الكيميائي عندما تدخل مواد مثل المنظفات أو المطهِّرات أو المبيدات إلى الطعام؛ يجب تخزين المواد الكيميائية أسفل الطعام وبعيداً عنه."}},{"cat":"crosscontam","a":2,"q":{"en":"Bacteria, viruses, parasites, and fungi that contaminate food are categorized as which type of hazard?","es":"Las bacterias, los virus, los parásitos y los hongos que contaminan los alimentos se clasifican como qué tipo de peligro?","ru":"Бактерии, вирусы, паразиты и грибки, загрязняющие пищу, относятся к какому типу опасности?","tr":"Gıdayı kirleten bakteriler, virüsler, parazitler ve mantarlar hangi tehlike türü olarak sınıflandırılır?","hi":"बैक्टीरिया, वायरस, परजीवी और कवक जो भोजन को संदूषित करते हैं, उन्हें किस प्रकार के खतरे के रूप में वर्गीकृत किया जाता है?","ar":"تُصنَّف البكتيريا والفيروسات والطفيليات والفطريات التي تلوّث الطعام ضمن أي نوع من المخاطر؟"},"o":[{"en":"Chemical","es":"Químico","ru":"Химической","tr":"Kimyasal","hi":"रासायनिक","ar":"كيميائي"},{"en":"Physical","es":"Físico","ru":"Физической","tr":"Fiziksel","hi":"भौतिक","ar":"فيزيائي"},{"en":"Biological","es":"Biológico","ru":"Биологической","tr":"Biyolojik","hi":"जैविक","ar":"بيولوجي"},{"en":"Environmental","es":"Ambiental","ru":"Экологической","tr":"Çevresel","hi":"पर्यावरणीय","ar":"بيئي"}],"e":{"en":"Biological hazards are living or organic contaminants such as bacteria, viruses, parasites, and fungi, and they are the most common cause of foodborne illness.","es":"Los peligros biológicos son contaminantes vivos u orgánicos como bacterias, virus, parásitos y hongos, y son la causa más común de enfermedades transmitidas por los alimentos.","ru":"Биологические опасности — это живые или органические загрязнители, такие как бактерии, вирусы, паразиты и грибки, и они являются наиболее частой причиной пищевых заболеваний.","tr":"Biyolojik tehlikeler bakteri, virüs, parazit ve mantar gibi canlı veya organik kirleticilerdir ve gıda kaynaklı hastalıkların en yaygın nedenidir.","hi":"जैविक खतरे जीवित या जैविक संदूषक होते हैं जैसे बैक्टीरिया, वायरस, परजीवी और कवक, और ये खाद्यजनित बीमारी का सबसे आम कारण हैं।","ar":"المخاطر البيولوجية هي ملوثات حية أو عضوية مثل البكتيريا والفيروسات والطفيليات والفطريات، وهي السبب الأكثر شيوعاً للأمراض المنقولة بالغذاء."}},{"cat":"crosscontam","a":1,"q":{"en":"An operation must store raw fish, raw ground pork, and a pan of cooked rice in one cooler with three shelves. Which arrangement is correct from top to bottom?","es":"Una operación debe almacenar pescado crudo, carne molida de cerdo cruda y una bandeja de arroz cocido en un refrigerador con tres estantes. ¿Cuál disposición es correcta de arriba hacia abajo?","ru":"Предприятие должно хранить сырую рыбу, сырой свиной фарш и лоток с варёным рисом в одном холодильнике с тремя полками. Какое расположение правильное сверху вниз?","tr":"Bir işletme, çiğ balığı, çiğ kıyma domuz etini ve bir tava pişmiş pirinci üç raflı bir soğutucuda saklamak zorundadır. Yukarıdan aşağıya doğru hangi düzen doğrudur?","hi":"एक प्रतिष्ठान को कच्ची मछली, कच्चे पिसे हुए सूअर का मांस (pork) और पके हुए चावल का एक पैन तीन शेल्फ वाले एक कूलर में रखना है। ऊपर से नीचे तक कौन सी व्यवस्था सही है?","ar":"على منشأة تخزين سمك نيء ولحم خنزير مفروم نيء وصينية أرز مطبوخ في ثلاجة واحدة بثلاثة أرفف. أي ترتيب صحيح من الأعلى إلى الأسفل؟"},"o":[{"en":"Raw ground pork on top, raw fish in the middle, cooked rice on the bottom","es":"Carne molida de cerdo cruda arriba, pescado crudo en el medio, arroz cocido abajo","ru":"Сырой свиной фарш сверху, сырая рыба посередине, варёный рис снизу","tr":"En üstte çiğ kıyma domuz eti, ortada çiğ balık, en altta pişmiş pirinç","hi":"सबसे ऊपर कच्चा पिसा हुआ सूअर का मांस, बीच में कच्ची मछली, सबसे नीचे पके हुए चावल","ar":"لحم الخنزير المفروم النيء في الأعلى، والسمك النيء في الوسط، والأرز المطبوخ في الأسفل"},{"en":"Cooked rice on top, raw fish in the middle, raw ground pork on the bottom","es":"Arroz cocido arriba, pescado crudo en el medio, carne molida de cerdo cruda abajo","ru":"Варёный рис сверху, сырая рыба посередине, сырой свиной фарш снизу","tr":"En üstte pişmiş pirinç, ortada çiğ balık, en altta çiğ kıyma domuz eti","hi":"सबसे ऊपर पके हुए चावल, बीच में कच्ची मछली, सबसे नीचे कच्चा पिसा हुआ सूअर का मांस","ar":"الأرز المطبوخ في الأعلى، والسمك النيء في الوسط، ولحم الخنزير المفروم النيء في الأسفل"},{"en":"Raw fish on top, cooked rice in the middle, raw ground pork on the bottom","es":"Pescado crudo arriba, arroz cocido en el medio, carne molida de cerdo cruda abajo","ru":"Сырая рыба сверху, варёный рис посередине, сырой свиной фарш снизу","tr":"En üstte çiğ balık, ortada pişmiş pirinç, en altta çiğ kıyma domuz eti","hi":"सबसे ऊपर कच्ची मछली, बीच में पके हुए चावल, सबसे नीचे कच्चा पिसा हुआ सूअर का मांस","ar":"السمك النيء في الأعلى، والأرز المطبوخ في الوسط، ولحم الخنزير المفروم النيء في الأسفل"},{"en":"Cooked rice on top, raw ground pork in the middle, raw fish on the bottom","es":"Arroz cocido arriba, carne molida de cerdo cruda en el medio, pescado crudo abajo","ru":"Варёный рис сверху, сырой свиной фарш посередине, сырая рыба снизу","tr":"En üstte pişmiş pirinç, ortada çiğ kıyma domuz eti, en altta çiğ balık","hi":"सबसे ऊपर पके हुए चावल, बीच में कच्चा पिसा हुआ सूअर का मांस, सबसे नीचे कच्ची मछली","ar":"الأرز المطبوخ في الأعلى، ولحم الخنزير المفروم النيء في الوسط، والسمك النيء في الأسفل"}],"e":{"en":"Ready-to-eat cooked rice goes on top, then raw fish (145°F), and raw ground pork (155°F) on the bottom because it has the higher minimum cooking temperature.","es":"El arroz cocido listo para comer va arriba, luego el pescado crudo (145°F), y la carne molida de cerdo cruda (155°F) abajo porque tiene la temperatura mínima de cocción más alta.","ru":"Готовый к употреблению варёный рис размещается сверху, затем сырая рыба (145°F), а сырой свиной фарш (155°F) снизу, поскольку у него более высокая минимальная температура приготовления.","tr":"Yemeye hazır pişmiş pirinç en üste, ardından çiğ balık (145°F) gelir ve çiğ kıyma domuz eti (155°F) daha yüksek asgari pişirme sıcaklığına sahip olduğu için en alta konur.","hi":"खाने के लिए तैयार पके हुए चावल सबसे ऊपर जाते हैं, फिर कच्ची मछली (145°F), और कच्चा पिसा हुआ सूअर का मांस (155°F) सबसे नीचे क्योंकि इसका न्यूनतम पकाने का तापमान अधिक होता है।","ar":"يوضع الأرز المطبوخ الجاهز للأكل في الأعلى، ثم السمك النيء (145°F)، ولحم الخنزير المفروم النيء (155°F) في الأسفل لأنه يتطلب درجة حرارة طهي دنيا أعلى."}},{"cat":"illness","a":2,"q":{"en":"What does the acronym FAT TOM stand for in food safety?","es":"¿Qué significa el acrónimo FAT TOM en la seguridad alimentaria?","ru":"Что означает акроним FAT TOM в области пищевой безопасности?","tr":"Gıda güvenliğinde FAT TOM kısaltması neyi ifade eder?","hi":"खाद्य सुरक्षा में FAT TOM संक्षिप्त नाम किसका प्रतिनिधित्व करता है?","ar":"ماذا يرمز اختصار FAT TOM في سلامة الغذاء؟"},"o":[{"en":"Freshness, Air, Temperature, Toxins, Oxygen, Metals","es":"Frescura, Aire, Temperatura, Toxinas, Oxígeno, Metales","ru":"Свежесть, Воздух, Температура, Токсины, Кислород, Металлы","tr":"Tazelik, Hava, Sıcaklık, Toksinler, Oksijen, Metaller","hi":"Freshness, Air, Temperature, Toxins, Oxygen, Metals","ar":"Freshness، Air، Temperature، Toxins، Oxygen، Metals"},{"en":"Fat, Allergens, Texture, Taste, Odor, Microbes","es":"Grasa, Alérgenos, Textura, Sabor, Olor, Microbios","ru":"Жир, Аллергены, Текстура, Вкус, Запах, Микробы","tr":"Yağ, Alerjenler, Doku, Tat, Koku, Mikroplar","hi":"Fat, Allergens, Texture, Taste, Odor, Microbes","ar":"Fat، Allergens، Texture، Taste، Odor، Microbes"},{"en":"Food, Acidity, Temperature, Time, Oxygen, Moisture","es":"Alimento (Food), Acidez, Temperatura (Temperature), Tiempo (Time), Oxígeno, Humedad (Moisture)","ru":"Пища, Кислотность, Температура, Время, Кислород, Влажность","tr":"Gıda, Asitlik, Sıcaklık, Zaman, Oksijen, Nem","hi":"Food, Acidity, Temperature, Time, Oxygen, Moisture","ar":"Food، Acidity، Temperature، Time، Oxygen، Moisture"},{"en":"Food, Allergens, Time, Toxins, Oxygen, Moisture","es":"Alimento, Alérgenos, Tiempo, Toxinas, Oxígeno, Humedad","ru":"Пища, Аллергены, Время, Токсины, Кислород, Влажность","tr":"Gıda, Alerjenler, Zaman, Toksinler, Oksijen, Nem","hi":"Food, Allergens, Time, Toxins, Oxygen, Moisture","ar":"Food، Allergens، Time، Toxins، Oxygen، Moisture"}],"e":{"en":"FAT TOM names the six conditions bacteria need to grow: Food, Acidity, Temperature, Time, Oxygen, and Moisture.","es":"FAT TOM nombra las seis condiciones que las bacterias necesitan para crecer: Alimento (Food), Acidez, Temperatura (Temperature), Tiempo (Time), Oxígeno y Humedad (Moisture).","ru":"FAT TOM называет шесть условий, необходимых бактериям для роста: Пища (Food), Кислотность (Acidity), Температура (Temperature), Время (Time), Кислород (Oxygen) и Влажность (Moisture).","tr":"FAT TOM, bakterilerin büyümesi için ihtiyaç duyduğu altı koşulu adlandırır: Gıda (Food), Asitlik (Acidity), Sıcaklık (Temperature), Zaman (Time), Oksijen (Oxygen) ve Nem (Moisture).","hi":"FAT TOM उन छह स्थितियों के नाम बताता है जिनकी बैक्टीरिया को बढ़ने के लिए आवश्यकता होती है: Food, Acidity, Temperature, Time, Oxygen, और Moisture।","ar":"يُسمّي FAT TOM الظروف الستة التي تحتاجها البكتيريا للنمو: الغذاء (Food)، والحموضة (Acidity)، ودرجة الحرارة (Temperature)، والوقت (Time)، والأكسجين (Oxygen)، والرطوبة (Moisture)."}},{"cat":"illness","a":2,"q":{"en":"A food employee tells the person-in-charge they are vomiting at home. According to the FDA Food Code, what is the correct action?","es":"Un empleado de alimentos le dice a la persona a cargo que está vomitando en casa. Según el Código de Alimentos de la FDA, ¿cuál es la acción correcta?","ru":"Сотрудник, работающий с пищей, сообщает ответственному лицу, что у него рвота дома. Согласно Пищевому кодексу FDA, каким должно быть правильное действие?","tr":"Bir gıda çalışanı, sorumlu kişiye evde kustuğunu söylüyor. FDA Gıda Yönetmeliği'ne göre doğru eylem nedir?","hi":"एक खाद्य कर्मचारी प्रभारी व्यक्ति (person-in-charge) को बताता है कि वह घर पर उल्टी कर रहा है। FDA Food Code के अनुसार, सही कार्रवाई क्या है?","ar":"يُخبر موظف غذاء المسؤول المباشر بأنه يتقيأ في المنزل. وفقاً لمدوّنة الغذاء الصادرة عن FDA، ما هو الإجراء الصحيح؟"},"o":[{"en":"Allow them to work as long as they wear gloves","es":"Permitirle trabajar siempre que use guantes","ru":"Разрешить ему работать, если он надевает перчатки","tr":"Eldiven taktığı sürece çalışmasına izin vermek","hi":"जब तक वह दस्ताने पहनता है तब तक उसे काम करने दें","ar":"السماح له بالعمل ما دام يرتدي قفازات"},{"en":"Send them to prep raw meat only, away from ready-to-eat food","es":"Enviarlo a preparar solo carne cruda, lejos de los alimentos listos para comer","ru":"Отправить его готовить только сырое мясо, вдали от готовых к употреблению продуктов","tr":"Onu yemeye hazır gıdadan uzakta yalnızca çiğ et hazırlamaya yönlendirmek","hi":"उसे केवल कच्चा मांस तैयार करने भेजें, खाने के लिए तैयार भोजन से दूर","ar":"إرساله لتحضير اللحوم النيئة فقط، بعيداً عن الطعام الجاهز للأكل"},{"en":"Exclude or restrict them from handling food until cleared","es":"Excluirlo o restringirlo de manipular alimentos hasta que sea autorizado","ru":"Отстранить или ограничить его от работы с пищей до получения разрешения","tr":"İyileştiği onaylanana kadar gıdayla teması engellemek veya kısıtlamak","hi":"उसे तब तक भोजन संभालने से बाहर रखें या प्रतिबंधित करें जब तक उसे मंज़ूरी न मिल जाए","ar":"استبعاده أو تقييده من التعامل مع الطعام حتى يُسمح له بالعودة"},{"en":"Let them work but assign them to dishwashing","es":"Dejarlo trabajar pero asignarlo a lavar platos","ru":"Разрешить ему работать, но поручить мытьё посуды","tr":"Çalışmasına izin verip ona bulaşık yıkamayı görevlendirmek","hi":"उसे काम करने दें लेकिन बर्तन धोने का काम सौंपें","ar":"السماح له بالعمل مع تكليفه بغسل الأطباق"}],"e":{"en":"Vomiting is a reportable symptom; the person-in-charge must exclude or restrict the employee to prevent spreading foodborne illness.","es":"El vómito es un síntoma que debe reportarse; la persona a cargo debe excluir o restringir al empleado para evitar la propagación de enfermedades transmitidas por los alimentos.","ru":"Рвота — это симптом, подлежащий обязательному сообщению; ответственное лицо должно отстранить или ограничить сотрудника, чтобы предотвратить распространение пищевого заболевания.","tr":"Kusma bildirilmesi gereken bir belirtidir; sorumlu kişi, gıda kaynaklı hastalığın yayılmasını önlemek için çalışanın teması engellemeli veya kısıtlamalıdır.","hi":"उल्टी एक रिपोर्ट करने योग्य लक्षण है; प्रभारी व्यक्ति को खाद्यजनित बीमारी फैलने से रोकने के लिए कर्मचारी को बाहर रखना या प्रतिबंधित करना चाहिए।","ar":"التقيؤ عَرَض يجب الإبلاغ عنه؛ على المسؤول المباشر استبعاد الموظف أو تقييده لمنع انتشار المرض المنقول بالغذاء."}},{"cat":"illness","a":1,"q":{"en":"Which group is NOT considered a highly susceptible population for foodborne illness?","es":"¿Cuál grupo NO se considera una población altamente susceptible a las enfermedades transmitidas por los alimentos?","ru":"Какая группа НЕ считается группой повышенного риска по пищевым заболеваниям?","tr":"Hangi grup gıda kaynaklı hastalık için yüksek riskli bir nüfus olarak KABUL EDİLMEZ?","hi":"कौन सा समूह खाद्यजनित बीमारी के लिए अत्यधिक संवेदनशील आबादी नहीं माना जाता है?","ar":"أي فئة لا تُعتبر من السكان شديدي القابلية للإصابة بالأمراض المنقولة بالغذاء؟"},"o":[{"en":"Young children","es":"Niños pequeños","ru":"Маленькие дети","tr":"Küçük çocuklar","hi":"छोटे बच्चे","ar":"الأطفال الصغار"},{"en":"Healthy adults in their 20s","es":"Adultos sanos de veintitantos años","ru":"Здоровые взрослые в возрасте около 20 лет","tr":"20'li yaşlarındaki sağlıklı yetişkinler","hi":"अपने 20 के दशक में स्वस्थ वयस्क","ar":"البالغون الأصحّاء في العشرينيات من العمر"},{"en":"Pregnant women","es":"Mujeres embarazadas","ru":"Беременные женщины","tr":"Hamile kadınlar","hi":"गर्भवती महिलाएं","ar":"النساء الحوامل"},{"en":"People with weakened immune systems","es":"Personas con sistemas inmunitarios debilitados","ru":"Люди с ослабленным иммунитетом","tr":"Bağışıklık sistemi zayıflamış kişiler","hi":"कमज़ोर प्रतिरक्षा प्रणाली वाले लोग","ar":"الأشخاص ذوو المناعة الضعيفة"}],"e":{"en":"Highly susceptible populations are the young, old, pregnant, and immunocompromised (YOPI); healthy young adults are not included.","es":"Las poblaciones altamente susceptibles son los jóvenes, los adultos mayores, las embarazadas y las personas inmunocomprometidas (YOPI); los adultos jóvenes y sanos no están incluidos.","ru":"Группы повышенного риска — это дети, пожилые люди, беременные и люди с ослабленным иммунитетом (YOPI); здоровые молодые взрослые в них не входят.","tr":"Yüksek riskli nüfuslar küçükler, yaşlılar, hamileler ve bağışıklığı baskılanmış kişilerdir (YOPI); sağlıklı genç yetişkinler buna dahil değildir.","hi":"अत्यधिक संवेदनशील आबादी में छोटे, बुज़ुर्ग, गर्भवती और प्रतिरक्षा-समझौता वाले लोग (YOPI) शामिल हैं; स्वस्थ युवा वयस्क इसमें शामिल नहीं हैं।","ar":"السكان شديدو القابلية للإصابة هم الصغار وكبار السن والحوامل وضعاف المناعة (YOPI)؛ ولا يشمل ذلك البالغين الأصحّاء صغار السن."}},{"cat":"illness","a":0,"q":{"en":"Which of the following is an example of a physical hazard in food?","es":"¿Cuál de los siguientes es un ejemplo de un peligro físico en los alimentos?","ru":"Что из перечисленного является примером физической опасности в пище?","tr":"Aşağıdakilerden hangisi gıdada fiziksel bir tehlikeye örnektir?","hi":"निम्नलिखित में से कौन सा भोजन में भौतिक खतरे का उदाहरण है?","ar":"أي مما يلي يُعد مثالاً على خطر فيزيائي في الطعام؟"},"o":[{"en":"A piece of broken glass","es":"Un trozo de vidrio roto","ru":"Кусок битого стекла","tr":"Bir kırık cam parçası","hi":"टूटे हुए कांच का एक टुकड़ा","ar":"قطعة زجاج مكسور"},{"en":"Salmonella bacteria","es":"Bacterias de Salmonella","ru":"Бактерии сальмонеллы","tr":"Salmonella bakterisi","hi":"साल्मोनेला (Salmonella) बैक्टीरिया","ar":"بكتيريا السالمونيلا"},{"en":"A cleaning sanitizer residue","es":"Un residuo de desinfectante de limpieza","ru":"Остатки чистящего дезинфицирующего средства","tr":"Bir temizlik dezenfektanı kalıntısı","hi":"एक सफाई सैनिटाइज़र अवशेष","ar":"بقايا مطهِّر تنظيف"},{"en":"Norovirus particles","es":"Partículas de norovirus","ru":"Частицы норовируса","tr":"Norovirüs partikülleri","hi":"नोरोवायरस (norovirus) के कण","ar":"جزيئات فيروس نوروفيروس"}],"e":{"en":"Physical hazards are foreign objects such as glass, metal, or bone; bacteria and viruses are biological and sanitizer is chemical.","es":"Los peligros físicos son objetos extraños como vidrio, metal o hueso; las bacterias y los virus son biológicos y el desinfectante es químico.","ru":"Физические опасности — это посторонние предметы, такие как стекло, металл или кость; бактерии и вирусы являются биологическими, а дезинфицирующее средство — химическим.","tr":"Fiziksel tehlikeler cam, metal veya kemik gibi yabancı cisimlerdir; bakteri ve virüsler biyolojik, dezenfektan ise kimyasaldır.","hi":"भौतिक खतरे बाहरी वस्तुएं होती हैं जैसे कांच, धातु या हड्डी; बैक्टीरिया और वायरस जैविक होते हैं और सैनिटाइज़र रासायनिक होता है।","ar":"المخاطر الفيزيائية هي أجسام غريبة مثل الزجاج أو المعدن أو العظم؛ أما البكتيريا والفيروسات فبيولوجية والمطهِّر كيميائي."}},{"cat":"illness","a":3,"q":{"en":"Which symptom is most commonly associated with Hepatitis A infection and must be reported to the person-in-charge?","es":"¿Qué síntoma se asocia más comúnmente con la infección por Hepatitis A y debe reportarse a la persona a cargo?","ru":"Какой симптом наиболее часто связан с инфекцией гепатита А и должен быть сообщён ответственному лицу?","tr":"Hepatit A enfeksiyonuyla en yaygın olarak ilişkilendirilen ve sorumlu kişiye bildirilmesi gereken belirti hangisidir?","hi":"कौन सा लक्षण हेपेटाइटिस A (Hepatitis A) संक्रमण से सबसे आम तौर पर जुड़ा है और जिसे प्रभारी व्यक्ति को रिपोर्ट किया जाना चाहिए?","ar":"أي عَرَض يرتبط بشكل أكثر شيوعاً بعدوى التهاب الكبد A (Hepatitis A) ويجب الإبلاغ عنه للمسؤول المباشر؟"},"o":[{"en":"Itchy skin rash","es":"Erupción cutánea con picazón","ru":"Зудящая кожная сыпь","tr":"Kaşıntılı cilt döküntüsü","hi":"खुजली वाला त्वचा पर चकत्ता","ar":"طفح جلدي مثير للحكة"},{"en":"A runny nose","es":"Secreción nasal","ru":"Насморк","tr":"Burun akıntısı","hi":"बहती नाक","ar":"سيلان الأنف"},{"en":"Muscle cramps in the legs","es":"Calambres musculares en las piernas","ru":"Мышечные судороги в ногах","tr":"Bacaklarda kas krampları","hi":"पैरों में मांसपेशियों की ऐंठन","ar":"تشنجات عضلية في الساقين"},{"en":"Jaundice (yellowing of the skin or eyes)","es":"Ictericia (coloración amarillenta de la piel o los ojos)","ru":"Желтуха (пожелтение кожи или глаз)","tr":"Sarılık (cildin veya gözlerin sararması)","hi":"पीलिया (त्वचा या आंखों का पीला होना)","ar":"اليرقان (اصفرار الجلد أو العينين)"}],"e":{"en":"Hepatitis A commonly causes jaundice, and any food employee who is jaundiced must be reported and excluded under the Food Code.","es":"La Hepatitis A comúnmente causa ictericia, y cualquier empleado de alimentos que tenga ictericia debe ser reportado y excluido según el Código de Alimentos.","ru":"Гепатит А часто вызывает желтуху, и о любом сотруднике с желтухой необходимо сообщить и отстранить его согласно Пищевому кодексу.","tr":"Hepatit A yaygın olarak sarılığa neden olur ve sarılığı olan herhangi bir gıda çalışanı Gıda Yönetmeliği uyarınca bildirilmeli ve gıdayla teması engellenmelidir.","hi":"हेपेटाइटिस A आमतौर पर पीलिया का कारण बनता है, और किसी भी खाद्य कर्मचारी को जिसे पीलिया हो, उसे Food Code के तहत रिपोर्ट किया जाना चाहिए और बाहर रखा जाना चाहिए।","ar":"يسبب التهاب الكبد A عادةً اليرقان، وأي موظف غذاء مصاب باليرقان يجب الإبلاغ عنه واستبعاده بموجب مدوّنة الغذاء."}},{"cat":"illness","a":2,"q":{"en":"Which of these pathogens is one of the 'Big 6' highly contagious reportable pathogens?","es":"¿Cuál de estos patógenos es uno de los patógenos altamente contagiosos y de declaración obligatoria de los 'Seis Grandes' (Big 6)?","ru":"Какой из этих патогенов входит в «Большую шестёрку» (Big 6) высокозаразных патогенов, подлежащих обязательному сообщению?","tr":"Bu patojenlerden hangisi 'Büyük 6' yüksek bulaşıcı, bildirilmesi gereken patojenlerden biridir?","hi":"इनमें से कौन सा रोगजनक 'Big 6' अत्यधिक संक्रामक रिपोर्ट करने योग्य रोगजनकों में से एक है?","ar":"أي من مسببات الأمراض التالية يُعد من 'الستة الكبار' (Big 6) شديدي العدوى الواجب الإبلاغ عنهم؟"},"o":[{"en":"Staphylococcus aureus","es":"Staphylococcus aureus","ru":"Золотистый стафилококк (Staphylococcus aureus)","tr":"Staphylococcus aureus","hi":"स्टैफिलोकोकस ऑरियस (Staphylococcus aureus)","ar":"المكورات العنقودية الذهبية (Staphylococcus aureus)"},{"en":"Clostridium botulinum","es":"Clostridium botulinum","ru":"Клостридия ботулизма (Clostridium botulinum)","tr":"Clostridium botulinum","hi":"क्लोस्ट्रिडियम बोटुलिनम (Clostridium botulinum)","ar":"المطثية الوشيقية (Clostridium botulinum)"},{"en":"Norovirus","es":"Norovirus","ru":"Норовирус","tr":"Norovirüs","hi":"नोरोवायरस (Norovirus)","ar":"فيروس نوروفيروس (Norovirus)"},{"en":"Bacillus cereus","es":"Bacillus cereus","ru":"Бацилла цереус (Bacillus cereus)","tr":"Bacillus cereus","hi":"बैसिलस सीरियस (Bacillus cereus)","ar":"العصوية الشمعية (Bacillus cereus)"}],"e":{"en":"The Big 6 are Norovirus, Hepatitis A, Shigella, STEC, Salmonella Typhi, and nontyphoidal Salmonella.","es":"Los Seis Grandes (Big 6) son Norovirus, Hepatitis A, Shigella, STEC, Salmonella Typhi y Salmonella no tifoidea.","ru":"В «Большую шестёрку» (Big 6) входят норовирус, гепатит А, шигелла, STEC, Salmonella Typhi и нетифоидная сальмонелла.","tr":"Büyük 6; Norovirüs, Hepatit A, Shigella, STEC, Salmonella Typhi ve tifo dışı Salmonella'dır.","hi":"Big 6 हैं Norovirus, Hepatitis A, Shigella, STEC, Salmonella Typhi, और नॉनटाइफॉइडल Salmonella।","ar":"الستة الكبار هم نوروفيروس (Norovirus)، والتهاب الكبد A (Hepatitis A)، والشيغيلا (Shigella)، وE. coli المنتجة لسم شيغا (STEC)، والسالمونيلا التيفية (Salmonella Typhi)، والسالمونيلا غير التيفية."}},{"cat":"illness","a":3,"q":{"en":"Within FAT TOM, what is the Temperature Danger Zone in which bacteria grow most rapidly?","es":"Dentro de FAT TOM, ¿cuál es la Zona de Peligro de Temperatura en la que las bacterias crecen más rápidamente?","ru":"В рамках FAT TOM, что такое опасная температурная зона, в которой бактерии растут наиболее быстро?","tr":"FAT TOM içinde, bakterilerin en hızlı büyüdüğü Tehlikeli Sıcaklık Bölgesi nedir?","hi":"FAT TOM के भीतर, खतरनाक तापमान क्षेत्र (Temperature Danger Zone) क्या है जिसमें बैक्टीरिया सबसे तेज़ी से बढ़ते हैं?","ar":"ضمن FAT TOM، ما هي منطقة الخطر الحرارية التي تنمو فيها البكتيريا بأسرع ما يمكن؟"},"o":[{"en":"32°F to 41°F (0°C to 5°C)","es":"32°F a 41°F (0°C a 5°C)","ru":"От 32°F до 41°F (от 0°C до 5°C)","tr":"32°F ile 41°F arası (0°C ile 5°C)","hi":"32°F से 41°F (0°C से 5°C)","ar":"32°F to 41°F (0°C to 5°C)"},{"en":"0°F to 32°F (-18°C to 0°C)","es":"0°F a 32°F (-18°C a 0°C)","ru":"От 0°F до 32°F (от -18°C до 0°C)","tr":"0°F ile 32°F arası (-18°C ile 0°C)","hi":"0°F से 32°F (-18°C से 0°C)","ar":"0°F to 32°F (-18°C to 0°C)"},{"en":"135°F to 212°F (57°C to 100°C)","es":"135°F a 212°F (57°C a 100°C)","ru":"От 135°F до 212°F (от 57°C до 100°C)","tr":"135°F ile 212°F arası (57°C ile 100°C)","hi":"135°F से 212°F (57°C से 100°C)","ar":"135°F to 212°F (57°C to 100°C)"},{"en":"41°F to 135°F (5°C to 57°C)","es":"41°F a 135°F (5°C a 57°C)","ru":"От 41°F до 135°F (от 5°C до 57°C)","tr":"41°F ile 135°F arası (5°C ile 57°C)","hi":"41°F से 135°F (5°C से 57°C)","ar":"41°F to 135°F (5°C to 57°C)"}],"e":{"en":"The temperature danger zone is 41°F to 135°F, where foodborne pathogens multiply most quickly.","es":"La zona de peligro de temperatura es de 41°F a 135°F, donde los patógenos transmitidos por los alimentos se multiplican más rápidamente.","ru":"Опасная температурная зона — это от 41°F до 135°F, где пищевые патогены размножаются быстрее всего.","tr":"Tehlikeli sıcaklık bölgesi 41°F ile 135°F arasıdır ve gıda kaynaklı patojenlerin en hızlı çoğaldığı aralıktır.","hi":"खतरनाक तापमान क्षेत्र 41°F से 135°F है, जहां खाद्यजनित रोगजनक सबसे तेज़ी से गुणा करते हैं।","ar":"منطقة الخطر الحرارية هي 41°F to 135°F، حيث تتكاثر مسببات الأمراض المنقولة بالغذاء بأسرع ما يمكن."}},{"cat":"illness","a":3,"q":{"en":"Which foodborne pathogen is most strongly linked to undercooked ground beef and can cause bloody diarrhea?","es":"¿Cuál patógeno transmitido por los alimentos está más fuertemente vinculado a la carne molida de res poco cocida y puede causar diarrea con sangre?","ru":"Какой пищевой патоген наиболее тесно связан с недостаточно прожаренным говяжьим фаршем и может вызывать кровавую диарею?","tr":"Hangi gıda kaynaklı patojen, az pişmiş kıyma dana eti ile en güçlü şekilde bağlantılıdır ve kanlı ishale neden olabilir?","hi":"कौन सा खाद्यजनित रोगजनक अधपके पिसे हुए गोमांस (ground beef) से सबसे मज़बूती से जुड़ा है और खूनी दस्त का कारण बन सकता है?","ar":"أي من مسببات الأمراض المنقولة بالغذاء يرتبط بأقوى صورة باللحم البقري المفروم غير المطهو جيداً ويمكن أن يسبب إسهالاً دموياً؟"},"o":[{"en":"Salmonella Typhi","es":"Salmonella Typhi","ru":"Salmonella Typhi","tr":"Salmonella Typhi","hi":"साल्मोनेला टाइफी (Salmonella Typhi)","ar":"السالمونيلا التيفية (Salmonella Typhi)"},{"en":"Norovirus","es":"Norovirus","ru":"Норовирус","tr":"Norovirüs","hi":"नोरोवायरस (Norovirus)","ar":"فيروس نوروفيروس (Norovirus)"},{"en":"Hepatitis A","es":"Hepatitis A","ru":"Гепатит А","tr":"Hepatit A","hi":"हेपेटाइटिस A (Hepatitis A)","ar":"التهاب الكبد A (Hepatitis A)"},{"en":"Shiga toxin-producing E. coli (STEC)","es":"E. coli productora de toxina Shiga (STEC)","ru":"Шига-токсин-продуцирующая кишечная палочка (STEC)","tr":"Shiga toksini üreten E. coli (STEC)","hi":"शिगा टॉक्सिन-उत्पादक E. coli (STEC)","ar":"E. coli المنتجة لسم شيغا (STEC)"}],"e":{"en":"STEC is classically associated with undercooked ground beef and can cause severe, often bloody, diarrhea.","es":"La STEC se asocia clásicamente con la carne molida de res poco cocida y puede causar diarrea grave, a menudo con sangre.","ru":"STEC классически ассоциируется с недостаточно прожаренным говяжьим фаршем и может вызывать тяжёлую, часто кровавую диарею.","tr":"STEC klasik olarak az pişmiş kıyma dana eti ile ilişkilendirilir ve şiddetli, çoğu zaman kanlı ishale neden olabilir.","hi":"STEC पारंपरिक रूप से अधपके पिसे हुए गोमांस से जुड़ा है और गंभीर, अक्सर खूनी, दस्त का कारण बन सकता है।","ar":"ترتبط STEC تقليدياً باللحم البقري المفروم غير المطهو جيداً ويمكن أن تسبب إسهالاً شديداً، غالباً ما يكون دموياً."}},{"cat":"illness","a":1,"q":{"en":"Which of the following is one of the five main risk factors for foodborne illness identified by the CDC and FDA?","es":"¿Cuál de los siguientes es uno de los cinco factores de riesgo principales de enfermedades transmitidas por los alimentos identificados por los CDC y la FDA?","ru":"Что из перечисленного является одним из пяти основных факторов риска пищевых заболеваний, определённых CDC и FDA?","tr":"Aşağıdakilerden hangisi CDC ve FDA tarafından belirlenen gıda kaynaklı hastalığın beş ana risk faktöründen biridir?","hi":"निम्नलिखित में से कौन सा CDC और FDA द्वारा पहचाने गए खाद्यजनित बीमारी के पांच मुख्य जोखिम कारकों में से एक है?","ar":"أي مما يلي يُعد أحد عوامل الخطر الرئيسية الخمسة للأمراض المنقولة بالغذاء التي حدّدتها CDC وFDA؟"},"o":[{"en":"Serving food on white plates","es":"Servir la comida en platos blancos","ru":"Подача еды на белых тарелках","tr":"Yemeği beyaz tabaklarda servis etmek","hi":"सफेद प्लेटों में भोजन परोसना","ar":"تقديم الطعام في أطباق بيضاء"},{"en":"Poor personal hygiene","es":"Higiene personal deficiente","ru":"Плохая личная гигиена","tr":"Kötü kişisel hijyen","hi":"खराब व्यक्तिगत स्वच्छता","ar":"النظافة الشخصية السيئة"},{"en":"Using stainless steel work tables","es":"Usar mesas de trabajo de acero inoxidable","ru":"Использование рабочих столов из нержавеющей стали","tr":"Paslanmaz çelik çalışma tezgâhları kullanmak","hi":"स्टेनलेस स्टील के वर्क टेबल का उपयोग करना","ar":"استخدام طاولات عمل من الفولاذ المقاوم للصدأ"},{"en":"Storing dry goods on shelves","es":"Almacenar productos secos en estantes","ru":"Хранение сухих продуктов на полках","tr":"Kuru gıdaları raflarda saklamak","hi":"सूखे सामान को शेल्फ पर रखना","ar":"تخزين السلع الجافة على الأرفف"}],"e":{"en":"The CDC/FDA name poor personal hygiene, time-temperature abuse, cross-contamination, contaminated equipment, and unsafe sources as the top risk factors.","es":"Los CDC/FDA nombran la higiene personal deficiente, el abuso de tiempo y temperatura, la contaminación cruzada, el equipo contaminado y las fuentes no seguras como los principales factores de riesgo.","ru":"CDC/FDA называют плохую личную гигиену, нарушение режима времени и температуры, перекрёстное загрязнение, загрязнённое оборудование и небезопасные источники главными факторами риска.","tr":"CDC/FDA, en önemli risk faktörleri olarak kötü kişisel hijyen, zaman-sıcaklık ihlali, çapraz bulaşma, kirli ekipman ve güvenli olmayan kaynakları belirtir.","hi":"CDC/FDA खराब व्यक्तिगत स्वच्छता, समय-तापमान दुरुपयोग, क्रॉस-कॉन्टैमिनेशन, संदूषित उपकरण, और असुरक्षित स्रोतों को शीर्ष जोखिम कारकों के रूप में नाम देते हैं।","ar":"تحدّد CDC/FDA النظافة الشخصية السيئة، وإساءة استخدام الوقت ودرجة الحرارة، والتلوث المتبادل، والمعدات الملوثة، والمصادر غير الآمنة بوصفها أبرز عوامل الخطر."}},{"cat":"illness","a":1,"q":{"en":"Norovirus and Hepatitis A are most often spread to food through which route?","es":"El Norovirus y la Hepatitis A se propagan más a menudo a los alimentos a través de qué vía?","ru":"Норовирус и гепатит А чаще всего попадают в пищу каким путём?","tr":"Norovirüs ve Hepatit A en sık hangi yolla gıdaya yayılır?","hi":"नोरोवायरस और हेपेटाइटिस A सबसे अधिक बार किस मार्ग से भोजन में फैलते हैं?","ar":"ينتقل فيروس نوروفيروس والتهاب الكبد A إلى الطعام في الغالب عبر أي مسار؟"},"o":[{"en":"Cooking food at too high a temperature","es":"Cocinar los alimentos a una temperatura demasiado alta","ru":"При приготовлении пищи при слишком высокой температуре","tr":"Gıdayı çok yüksek sıcaklıkta pişirerek","hi":"भोजन को बहुत अधिक तापमान पर पकाना","ar":"طهي الطعام عند درجة حرارة مرتفعة جداً"},{"en":"The fecal-oral route from an infected food handler's unwashed hands","es":"La vía fecal-oral desde las manos sin lavar de un manipulador de alimentos infectado","ru":"Фекально-оральным путём с немытых рук инфицированного работника пищевой сферы","tr":"Enfekte bir gıda çalışanının yıkanmamış ellerinden fekal-oral yolla","hi":"संक्रमित खाद्य संचालक के बिना धोए हाथों से मल-मौखिक (fecal-oral) मार्ग","ar":"المسار البرازي الفموي من يدي متداول طعام مصاب غير مغسولتين"},{"en":"Storing food in metal containers","es":"Almacenar los alimentos en recipientes metálicos","ru":"При хранении пищи в металлических контейнерах","tr":"Gıdayı metal kaplarda saklayarak","hi":"भोजन को धातु के कंटेनरों में रखना","ar":"تخزين الطعام في حاويات معدنية"},{"en":"Leaving food uncovered overnight in a freezer","es":"Dejar los alimentos destapados toda la noche en un congelador","ru":"При оставлении пищи открытой на ночь в морозильной камере","tr":"Gıdayı bir gecede dondurucuda üstü açık bırakarak","hi":"भोजन को फ्रीज़र में रात भर खुला छोड़ना","ar":"ترك الطعام مكشوفاً طوال الليل في المجمّد"}],"e":{"en":"Both viruses spread via the fecal-oral route, often when an infected handler with poor hand hygiene touches ready-to-eat food.","es":"Ambos virus se propagan por la vía fecal-oral, a menudo cuando un manipulador infectado con higiene de manos deficiente toca alimentos listos para comer.","ru":"Оба вируса распространяются фекально-оральным путём, часто когда инфицированный работник с плохой гигиеной рук прикасается к готовым к употреблению продуктам.","tr":"Her iki virüs de fekal-oral yolla, çoğunlukla kötü el hijyeni olan enfekte bir çalışan yemeye hazır gıdaya dokunduğunda yayılır.","hi":"दोनों वायरस मल-मौखिक मार्ग से फैलते हैं, अक्सर तब जब खराब हाथ स्वच्छता वाला कोई संक्रमित संचालक खाने के लिए तैयार भोजन को छूता है।","ar":"ينتشر كلا الفيروسين عبر المسار البرازي الفموي، غالباً عندما يلمس متداول مصاب ذو نظافة يدين سيئة طعاماً جاهزاً للأكل."}},{"cat":"illness","a":3,"q":{"en":"In FAT TOM, bacteria grow best in foods with which acidity (pH) range?","es":"En FAT TOM, las bacterias crecen mejor en alimentos con qué rango de acidez (pH)?","ru":"В FAT TOM бактерии лучше всего растут в продуктах с каким диапазоном кислотности (pH)?","tr":"FAT TOM içinde, bakteriler hangi asitlik (pH) aralığındaki gıdalarda en iyi büyür?","hi":"FAT TOM में, बैक्टीरिया किस अम्लता (pH) सीमा वाले भोजन में सबसे अच्छी तरह बढ़ते हैं?","ar":"في FAT TOM، تنمو البكتيريا على أفضل نحو في الأطعمة ذات أي نطاق حموضة (pH)؟"},"o":[{"en":"Only at exactly pH 7.0","es":"Solo exactamente a pH 7.0","ru":"Только точно при pH 7,0","tr":"Yalnızca tam olarak pH 7.0'da","hi":"केवल बिल्कुल pH 7.0 पर","ar":"فقط عند pH 7.0 بالضبط"},{"en":"Very acidic, below pH 2.0","es":"Muy ácido, por debajo de pH 2.0","ru":"Очень кислой, ниже pH 2,0","tr":"Çok asidik, pH 2.0'ın altında","hi":"बहुत अम्लीय, pH 2.0 से नीचे","ar":"حمضية جداً، أقل من pH 2.0"},{"en":"Strongly alkaline, above pH 11.0","es":"Fuertemente alcalino, por encima de pH 11.0","ru":"Сильно щелочной, выше pH 11,0","tr":"Güçlü alkali, pH 11.0'ın üzerinde","hi":"मज़बूत क्षारीय, pH 11.0 से ऊपर","ar":"قلوية بقوة، أعلى من pH 11.0"},{"en":"Slightly acidic to neutral, about pH 4.6 to 7.5","es":"De ligeramente ácido a neutro, aproximadamente pH 4.6 a 7.5","ru":"Слабокислой до нейтральной, около pH от 4,6 до 7,5","tr":"Hafif asidikten nötre, yaklaşık pH 4.6 ile 7.5 arası","hi":"थोड़ा अम्लीय से उदासीन, लगभग pH 4.6 से 7.5","ar":"حمضية قليلاً إلى متعادلة، نحو pH 4.6 to 7.5"}],"e":{"en":"Most foodborne bacteria thrive in the slightly acidic to neutral range (about pH 4.6–7.5); highly acidic foods inhibit growth.","es":"La mayoría de las bacterias transmitidas por los alimentos prosperan en el rango de ligeramente ácido a neutro (aproximadamente pH 4.6–7.5); los alimentos muy ácidos inhiben el crecimiento.","ru":"Большинство пищевых бактерий процветают в слабокислом и нейтральном диапазоне (около pH 4,6–7,5); сильнокислые продукты подавляют рост.","tr":"Çoğu gıda kaynaklı bakteri hafif asidikten nötre kadar olan aralıkta (yaklaşık pH 4.6–7.5) gelişir; yüksek asitli gıdalar büyümeyi engeller.","hi":"अधिकांश खाद्यजनित बैक्टीरिया थोड़े अम्लीय से उदासीन सीमा (लगभग pH 4.6–7.5) में पनपते हैं; अत्यधिक अम्लीय भोजन वृद्धि को रोकते हैं।","ar":"تزدهر معظم البكتيريا المنقولة بالغذاء في النطاق الحمضي قليلاً إلى المتعادل (نحو pH 4.6–7.5)؛ أما الأطعمة شديدة الحموضة فتثبّط النمو."}},{"cat":"illness","a":0,"q":{"en":"Salmonella Typhi, one of the Big 6, is the cause of which disease?","es":"Salmonella Typhi, uno de los Seis Grandes (Big 6), es la causa de qué enfermedad?","ru":"Salmonella Typhi, одна из «Большой шестёрки» (Big 6), является причиной какого заболевания?","tr":"Büyük 6'dan biri olan Salmonella Typhi, hangi hastalığın nedenidir?","hi":"साल्मोनेला टाइफी (Salmonella Typhi), Big 6 में से एक, किस बीमारी का कारण है?","ar":"السالمونيلا التيفية (Salmonella Typhi)، أحد الستة الكبار، هي سبب أي مرض؟"},"o":[{"en":"Typhoid fever","es":"Fiebre tifoidea","ru":"Брюшного тифа","tr":"Tifo (tifoid ateşi)","hi":"टाइफाइड बुखार","ar":"حمى التيفوئيد"},{"en":"Botulism","es":"Botulismo","ru":"Ботулизма","tr":"Botulizm","hi":"बोटुलिज़्म (Botulism)","ar":"التسمم الوشيقي (البوتوليزم)"},{"en":"Listeriosis","es":"Listeriosis","ru":"Листериоза","tr":"Listeriyoz","hi":"लिस्टेरियोसिस (Listeriosis)","ar":"داء الليستيريات"},{"en":"Tetanus","es":"Tétanos","ru":"Столбняка","tr":"Tetanoz","hi":"टिटनेस (Tetanus)","ar":"الكزاز (التيتانوس)"}],"e":{"en":"Salmonella Typhi causes typhoid fever and is specifically listed among the Big 6 reportable pathogens.","es":"Salmonella Typhi causa la fiebre tifoidea y está específicamente incluida entre los patógenos de declaración obligatoria de los Seis Grandes (Big 6).","ru":"Salmonella Typhi вызывает брюшной тиф и конкретно указана среди патогенов «Большой шестёрки» (Big 6), подлежащих обязательному сообщению.","tr":"Salmonella Typhi tifo ateşine neden olur ve Büyük 6 bildirilmesi gereken patojenler arasında özellikle yer alır.","hi":"साल्मोनेला टाइफी टाइफाइड बुखार का कारण बनता है और इसे विशेष रूप से Big 6 रिपोर्ट करने योग्य रोगजनकों में सूचीबद्ध किया गया है।","ar":"تسبب السالمونيلا التيفية حمى التيفوئيد وهي مُدرجة تحديداً ضمن مسببات الأمراض الستة الكبار الواجب الإبلاغ عنها."}},{"cat":"illness","a":1,"q":{"en":"Which scenario is the clearest example of cross-contamination?","es":"¿Cuál escenario es el ejemplo más claro de contaminación cruzada?","ru":"Какой сценарий является наиболее наглядным примером перекрёстного загрязнения?","tr":"Hangi senaryo çapraz bulaşmanın en açık örneğidir?","hi":"कौन सा परिदृश्य क्रॉस-कॉन्टैमिनेशन का सबसे स्पष्ट उदाहरण है?","ar":"أي سيناريو هو المثال الأوضح على التلوث المتبادل؟"},"o":[{"en":"Cooking chicken to 165°F before serving","es":"Cocinar el pollo a 165°F antes de servirlo","ru":"Приготовление курицы до 165°F перед подачей","tr":"Tavuğu servis etmeden önce 165°F'ye pişirmek","hi":"परोसने से पहले चिकन को 165°F तक पकाना","ar":"طهي الدجاج إلى 165°F قبل التقديم"},{"en":"Using the same cutting board for raw chicken and then fresh salad without cleaning","es":"Usar la misma tabla de cortar para pollo crudo y luego para ensalada fresca sin limpiarla","ru":"Использование одной разделочной доски для сырой курицы, а затем для свежего салата без очистки","tr":"Aynı kesme tahtasını çiğ tavuk için kullanıp ardından temizlemeden taze salata için kullanmak","hi":"कच्चे चिकन के लिए उसी कटिंग बोर्ड का उपयोग करना और फिर बिना साफ किए ताज़ा सलाद के लिए","ar":"استخدام لوح التقطيع نفسه للدجاج النيء ثم للسلطة الطازجة دون تنظيف"},{"en":"Storing milk at 38°F in the cooler","es":"Almacenar la leche a 38°F en el refrigerador","ru":"Хранение молока при 38°F в холодильнике","tr":"Sütü soğutucuda 38°F'de saklamak","hi":"कूलर में दूध को 38°F पर रखना","ar":"تخزين الحليب عند 38°F في الثلاجة"},{"en":"Labeling and dating leftovers before refrigerating","es":"Etiquetar y fechar las sobras antes de refrigerarlas","ru":"Маркировка и датирование остатков перед охлаждением","tr":"Artıkları buzdolabına koymadan önce etiketleyip tarih atmak","hi":"रेफ्रिजरेट करने से पहले बचे हुए भोजन को लेबल और तारीख डालना","ar":"وضع ملصقات وتواريخ على بقايا الطعام قبل تبريدها"}],"e":{"en":"Cross-contamination occurs when pathogens transfer from one food or surface to another, such as raw chicken juices to ready-to-eat salad.","es":"La contaminación cruzada ocurre cuando los patógenos se transfieren de un alimento o superficie a otro, como los jugos del pollo crudo a una ensalada lista para comer.","ru":"Перекрёстное загрязнение происходит, когда патогены переносятся с одного продукта или поверхности на другой, например соки сырой курицы на готовый к употреблению салат.","tr":"Çapraz bulaşma, patojenler bir gıdadan veya yüzeyden bir diğerine geçtiğinde oluşur, örneğin çiğ tavuk sularının yemeye hazır salataya bulaşması gibi.","hi":"क्रॉस-कॉन्टैमिनेशन तब होता है जब रोगजनक एक भोजन या सतह से दूसरे में स्थानांतरित होते हैं, जैसे कच्चे चिकन का रस खाने के लिए तैयार सलाद में।","ar":"يحدث التلوث المتبادل عندما تنتقل مسببات الأمراض من طعام أو سطح إلى آخر، مثل انتقال عصارة الدجاج النيء إلى سلطة جاهزة للأكل."}},{"cat":"illness","a":0,"q":{"en":"Most foodborne bacteria need available water to grow. They generally require a water activity (aw) above which value?","es":"La mayoría de las bacterias transmitidas por los alimentos necesitan agua disponible para crecer. Generalmente requieren una actividad de agua (aw) por encima de qué valor?","ru":"Большинству пищевых бактерий для роста требуется доступная вода. Обычно им необходима активность воды (aw) выше какого значения?","tr":"Çoğu gıda kaynaklı bakteri büyümek için mevcut suya ihtiyaç duyar. Genellikle hangi değerin üzerinde bir su aktivitesine (aw) ihtiyaç duyarlar?","hi":"अधिकांश खाद्यजनित बैक्टीरिया को बढ़ने के लिए उपलब्ध पानी की आवश्यकता होती है। उन्हें आम तौर पर किस मान से ऊपर जल सक्रियता (water activity, aw) की आवश्यकता होती है?","ar":"تحتاج معظم البكتيريا المنقولة بالغذاء إلى ماء متاح لتنمو. وهي تتطلب عموماً نشاطاً مائياً (aw) أعلى من أي قيمة؟"},"o":[{"en":"About 0.85","es":"Aproximadamente 0.85","ru":"Около 0,85","tr":"Yaklaşık 0.85","hi":"लगभग 0.85","ar":"نحو 0.85"},{"en":"Exactly 0.10","es":"Exactamente 0.10","ru":"Ровно 0,10","tr":"Tam olarak 0.10","hi":"बिल्कुल 0.10","ar":"0.10 بالضبط"},{"en":"About 0.30","es":"Aproximadamente 0.30","ru":"Около 0,30","tr":"Yaklaşık 0.30","hi":"लगभग 0.30","ar":"نحو 0.30"},{"en":"Exactly 0.00","es":"Exactamente 0.00","ru":"Ровно 0,00","tr":"Tam olarak 0.00","hi":"बिल्कुल 0.00","ar":"0.00 بالضبط"}],"e":{"en":"Pathogenic bacteria generally require a water activity above roughly 0.85, which is why dried and low-moisture foods resist growth.","es":"Las bacterias patógenas generalmente requieren una actividad de agua por encima de aproximadamente 0.85, por lo que los alimentos secos y de baja humedad resisten el crecimiento.","ru":"Патогенным бактериям обычно требуется активность воды выше примерно 0,85, поэтому сушёные продукты и продукты с низкой влажностью устойчивы к росту.","tr":"Patojenik bakteriler genellikle yaklaşık 0.85'in üzerinde bir su aktivitesine ihtiyaç duyar; bu nedenle kurutulmuş ve düşük nemli gıdalar büyümeye karşı dirençlidir.","hi":"रोगजनक बैक्टीरिया को आम तौर पर लगभग 0.85 से ऊपर जल सक्रियता की आवश्यकता होती है, यही कारण है कि सूखे और कम नमी वाले भोजन वृद्धि का प्रतिरोध करते हैं।","ar":"تتطلب البكتيريا المُمرِضة عموماً نشاطاً مائياً أعلى من نحو 0.85، وهذا هو سبب مقاومة الأطعمة المجففة وقليلة الرطوبة للنمو."}},{"cat":"illness","a":1,"q":{"en":"Which pair correctly matches a hazard type with an example?","es":"¿Cuál par relaciona correctamente un tipo de peligro con un ejemplo?","ru":"Какая пара правильно сопоставляет тип опасности с примером?","tr":"Hangi çift bir tehlike türünü bir örnekle doğru şekilde eşleştirir?","hi":"कौन सी जोड़ी खतरे के प्रकार को एक उदाहरण के साथ सही ढंग से मिलाती है?","ar":"أي زوج يطابق بشكل صحيح نوع الخطر مع مثاله؟"},"o":[{"en":"Biological hazard - a metal shaving from a worn can opener","es":"Peligro biológico - una viruta de metal de un abrelatas desgastado","ru":"Биологическая опасность — металлическая стружка от изношенного консервного ножа","tr":"Biyolojik tehlike - aşınmış bir konserve açacağından gelen metal talaşı","hi":"जैविक खतरा - घिसे हुए कैन ओपनर से धातु की छीलन","ar":"خطر بيولوجي - رقاقة معدنية من فتّاحة علب مهترئة"},{"en":"Chemical hazard - a sanitizer accidentally sprayed into food","es":"Peligro químico - un desinfectante rociado accidentalmente en la comida","ru":"Химическая опасность — дезинфицирующее средство, случайно распылённое в пищу","tr":"Kimyasal tehlike - gıdaya yanlışlıkla püskürtülen bir dezenfektan","hi":"रासायनिक खतरा - गलती से भोजन में छिड़का गया सैनिटाइज़र","ar":"خطر كيميائي - مطهِّر رُشّ في الطعام عن طريق الخطأ"},{"en":"Physical hazard - Shigella bacteria from unwashed hands","es":"Peligro físico - bacterias de Shigella de manos sin lavar","ru":"Физическая опасность — бактерии шигеллы с немытых рук","tr":"Fiziksel tehlike - yıkanmamış ellerden gelen Shigella bakterisi","hi":"भौतिक खतरा - बिना धोए हाथों से शिगेला (Shigella) बैक्टीरिया","ar":"خطر فيزيائي - بكتيريا الشيغيلا من أيدٍ غير مغسولة"},{"en":"Chemical hazard - Hepatitis A virus on produce","es":"Peligro químico - virus de la Hepatitis A en productos agrícolas","ru":"Химическая опасность — вирус гепатита А на продуктах","tr":"Kimyasal tehlike - sebzelerdeki Hepatit A virüsü","hi":"रासायनिक खतरा - उपज पर हेपेटाइटिस A (Hepatitis A) वायरस","ar":"خطر كيميائي - فيروس التهاب الكبد A على المنتجات الطازجة"}],"e":{"en":"Chemicals like sanitizers and cleaners are chemical hazards; metal is physical, and Shigella and Hepatitis A are biological.","es":"Los químicos como los desinfectantes y los limpiadores son peligros químicos; el metal es físico, y Shigella y la Hepatitis A son biológicos.","ru":"Химикаты, такие как дезинфектанты и чистящие средства, являются химическими опасностями; металл — физической, а шигелла и гепатит А — биологическими.","tr":"Dezenfektanlar ve temizleyiciler gibi kimyasallar kimyasal tehlikedir; metal fizikseldir ve Shigella ile Hepatit A biyolojiktir.","hi":"सैनिटाइज़र और क्लीनर जैसे रसायन रासायनिक खतरे हैं; धातु भौतिक है, और शिगेला तथा हेपेटाइटिस A जैविक हैं।","ar":"المواد الكيميائية مثل المطهِّرات والمنظفات هي مخاطر كيميائية؛ أما المعدن ففيزيائي، والشيغيلا والتهاب الكبد A بيولوجيان."}},{"cat":"illness","a":0,"q":{"en":"A handler has been diagnosed with nontyphoidal Salmonella. Why does the Food Code require reporting and exclusion?","es":"A un manipulador se le ha diagnosticado Salmonella no tifoidea. ¿Por qué el Código de Alimentos exige reportarlo y excluirlo?","ru":"У работника диагностирована нетифоидная сальмонелла. Почему Пищевой кодекс требует сообщения и отстранения?","tr":"Bir çalışana tifo dışı Salmonella teşhisi konmuştur. Gıda Yönetmeliği neden bildirim ve teması engellemeyi gerektirir?","hi":"एक संचालक को नॉनटाइफॉइडल साल्मोनेला (nontyphoidal Salmonella) का निदान हुआ है। Food Code रिपोर्टिंग और बहिष्करण की आवश्यकता क्यों रखता है?","ar":"شُخِّص متداول طعام بالسالمونيلا غير التيفية. لماذا تتطلب مدوّنة الغذاء الإبلاغ والاستبعاد؟"},"o":[{"en":"It is highly transmissible through food and is one of the Big 6 reportable pathogens","es":"Es altamente transmisible a través de los alimentos y es uno de los patógenos de declaración obligatoria de los Seis Grandes (Big 6)","ru":"Она легко передаётся через пищу и является одним из патогенов «Большой шестёрки» (Big 6), подлежащих обязательному сообщению","tr":"Gıda yoluyla yüksek bulaşıcılığa sahiptir ve Büyük 6 bildirilmesi gereken patojenlerden biridir","hi":"यह भोजन के माध्यम से अत्यधिक संक्रामक है और Big 6 रिपोर्ट करने योग्य रोगजनकों में से एक है","ar":"لأنها شديدة الانتقال عبر الطعام وهي أحد مسببات الأمراض الستة الكبار الواجب الإبلاغ عنهم"},{"en":"It is only dangerous if the food is frozen","es":"Solo es peligrosa si el alimento está congelado","ru":"Она опасна только если пища заморожена","tr":"Yalnızca gıda donmuşsa tehlikelidir","hi":"यह केवल तभी खतरनाक है जब भोजन फ्रोज़न हो","ar":"لأنها خطيرة فقط إذا كان الطعام مجمّداً"},{"en":"It cannot be spread by people, only by packaging","es":"No puede ser propagada por personas, solo por el empaque","ru":"Она не может передаваться людьми, только упаковкой","tr":"İnsanlar tarafından değil, yalnızca ambalaj yoluyla yayılabilir","hi":"इसे लोगों द्वारा नहीं फैलाया जा सकता, केवल पैकेजिंग द्वारा","ar":"لأنها لا تنتقل عن طريق الأشخاص، بل عن طريق التغليف فقط"},{"en":"It is not actually a foodborne pathogen","es":"No es realmente un patógeno transmitido por los alimentos","ru":"Она на самом деле не является пищевым патогеном","tr":"Aslında gıda kaynaklı bir patojen değildir","hi":"यह वास्तव में एक खाद्यजनित रोगजनक नहीं है","ar":"لأنها ليست في الواقع من مسببات الأمراض المنقولة بالغذاء"}],"e":{"en":"Nontyphoidal Salmonella is one of the Big 6; an infected handler can readily transmit it through food, so reporting and exclusion are required.","es":"La Salmonella no tifoidea es uno de los Seis Grandes (Big 6); un manipulador infectado puede transmitirla fácilmente a través de los alimentos, por lo que se requiere reportarlo y excluirlo.","ru":"Нетифоидная сальмонелла — один из патогенов «Большой шестёрки» (Big 6); инфицированный работник может легко передать её через пищу, поэтому сообщение и отстранение обязательны.","tr":"Tifo dışı Salmonella Büyük 6'dan biridir; enfekte bir çalışan onu gıda yoluyla kolayca bulaştırabilir, bu nedenle bildirim ve teması engelleme gereklidir.","hi":"नॉनटाइफॉइडल साल्मोनेला Big 6 में से एक है; एक संक्रमित संचालक इसे आसानी से भोजन के माध्यम से फैला सकता है, इसलिए रिपोर्टिंग और बहिष्करण आवश्यक है।","ar":"السالمونيلا غير التيفية هي أحد الستة الكبار؛ ويمكن لمتداول مصاب أن ينقلها بسهولة عبر الطعام، لذا يُشترط الإبلاغ والاستبعاد."}},{"cat":"illness","a":0,"q":{"en":"Refrigerating a potentially hazardous food at 39°F primarily controls bacterial growth by limiting which two FAT TOM factors?","es":"Refrigerar un alimento potencialmente peligroso a 39°F controla principalmente el crecimiento bacteriano al limitar cuáles dos factores de FAT TOM?","ru":"Охлаждение потенциально опасной пищи при 39°F в основном контролирует рост бактерий, ограничивая какие два фактора FAT TOM?","tr":"Potansiyel olarak tehlikeli bir gıdayı 39°F'de soğutmak, bakteri büyümesini esas olarak FAT TOM faktörlerinden hangi ikisini sınırlayarak kontrol eder?","hi":"किसी संभावित रूप से खतरनाक भोजन को 39°F पर रेफ्रिजरेट करना मुख्य रूप से किन दो FAT TOM कारकों को सीमित करके बैक्टीरिया की वृद्धि को नियंत्रित करता है?","ar":"تبريد طعام يحتمل أن يكون خطراً عند 39°F يتحكم في نمو البكتيريا أساساً عن طريق الحد من أيٍّ من عاملي FAT TOM؟"},"o":[{"en":"Temperature and Time","es":"Temperatura y Tiempo","ru":"Температуру и Время","tr":"Sıcaklık ve Zaman","hi":"Temperature और Time","ar":"درجة الحرارة والوقت"},{"en":"Acidity and Oxygen","es":"Acidez y Oxígeno","ru":"Кислотность и Кислород","tr":"Asitlik ve Oksijen","hi":"Acidity और Oxygen","ar":"الحموضة والأكسجين"},{"en":"Food and Moisture","es":"Alimento y Humedad","ru":"Пищу и Влажность","tr":"Gıda ve Nem","hi":"Food और Moisture","ar":"الغذاء والرطوبة"},{"en":"Oxygen and Acidity","es":"Oxígeno y Acidez","ru":"Кислород и Кислотность","tr":"Oksijen ve Asitlik","hi":"Oxygen और Acidity","ar":"الأكسجين والحموضة"}],"e":{"en":"Keeping food at 39°F holds it below the danger zone (Temperature) and slows multiplication, extending the safe holding window (Time).","es":"Mantener el alimento a 39°F lo conserva por debajo de la zona de peligro (Temperatura) y ralentiza la multiplicación, extendiendo el período seguro de conservación (Tiempo).","ru":"Хранение пищи при 39°F удерживает её ниже опасной зоны (Температура) и замедляет размножение, продлевая безопасный срок хранения (Время).","tr":"Gıdayı 39°F'de tutmak onu tehlikeli bölgenin altında tutar (Sıcaklık) ve çoğalmayı yavaşlatarak güvenli saklama süresini uzatır (Zaman).","hi":"भोजन को 39°F पर रखना इसे खतरनाक क्षेत्र (Temperature) से नीचे रखता है और गुणन को धीमा करता है, जिससे सुरक्षित होल्डिंग अवधि (Time) बढ़ती है।","ar":"يُبقي حفظ الطعام عند 39°F الطعام دون منطقة الخطر (درجة الحرارة) ويبطئ التكاثر، مما يطيل نافذة الحفظ الآمن (الوقت)."}},{"cat":"illness","a":2,"q":{"en":"Clostridium botulinum can grow in sealed canned and vacuum-packed foods because it is an anaerobe. Which FAT TOM factor does this exception specifically illustrate?","es":"Clostridium botulinum puede crecer en alimentos enlatados y empacados al vacío sellados porque es anaerobio. ¿Cuál factor de FAT TOM ilustra específicamente esta excepción?","ru":"Clostridium botulinum может расти в герметичных консервированных и вакуумно-упакованных продуктах, поскольку является анаэробом. Какой фактор FAT TOM конкретно иллюстрирует это исключение?","tr":"Clostridium botulinum anaerob olduğu için kapalı konserve ve vakumlu paketlenmiş gıdalarda büyüyebilir. Bu istisna özellikle hangi FAT TOM faktörünü gösterir?","hi":"क्लोस्ट्रिडियम बोटुलिनम (Clostridium botulinum) सीलबंद डिब्बाबंद और वैक्यूम-पैक्ड भोजन में बढ़ सकता है क्योंकि यह एक अवायवीय (anaerobe) है। यह अपवाद विशेष रूप से किस FAT TOM कारक को दर्शाता है?","ar":"يمكن للمطثية الوشيقية (Clostridium botulinum) أن تنمو في الأطعمة المعلّبة والمغلّفة بتفريغ الهواء لأنها لا هوائية. أي عامل من FAT TOM يوضّحه هذا الاستثناء تحديداً؟"},"o":[{"en":"Moisture","es":"Humedad","ru":"Влажность","tr":"Nem","hi":"Moisture","ar":"الرطوبة"},{"en":"Acidity","es":"Acidez","ru":"Кислотность","tr":"Asitlik","hi":"Acidity","ar":"الحموضة"},{"en":"Oxygen","es":"Oxígeno","ru":"Кислород","tr":"Oksijen","hi":"Oxygen","ar":"الأكسجين"},{"en":"Food","es":"Alimento","ru":"Пища","tr":"Gıda","hi":"Food","ar":"الغذاء"}],"e":{"en":"Most pathogens need oxygen, but anaerobes like C. botulinum grow without it, which is why oxygen-free packaging does not guarantee safety.","es":"La mayoría de los patógenos necesitan oxígeno, pero los anaerobios como C. botulinum crecen sin él, por lo que el empaque libre de oxígeno no garantiza la seguridad.","ru":"Большинству патогенов нужен кислород, но анаэробы, такие как C. botulinum, растут без него, поэтому бескислородная упаковка не гарантирует безопасность.","tr":"Çoğu patojen oksijene ihtiyaç duyar, ancak C. botulinum gibi anaeroblar oksijensiz büyür, bu nedenle oksijensiz ambalaj güvenliği garanti etmez.","hi":"अधिकांश रोगजनकों को ऑक्सीजन की आवश्यकता होती है, लेकिन C. botulinum जैसे अवायवीय इसके बिना बढ़ते हैं, यही कारण है कि ऑक्सीजन-मुक्त पैकेजिंग सुरक्षा की गारंटी नहीं देती।","ar":"تحتاج معظم مسببات الأمراض إلى الأكسجين، لكن اللاهوائيات مثل C. botulinum تنمو بدونه، ولهذا فإن التغليف الخالي من الأكسجين لا يضمن السلامة."}},{"cat":"cleaning","a":0,"q":{"en":"What is the main difference between cleaning and sanitizing a surface?","es":"¿Cuál es la diferencia principal entre limpiar y desinfectar una superficie?","ru":"В чём основное различие между очисткой и дезинфекцией поверхности?","tr":"Bir yüzeyi temizlemek ile dezenfekte etmek arasındaki temel fark nedir?","hi":"किसी सतह को साफ करने (cleaning) और सैनिटाइज़ करने (sanitizing) के बीच मुख्य अंतर क्या है?","ar":"ما الفرق الرئيسي بين تنظيف السطح وتطهيره؟"},"o":[{"en":"Cleaning removes food residue and dirt, while sanitizing reduces pathogens to safe levels","es":"Limpiar elimina los residuos de comida y la suciedad, mientras que desinfectar reduce los patógenos a niveles seguros","ru":"Очистка удаляет остатки пищи и грязь, а дезинфекция снижает количество патогенов до безопасного уровня","tr":"Temizlik gıda kalıntısını ve kiri giderir, dezenfekte etmek ise patojenleri güvenli seviyelere düşürür","hi":"सफाई भोजन के अवशेष और गंदगी को हटाती है, जबकि सैनिटाइज़ करना रोगजनकों को सुरक्षित स्तर तक कम करता है","ar":"التنظيف يزيل بقايا الطعام والأوساخ، بينما التطهير يقلّل مسببات الأمراض إلى مستويات آمنة"},{"en":"Cleaning kills germs, while sanitizing only removes visible dirt","es":"Limpiar mata los gérmenes, mientras que desinfectar solo elimina la suciedad visible","ru":"Очистка убивает микробы, а дезинфекция только удаляет видимую грязь","tr":"Temizlik mikropları öldürür, dezenfekte etmek ise yalnızca görünür kiri giderir","hi":"सफाई कीटाणुओं को मारती है, जबकि सैनिटाइज़ करना केवल दिखाई देने वाली गंदगी को हटाता है","ar":"التنظيف يقتل الجراثيم، بينما التطهير يزيل الأوساخ المرئية فقط"},{"en":"Cleaning and sanitizing are two words for the same single step","es":"Limpiar y desinfectar son dos palabras para el mismo paso único","ru":"Очистка и дезинфекция — это два слова для одного и того же единственного этапа","tr":"Temizlik ve dezenfekte tek bir adımın iki farklı adıdır","hi":"सफाई और सैनिटाइज़ करना एक ही एकल चरण के लिए दो शब्द हैं","ar":"التنظيف والتطهير كلمتان لنفس الخطوة الواحدة"},{"en":"Cleaning is done with hot water only, while sanitizing requires no chemicals","es":"Limpiar se hace solo con agua caliente, mientras que desinfectar no requiere químicos","ru":"Очистка выполняется только горячей водой, а дезинфекция не требует химикатов","tr":"Temizlik yalnızca sıcak suyla yapılır, dezenfekte ise kimyasal gerektirmez","hi":"सफाई केवल गर्म पानी से की जाती है, जबकि सैनिटाइज़ करने के लिए किसी रसायन की आवश्यकता नहीं होती","ar":"التنظيف يُجرى بالماء الساخن فقط، بينما التطهير لا يتطلب أي مواد كيميائية"}],"e":{"en":"Cleaning physically removes food, soil, and grease, while sanitizing reduces the number of pathogens on a clean surface to safe levels; a surface must be cleaned before it can be sanitized.","es":"Limpiar elimina físicamente la comida, la mugre y la grasa, mientras que desinfectar reduce el número de patógenos en una superficie limpia a niveles seguros; una superficie debe limpiarse antes de poder desinfectarse.","ru":"Очистка физически удаляет пищу, грязь и жир, а дезинфекция снижает количество патогенов на чистой поверхности до безопасного уровня; поверхность должна быть очищена, прежде чем её можно будет продезинфицировать.","tr":"Temizlik gıdayı, kiri ve yağı fiziksel olarak giderir, dezenfekte etmek ise temiz bir yüzeydeki patojen sayısını güvenli seviyelere düşürür; bir yüzey dezenfekte edilmeden önce temizlenmelidir.","hi":"सफाई भौतिक रूप से भोजन, मिट्टी और चिकनाई को हटाती है, जबकि सैनिटाइज़ करना एक साफ सतह पर रोगजनकों की संख्या को सुरक्षित स्तर तक कम करता है; किसी सतह को सैनिटाइज़ करने से पहले उसे साफ करना चाहिए।","ar":"يزيل التنظيف الطعام والأوساخ والشحوم فيزيائياً، بينما يقلّل التطهير عدد مسببات الأمراض على سطح نظيف إلى مستويات آمنة؛ ويجب تنظيف السطح قبل أن يمكن تطهيره."}},{"cat":"cleaning","a":2,"q":{"en":"Why must a surface be cleaned before it is sanitized?","es":"¿Por qué debe limpiarse una superficie antes de desinfectarla?","ru":"Почему поверхность необходимо очистить перед дезинфекцией?","tr":"Bir yüzey dezenfekte edilmeden önce neden temizlenmelidir?","hi":"किसी सतह को सैनिटाइज़ करने से पहले उसे साफ क्यों किया जाना चाहिए?","ar":"لماذا يجب تنظيف السطح قبل تطهيره؟"},"o":[{"en":"Sanitizer is too expensive to use on a dirty surface","es":"El desinfectante es demasiado caro para usarlo en una superficie sucia","ru":"Дезинфицирующее средство слишком дорого, чтобы использовать его на грязной поверхности","tr":"Dezenfektan kirli bir yüzeyde kullanılamayacak kadar pahalıdır","hi":"गंदी सतह पर उपयोग करने के लिए सैनिटाइज़र बहुत महंगा है","ar":"لأن المطهِّر باهظ الثمن لاستخدامه على سطح متسخ"},{"en":"Cleaning makes the surface too wet for sanitizer to stick","es":"Limpiar deja la superficie demasiado mojada para que el desinfectante se adhiera","ru":"Очистка делает поверхность слишком влажной для прилипания дезинфицирующего средства","tr":"Temizlik yüzeyi dezenfektanın tutunamayacağı kadar ıslak yapar","hi":"सफाई सतह को सैनिटाइज़र के चिपकने के लिए बहुत गीला बना देती है","ar":"لأن التنظيف يجعل السطح رطباً جداً بحيث لا يلتصق به المطهِّر"},{"en":"Leftover food and soil shield pathogens and stop the sanitizer from working","es":"Los restos de comida y la mugre protegen a los patógenos e impiden que el desinfectante funcione","ru":"Остатки пищи и грязь защищают патогены и мешают действию дезинфицирующего средства","tr":"Kalan gıda ve kir patojenleri korur ve dezenfektanın çalışmasını engeller","hi":"बचा हुआ भोजन और मिट्टी रोगजनकों को ढक लेते हैं और सैनिटाइज़र को काम करने से रोकते हैं","ar":"لأن بقايا الطعام والأوساخ تحمي مسببات الأمراض وتمنع المطهِّر من العمل"},{"en":"Sanitizing first makes the food debris harder to scrub off","es":"Desinfectar primero hace que los restos de comida sean más difíciles de tallar","ru":"Дезинфекция в первую очередь усложняет отскабливание пищевых остатков","tr":"Önce dezenfekte etmek gıda kalıntısını ovmayı zorlaştırır","hi":"पहले सैनिटाइज़ करने से भोजन के अवशेष को रगड़कर निकालना कठिन हो जाता है","ar":"لأن التطهير أولاً يجعل بقايا الطعام أصعب في الفرك لإزالتها"}],"e":{"en":"Food particles, grease, and soap residue physically block the sanitizer from contacting and killing pathogens, so surfaces must be cleaned and rinsed first.","es":"Las partículas de comida, la grasa y el residuo de jabón bloquean físicamente que el desinfectante entre en contacto con los patógenos y los mate, por lo que las superficies deben limpiarse y enjuagarse primero.","ru":"Частицы пищи, жир и остатки мыла физически препятствуют контакту дезинфицирующего средства с патогенами и их уничтожению, поэтому поверхности необходимо сначала очистить и промыть.","tr":"Gıda partikülleri, yağ ve sabun kalıntısı dezenfektanın patojenlere temas etmesini ve onları öldürmesini fiziksel olarak engeller, bu nedenle yüzeyler önce temizlenmeli ve durulanmalıdır.","hi":"भोजन के कण, चिकनाई और साबुन का अवशेष भौतिक रूप से सैनिटाइज़र को रोगजनकों से संपर्क करने और उन्हें मारने से रोकते हैं, इसलिए सतहों को पहले साफ और रिंस किया जाना चाहिए।","ar":"تمنع جزيئات الطعام والشحوم وبقايا الصابون المطهِّر فيزيائياً من ملامسة مسببات الأمراض وقتلها، لذا يجب تنظيف الأسطح وشطفها أولاً."}},{"cat":"cleaning","a":1,"q":{"en":"In a three-compartment sink, what is the correct order of steps?","es":"En un fregadero de tres compartimentos, ¿cuál es el orden correcto de los pasos?","ru":"В трёхсекционной мойке какой правильный порядок действий?","tr":"Üç bölmeli bir evyede adımların doğru sırası nedir?","hi":"तीन-कम्पार्टमेंट वाले सिंक में, चरणों का सही क्रम क्या है?","ar":"في حوض ذي ثلاثة أقسام، ما هو الترتيب الصحيح للخطوات؟"},"o":[{"en":"Wash, scrape, sanitize, rinse, towel dry","es":"Lavar, raspar, desinfectar, enjuagar, secar con toalla","ru":"Мыть, соскребать, дезинфицировать, промывать, вытирать полотенцем","tr":"Yıka, kazı, dezenfekte et, durula, havluyla kurula","hi":"धोना, खुरचना, सैनिटाइज़ करना, रिंस करना, तौलिए से सुखाना","ar":"الغسل، الكشط، التطهير، الشطف، التجفيف بالمنشفة"},{"en":"Scrape, wash, rinse, sanitize, air dry","es":"Raspar, lavar, enjuagar, desinfectar, secar al aire","ru":"Соскребать, мыть, промывать, дезинфицировать, сушить на воздухе","tr":"Kazı, yıka, durula, dezenfekte et, havada kurut","hi":"खुरचना, धोना, रिंस करना, सैनिटाइज़ करना, हवा में सुखाना","ar":"الكشط، الغسل، الشطف، التطهير، التجفيف بالهواء"},{"en":"Rinse, wash, scrape, air dry, sanitize","es":"Enjuagar, lavar, raspar, secar al aire, desinfectar","ru":"Промывать, мыть, соскребать, сушить на воздухе, дезинфицировать","tr":"Durula, yıka, kazı, havada kurut, dezenfekte et","hi":"रिंस करना, धोना, खुरचना, हवा में सुखाना, सैनिटाइज़ करना","ar":"الشطف، الغسل، الكشط، التجفيف بالهواء، التطهير"},{"en":"Scrape, sanitize, wash, rinse, towel dry","es":"Raspar, desinfectar, lavar, enjuagar, secar con toalla","ru":"Соскребать, дезинфицировать, мыть, промывать, вытирать полотенцем","tr":"Kazı, dezenfekte et, yıka, durula, havluyla kurula","hi":"खुरचना, सैनिटाइज़ करना, धोना, रिंस करना, तौलिए से सुखाना","ar":"الكشط، التطهير، الغسل، الشطف، التجفيف بالمنشفة"}],"e":{"en":"The correct sequence is scrape off debris, wash in detergent, rinse in clean water, sanitize, then air dry; the order ensures food and soap do not interfere with the sanitizer.","es":"La secuencia correcta es raspar los restos, lavar con detergente, enjuagar en agua limpia, desinfectar y luego secar al aire; el orden garantiza que la comida y el jabón no interfieran con el desinfectante.","ru":"Правильная последовательность: соскрести остатки, вымыть с моющим средством, промыть в чистой воде, продезинфицировать, затем высушить на воздухе; такой порядок гарантирует, что пища и мыло не помешают действию дезинфицирующего средства.","tr":"Doğru sıra; kalıntıları kazımak, deterjanla yıkamak, temiz suda durulamak, dezenfekte etmek ve ardından havada kurutmaktır; bu sıra gıda ve sabunun dezenfektana müdahale etmemesini sağlar.","hi":"सही क्रम है मलबे को खुरचना, डिटर्जेंट में धोना, साफ पानी में रिंस करना, सैनिटाइज़ करना, फिर हवा में सुखाना; यह क्रम सुनिश्चित करता है कि भोजन और साबुन सैनिटाइज़र में हस्तक्षेप न करें।","ar":"التسلسل الصحيح هو كشط البقايا، ثم الغسل بالمنظف، ثم الشطف بماء نظيف، ثم التطهير، ثم التجفيف بالهواء؛ ويضمن هذا الترتيب ألا يتداخل الطعام والصابون مع المطهِّر."}},{"cat":"cleaning","a":3,"q":{"en":"After sanitizing dishes in a three-compartment sink, how should they be dried?","es":"Después de desinfectar los platos en un fregadero de tres compartimentos, ¿cómo deben secarse?","ru":"После дезинфекции посуды в трёхсекционной мойке, как её следует сушить?","tr":"Üç bölmeli bir evyede bulaşıkları dezenfekte ettikten sonra nasıl kurutulmalıdır?","hi":"तीन-कम्पार्टमेंट वाले सिंक में बर्तनों को सैनिटाइज़ करने के बाद, उन्हें कैसे सुखाया जाना चाहिए?","ar":"بعد تطهير الأطباق في حوض ذي ثلاثة أقسام، كيف ينبغي تجفيفها؟"},"o":[{"en":"Wipe dry with a clean cloth towel","es":"Secarlos con una toalla de tela limpia","ru":"Вытереть насухо чистым тканевым полотенцем","tr":"Temiz bir bez havluyla silerek kurutmak","hi":"एक साफ कपड़े के तौलिए से पोंछकर सुखाएं","ar":"مسحها حتى تجف بمنشفة قماشية نظيفة"},{"en":"Stack them while still wet to save counter space","es":"Apilarlos mientras todavía están mojados para ahorrar espacio en el mostrador","ru":"Сложить её ещё влажной, чтобы сэкономить место на столе","tr":"Tezgâh alanından tasarruf etmek için hâlâ ıslakken üst üste istiflemek","hi":"काउंटर की जगह बचाने के लिए उन्हें गीला रहते हुए ही ढेर कर दें","ar":"تكديسها وهي لا تزال مبللة لتوفير مساحة الطاولة"},{"en":"Dry them with a paper towel and a final wipe of sanitizer","es":"Secarlos con una toalla de papel y un repaso final de desinfectante","ru":"Высушить бумажным полотенцем и в завершение протереть дезинфицирующим средством","tr":"Bir kâğıt havlu ve son bir dezenfektan silmesiyle kurutmak","hi":"उन्हें एक पेपर टॉवल और सैनिटाइज़र के एक अंतिम पोंछे से सुखाएं","ar":"تجفيفها بمنشفة ورقية ومسحة أخيرة من المطهِّر"},{"en":"Air dry completely before stacking or storing","es":"Secar al aire completamente antes de apilarlos o guardarlos","ru":"Полностью высушить на воздухе перед складыванием или хранением","tr":"İstiflemeden veya saklamadan önce tamamen havada kurutmak","hi":"ढेर करने या रखने से पहले उन्हें पूरी तरह से हवा में सुखाएं","ar":"تركها تجف بالهواء تماماً قبل التكديس أو التخزين"}],"e":{"en":"Items must be allowed to air dry; towel drying can recontaminate the just-sanitized surface.","es":"Los artículos deben dejarse secar al aire; secarlos con toalla puede recontaminar la superficie recién desinfectada.","ru":"Предметы должны высыхать на воздухе; вытирание полотенцем может повторно загрязнить только что продезинфицированную поверхность.","tr":"Eşyaların havada kurumasına izin verilmelidir; havluyla kurutmak yeni dezenfekte edilmiş yüzeyi yeniden kirletebilir.","hi":"वस्तुओं को हवा में सूखने दिया जाना चाहिए; तौलिए से सुखाने से अभी-अभी सैनिटाइज़ की गई सतह फिर से संदूषित हो सकती है।","ar":"يجب ترك الأدوات تجف بالهواء؛ فالتجفيف بالمنشفة قد يعيد تلويث السطح الذي تم تطهيره للتو."}},{"cat":"cleaning","a":2,"q":{"en":"What is the minimum recommended water temperature for the wash (detergent) compartment of a three-compartment sink?","es":"¿Cuál es la temperatura mínima recomendada del agua para el compartimento de lavado (detergente) de un fregadero de tres compartimentos?","ru":"Какова минимальная рекомендуемая температура воды для моечной секции (с моющим средством) трёхсекционной мойки?","tr":"Üç bölmeli bir evyenin yıkama (deterjan) bölmesi için önerilen asgari su sıcaklığı nedir?","hi":"तीन-कम्पार्टमेंट वाले सिंक के धोने (डिटर्जेंट) वाले कम्पार्टमेंट के लिए न्यूनतम अनुशंसित पानी का तापमान क्या है?","ar":"ما هي الحد الأدنى الموصى به لدرجة حرارة الماء في قسم الغسل (المنظف) من حوض ذي ثلاثة أقسام؟"},"o":[{"en":"75°F (24°C)","es":"75°F (24°C)","ru":"75°F (24°C)","tr":"75°F (24°C)","hi":"75°F (24°C)","ar":"75°F (24°C)"},{"en":"95°F (35°C)","es":"95°F (35°C)","ru":"95°F (35°C)","tr":"95°F (35°C)","hi":"95°F (35°C)","ar":"95°F (35°C)"},{"en":"110°F (43°C)","es":"110°F (43°C)","ru":"110°F (43°C)","tr":"110°F (43°C)","hi":"110°F (43°C)","ar":"110°F (43°C)"},{"en":"171°F (77°C)","es":"171°F (77°C)","ru":"171°F (77°C)","tr":"171°F (77°C)","hi":"171°F (77°C)","ar":"171°F (77°C)"}],"e":{"en":"The wash water should be at least 110°F (43°C) so the detergent can effectively cut grease and loosen food soil.","es":"El agua de lavado debe estar a por lo menos 110°F (43°C) para que el detergente pueda cortar eficazmente la grasa y aflojar la mugre de la comida.","ru":"Вода для мытья должна быть не менее 110°F (43°C), чтобы моющее средство могло эффективно растворять жир и отделять пищевую грязь.","tr":"Yıkama suyu en az 110°F (43°C) olmalıdır ki deterjan yağı etkili şekilde kesebilsin ve gıda kirini çözebilsin.","hi":"धोने का पानी कम से कम 110°F (43°C) होना चाहिए ताकि डिटर्जेंट प्रभावी ढंग से चिकनाई काट सके और भोजन की मिट्टी को ढीला कर सके।","ar":"يجب أن تكون درجة حرارة ماء الغسل 110°F (43°C) على الأقل حتى يتمكن المنظف من تفتيت الشحوم وتفكيك بقايا الطعام بفعالية."}},{"cat":"cleaning","a":0,"q":{"en":"For chlorine (bleach) sanitizer, which concentration is a commonly accepted range for sanitizing food-contact surfaces?","es":"Para el desinfectante de cloro (lejía), ¿cuál concentración es un rango comúnmente aceptado para desinfectar las superficies en contacto con los alimentos?","ru":"Для хлорного (отбеливающего) дезинфицирующего средства какая концентрация является общепринятым диапазоном для дезинфекции поверхностей, контактирующих с пищей?","tr":"Klor (çamaşır suyu) dezenfektanı için, gıdayla temas eden yüzeyleri dezenfekte etmede yaygın olarak kabul edilen konsantrasyon aralığı hangisidir?","hi":"क्लोरीन (ब्लीच) सैनिटाइज़र के लिए, खाद्य-संपर्क सतहों को सैनिटाइज़ करने के लिए कौन सी सांद्रता आमतौर पर स्वीकृत सीमा है?","ar":"بالنسبة لمطهِّر الكلور (المبيّض)، أي تركيز يُعد نطاقاً مقبولاً عموماً لتطهير الأسطح الملامسة للطعام؟"},"o":[{"en":"50–100 ppm","es":"50–100 ppm","ru":"50–100 ppm","tr":"50–100 ppm","hi":"50–100 ppm","ar":"50–100 ppm"},{"en":"5–10 ppm","es":"5–10 ppm","ru":"5–10 ppm","tr":"5–10 ppm","hi":"5–10 ppm","ar":"5–10 ppm"},{"en":"200–400 ppm","es":"200–400 ppm","ru":"200–400 ppm","tr":"200–400 ppm","hi":"200–400 ppm","ar":"200–400 ppm"},{"en":"500–1000 ppm","es":"500–1000 ppm","ru":"500–1000 ppm","tr":"500–1000 ppm","hi":"500–1000 ppm","ar":"500–1000 ppm"}],"e":{"en":"Chlorine sanitizer is typically used at about 50–100 ppm for food-contact surfaces; too little is ineffective and too much can be unsafe.","es":"El desinfectante de cloro se usa típicamente a aproximadamente 50–100 ppm para las superficies en contacto con los alimentos; muy poco es ineficaz y demasiado puede ser peligroso.","ru":"Хлорное дезинфицирующее средство обычно используется в концентрации около 50–100 ppm для поверхностей, контактирующих с пищей; слишком малое количество неэффективно, а слишком большое может быть небезопасным.","tr":"Klor dezenfektanı gıdayla temas eden yüzeyler için tipik olarak yaklaşık 50–100 ppm'de kullanılır; çok az etkisizdir, çok fazlası ise güvenli olmayabilir.","hi":"क्लोरीन सैनिटाइज़र आमतौर पर खाद्य-संपर्क सतहों के लिए लगभग 50–100 ppm पर उपयोग किया जाता है; बहुत कम अप्रभावी है और बहुत अधिक असुरक्षित हो सकता है।","ar":"يُستخدم مطهِّر الكلور عادةً بتركيز نحو 50–100 ppm للأسطح الملامسة للطعام؛ فالقليل جداً غير فعّال والكثير جداً قد يكون غير آمن."}},{"cat":"cleaning","a":3,"q":{"en":"When sanitizing by hot-water immersion (no chemicals), the water must be held at a minimum of which temperature?","es":"Al desinfectar por inmersión en agua caliente (sin químicos), el agua debe mantenerse a un mínimo de qué temperatura?","ru":"При дезинфекции погружением в горячую воду (без химикатов) вода должна поддерживаться при минимальной температуре в какое значение?","tr":"Sıcak suya daldırarak (kimyasal kullanmadan) dezenfekte ederken, su asgari hangi sıcaklıkta tutulmalıdır?","hi":"गर्म-पानी में डुबोकर (बिना रसायन के) सैनिटाइज़ करते समय, पानी को न्यूनतम किस तापमान पर रखा जाना चाहिए?","ar":"عند التطهير بالغمر في الماء الساخن (بدون مواد كيميائية)، يجب الحفاظ على الماء عند حد أدنى لأي درجة حرارة؟"},"o":[{"en":"120°F (49°C)","es":"120°F (49°C)","ru":"120°F (49°C)","tr":"120°F (49°C)","hi":"120°F (49°C)","ar":"120°F (49°C)"},{"en":"150°F (66°C)","es":"150°F (66°C)","ru":"150°F (66°C)","tr":"150°F (66°C)","hi":"150°F (66°C)","ar":"150°F (66°C)"},{"en":"194°F (90°C)","es":"194°F (90°C)","ru":"194°F (90°C)","tr":"194°F (90°C)","hi":"194°F (90°C)","ar":"194°F (90°C)"},{"en":"171°F (77°C)","es":"171°F (77°C)","ru":"171°F (77°C)","tr":"171°F (77°C)","hi":"171°F (77°C)","ar":"171°F (77°C)"}],"e":{"en":"Manual hot-water sanitizing requires immersing items for at least 30 seconds in water held at 171°F (77°C) or hotter.","es":"La desinfección manual con agua caliente requiere sumergir los artículos durante al menos 30 segundos en agua mantenida a 171°F (77°C) o más caliente.","ru":"Ручная дезинфекция горячей водой требует погружения предметов не менее чем на 30 секунд в воду, поддерживаемую при 171°F (77°C) или горячее.","tr":"Manuel sıcak su dezenfeksiyonu, eşyaların 171°F (77°C) veya daha sıcak suda en az 30 saniye daldırılmasını gerektirir.","hi":"मैनुअल गर्म-पानी सैनिटाइज़िंग के लिए वस्तुओं को 171°F (77°C) या उससे अधिक गर्म पानी में कम से कम 30 सेकंड के लिए डुबोना आवश्यक है।","ar":"يتطلب التطهير اليدوي بالماء الساخن غمر الأدوات لمدة 30 ثانية على الأقل في ماء محفوظ عند 171°F (77°C) أو أعلى."}},{"cat":"cleaning","a":1,"q":{"en":"How should the correct concentration of a chemical sanitizer solution be verified?","es":"¿Cómo debe verificarse la concentración correcta de una solución desinfectante química?","ru":"Как следует проверять правильную концентрацию раствора химического дезинфицирующего средства?","tr":"Bir kimyasal dezenfektan çözeltisinin doğru konsantrasyonu nasıl doğrulanmalıdır?","hi":"रासायनिक सैनिटाइज़र घोल की सही सांद्रता को कैसे सत्यापित किया जाना चाहिए?","ar":"كيف ينبغي التحقق من التركيز الصحيح لمحلول مطهِّر كيميائي؟"},"o":[{"en":"By smelling the solution for a strong chemical odor","es":"Oliendo la solución para detectar un fuerte olor químico","ru":"По запаху раствора на наличие сильного химического запаха","tr":"Çözeltiyi güçlü bir kimyasal koku için koklayarak","hi":"तेज़ रासायनिक गंध के लिए घोल को सूंघकर","ar":"بشمّ المحلول للكشف عن رائحة كيميائية قوية"},{"en":"By using a test kit or test strips made for that sanitizer","es":"Usando un kit de prueba o tiras reactivas hechas para ese desinfectante","ru":"С помощью тест-набора или тест-полосок, предназначенных для этого дезинфицирующего средства","tr":"O dezenfektan için yapılmış bir test kiti veya test şeritleri kullanarak","hi":"उस सैनिटाइज़र के लिए बने टेस्ट किट या टेस्ट स्ट्रिप्स का उपयोग करके","ar":"باستخدام مجموعة اختبار أو شرائح اختبار مصنوعة لذلك المطهِّر"},{"en":"By touching it to see if it feels slippery","es":"Tocándola para ver si se siente resbalosa","ru":"На ощупь, проверяя, скользкий ли он","tr":"Kaygan hissedip hissetmediğini anlamak için dokunarak","hi":"यह देखने के लिए उसे छूकर कि वह फिसलन भरा लगता है या नहीं","ar":"بلمسه لمعرفة ما إذا كان ملمسه زلِقاً"},{"en":"By checking that the water looks cloudy","es":"Comprobando que el agua se vea turbia","ru":"Проверяя, выглядит ли вода мутной","tr":"Suyun bulanık görünüp görünmediğini kontrol ederek","hi":"यह जांचकर कि पानी धुंधला दिखता है","ar":"بالتحقق من أن الماء يبدو عكراً"}],"e":{"en":"Sanitizer strength must be checked with the appropriate test kit or test strips, because the correct concentration cannot be judged by sight, smell, or touch.","es":"La concentración del desinfectante debe comprobarse con el kit de prueba o las tiras reactivas apropiadas, porque la concentración correcta no puede juzgarse por la vista, el olor o el tacto.","ru":"Крепость дезинфицирующего средства необходимо проверять с помощью соответствующего тест-набора или тест-полосок, поскольку правильную концентрацию нельзя определить на вид, по запаху или на ощупь.","tr":"Dezenfektan gücü uygun test kiti veya test şeritleriyle kontrol edilmelidir, çünkü doğru konsantrasyon görme, koku veya dokunmayla anlaşılamaz.","hi":"सैनिटाइज़र की मज़बूती को उपयुक्त टेस्ट किट या टेस्ट स्ट्रिप्स से जांचा जाना चाहिए, क्योंकि सही सांद्रता को दृष्टि, गंध या स्पर्श से नहीं आंका जा सकता।","ar":"يجب التحقق من قوة المطهِّر بمجموعة الاختبار أو شرائح الاختبار المناسبة، لأنه لا يمكن الحكم على التركيز الصحيح بالنظر أو الشمّ أو اللمس."}},{"cat":"cleaning","a":2,"q":{"en":"How often should food-contact surfaces be cleaned and sanitized during continuous use with the same food product?","es":"¿Con qué frecuencia deben limpiarse y desinfectarse las superficies en contacto con los alimentos durante el uso continuo con el mismo producto alimenticio?","ru":"Как часто следует очищать и дезинфицировать поверхности, контактирующие с пищей, при непрерывном использовании с одним и тем же пищевым продуктом?","tr":"Aynı gıda ürünüyle sürekli kullanım sırasında, gıdayla temas eden yüzeyler ne sıklıkla temizlenip dezenfekte edilmelidir?","hi":"एक ही खाद्य उत्पाद के साथ निरंतर उपयोग के दौरान खाद्य-संपर्क सतहों को कितनी बार साफ और सैनिटाइज़ किया जाना चाहिए?","ar":"كم مرة يجب تنظيف الأسطح الملامسة للطعام وتطهيرها أثناء الاستخدام المتواصل مع منتج الطعام نفسه؟"},"o":[{"en":"At least every 8 hours","es":"Por lo menos cada 8 horas","ru":"Не реже чем каждые 8 часов","tr":"En az her 8 saatte bir","hi":"कम से कम हर 8 घंटे में","ar":"كل 8 ساعات على الأقل"},{"en":"Once at the end of each shift","es":"Una vez al final de cada turno","ru":"Один раз в конце каждой смены","tr":"Her vardiyanın sonunda bir kez","hi":"प्रत्येक शिफ्ट के अंत में एक बार","ar":"مرة واحدة في نهاية كل وردية"},{"en":"At least every 4 hours","es":"Por lo menos cada 4 horas","ru":"Не реже чем каждые 4 часа","tr":"En az her 4 saatte bir","hi":"कम से कम हर 4 घंटे में","ar":"كل 4 ساعات على الأقل"},{"en":"Only when they look visibly dirty","es":"Solo cuando se vean visiblemente sucias","ru":"Только когда они выглядят явно грязными","tr":"Yalnızca gözle görülür şekilde kirli göründüklerinde","hi":"केवल जब वे दिखाई देने योग्य गंदी दिखें","ar":"فقط عندما تبدو متسخة بشكل مرئي"}],"e":{"en":"Surfaces in constant contact with TCS food must be cleaned and sanitized at least every 4 hours to limit pathogen growth.","es":"Las superficies en contacto constante con alimentos TCS deben limpiarse y desinfectarse por lo menos cada 4 horas para limitar el crecimiento de patógenos.","ru":"Поверхности, находящиеся в постоянном контакте с TCS-продуктами, должны очищаться и дезинфицироваться не реже чем каждые 4 часа, чтобы ограничить рост патогенов.","tr":"TCS gıdayla sürekli temas eden yüzeyler, patojen büyümesini sınırlamak için en az her 4 saatte bir temizlenip dezenfekte edilmelidir.","hi":"TCS भोजन के निरंतर संपर्क में रहने वाली सतहों को रोगजनक वृद्धि को सीमित करने के लिए कम से कम हर 4 घंटे में साफ और सैनिटाइज़ किया जाना चाहिए।","ar":"يجب تنظيف الأسطح الملامسة باستمرار لطعام TCS وتطهيرها كل 4 ساعات على الأقل للحد من نمو مسببات الأمراض."}},{"cat":"cleaning","a":3,"q":{"en":"A cook finishes cutting raw chicken on a board and now needs to slice lettuce. What must be done first?","es":"Un cocinero termina de cortar pollo crudo en una tabla y ahora necesita rebanar lechuga. ¿Qué debe hacerse primero?","ru":"Повар заканчивает резать сырую курицу на доске и теперь должен нарезать салат-латук. Что нужно сделать в первую очередь?","tr":"Bir aşçı bir tahta üzerinde çiğ tavuk kesmeyi bitiriyor ve şimdi marul dilimlemesi gerekiyor. Önce ne yapılmalıdır?","hi":"एक रसोइया एक बोर्ड पर कच्चा चिकन काटना समाप्त करता है और अब उसे सलाद-पत्ता (lettuce) काटने की आवश्यकता है। पहले क्या किया जाना चाहिए?","ar":"ينتهي طاهٍ من تقطيع دجاج نيء على لوح ويحتاج الآن إلى تقطيع الخس. ما الذي يجب فعله أولاً؟"},"o":[{"en":"Rinse the board with cold water and continue","es":"Enjuagar la tabla con agua fría y continuar","ru":"Сполоснуть доску холодной водой и продолжить","tr":"Tahtayı soğuk suyla durulayıp devam etmek","hi":"बोर्ड को ठंडे पानी से रिंस करें और जारी रखें","ar":"شطف اللوح بماء بارد والمتابعة"},{"en":"Just wipe the board with a dry towel and continue","es":"Solo limpiar la tabla con una toalla seca y continuar","ru":"Просто протереть доску сухим полотенцем и продолжить","tr":"Tahtayı yalnızca kuru bir havluyla silip devam etmek","hi":"बोर्ड को बस एक सूखे तौलिए से पोंछें और जारी रखें","ar":"فقط مسح اللوح بمنشفة جافة والمتابعة"},{"en":"Flip the cutting board over and use the other side","es":"Voltear la tabla de cortar y usar el otro lado","ru":"Перевернуть разделочную доску и использовать другую сторону","tr":"Kesme tahtasını ters çevirip diğer tarafını kullanmak","hi":"कटिंग बोर्ड को पलट दें और दूसरी तरफ का उपयोग करें","ar":"قلب لوح التقطيع واستخدام الجانب الآخر"},{"en":"Clean and sanitize the cutting board and knife before cutting the lettuce","es":"Limpiar y desinfectar la tabla de cortar y el cuchillo antes de cortar la lechuga","ru":"Очистить и продезинфицировать разделочную доску и нож перед нарезкой салата-латука","tr":"Marulu kesmeden önce kesme tahtasını ve bıçağı temizleyip dezenfekte etmek","hi":"सलाद-पत्ता काटने से पहले कटिंग बोर्ड और चाकू को साफ और सैनिटाइज़ करें","ar":"تنظيف لوح التقطيع والسكين وتطهيرهما قبل تقطيع الخس"}],"e":{"en":"Food-contact surfaces must be cleaned and sanitized when switching from raw meat to ready-to-eat food to prevent cross-contamination.","es":"Las superficies en contacto con los alimentos deben limpiarse y desinfectarse al cambiar de carne cruda a alimentos listos para comer para evitar la contaminación cruzada.","ru":"Поверхности, контактирующие с пищей, должны очищаться и дезинфицироваться при переходе от сырого мяса к готовым к употреблению продуктам, чтобы предотвратить перекрёстное загрязнение.","tr":"Çapraz bulaşmayı önlemek için, çiğ etten yemeye hazır gıdaya geçerken gıdayla temas eden yüzeyler temizlenmeli ve dezenfekte edilmelidir.","hi":"क्रॉस-कॉन्टैमिनेशन को रोकने के लिए कच्चे मांस से खाने के लिए तैयार भोजन पर स्विच करते समय खाद्य-संपर्क सतहों को साफ और सैनिटाइज़ किया जाना चाहिए।","ar":"يجب تنظيف الأسطح الملامسة للطعام وتطهيرها عند الانتقال من اللحم النيء إلى الطعام الجاهز للأكل لمنع التلوث المتبادل."}},{"cat":"cleaning","a":1,"q":{"en":"Besides every 4 hours of continuous use, when else must a food-contact surface be cleaned and sanitized?","es":"Además de cada 4 horas de uso continuo, ¿en qué otro momento debe limpiarse y desinfectarse una superficie en contacto con los alimentos?","ru":"Помимо каждых 4 часов непрерывного использования, когда ещё необходимо очищать и дезинфицировать поверхность, контактирующую с пищей?","tr":"Her 4 saatlik sürekli kullanımın yanı sıra, gıdayla temas eden bir yüzey başka ne zaman temizlenip dezenfekte edilmelidir?","hi":"निरंतर उपयोग के हर 4 घंटे के अलावा, खाद्य-संपर्क सतह को और कब साफ और सैनिटाइज़ किया जाना चाहिए?","ar":"بخلاف كل 4 ساعات من الاستخدام المتواصل، متى يجب أيضاً تنظيف السطح الملامس للطعام وتطهيره؟"},"o":[{"en":"Only at the very start of the day","es":"Solo al comienzo del día","ru":"Только в самом начале дня","tr":"Yalnızca günün en başında","hi":"केवल दिन की शुरुआत में","ar":"فقط في بداية اليوم تماماً"},{"en":"Whenever you begin working with a different type of food","es":"Cada vez que comience a trabajar con un tipo diferente de alimento","ru":"Каждый раз, когда вы начинаете работать с другим типом пищи","tr":"Farklı bir gıda türüyle çalışmaya başladığınızda her seferinde","hi":"जब भी आप किसी भिन्न प्रकार के भोजन के साथ काम करना शुरू करें","ar":"كلما بدأت العمل بنوع مختلف من الطعام"},{"en":"Only after the surface is visibly greasy","es":"Solo después de que la superficie esté visiblemente grasosa","ru":"Только после того, как поверхность станет явно жирной","tr":"Yalnızca yüzey gözle görülür şekilde yağlandığında","hi":"केवल सतह के दिखाई देने योग्य चिकना होने के बाद","ar":"فقط بعد أن يصبح السطح دهنياً بشكل مرئي"},{"en":"Once per week during deep cleaning","es":"Una vez por semana durante la limpieza profunda","ru":"Один раз в неделю во время генеральной уборки","tr":"Derin temizlik sırasında haftada bir kez","hi":"गहरी सफाई के दौरान सप्ताह में एक बार","ar":"مرة واحدة أسبوعياً أثناء التنظيف العميق"}],"e":{"en":"Surfaces must also be cleaned and sanitized when changing tasks or food types, after any interruption, and at least every 4 hours during continuous use.","es":"Las superficies también deben limpiarse y desinfectarse al cambiar de tarea o de tipo de alimento, después de cualquier interrupción, y por lo menos cada 4 horas durante el uso continuo.","ru":"Поверхности также должны очищаться и дезинфицироваться при смене задач или типов пищи, после любого перерыва, а также не реже чем каждые 4 часа при непрерывном использовании.","tr":"Yüzeyler ayrıca görev veya gıda türü değiştirildiğinde, herhangi bir kesintiden sonra ve sürekli kullanım sırasında en az her 4 saatte bir temizlenip dezenfekte edilmelidir.","hi":"कार्य या खाद्य प्रकार बदलते समय, किसी भी रुकावट के बाद, और निरंतर उपयोग के दौरान कम से कम हर 4 घंटे में भी सतहों को साफ और सैनिटाइज़ किया जाना चाहिए।","ar":"يجب أيضاً تنظيف الأسطح وتطهيرها عند تغيير المهام أو أنواع الطعام، وبعد أي انقطاع، وكل 4 ساعات على الأقل أثناء الاستخدام المتواصل."}},{"cat":"cleaning","a":0,"q":{"en":"At what maximum temperature should refrigerated (cold) TCS food be received at delivery?","es":"¿A qué temperatura máxima debe recibirse un alimento TCS refrigerado (frío) en la entrega?","ru":"При какой максимальной температуре следует принимать охлаждённые (холодные) TCS-продукты при доставке?","tr":"Soğutulmuş (soğuk) TCS gıda teslimat sırasında hangi azami sıcaklıkta teslim alınmalıdır?","hi":"डिलीवरी के समय रेफ्रिजरेटेड (ठंडे) TCS भोजन को अधिकतम किस तापमान पर प्राप्त किया जाना चाहिए?","ar":"عند أي درجة حرارة قصوى ينبغي استلام طعام TCS المبرّد (البارد) عند التوصيل؟"},"o":[{"en":"41°F (5°C) or lower","es":"41°F (5°C) o menos","ru":"41°F (5°C) или ниже","tr":"41°F (5°C) veya daha düşük","hi":"41°F (5°C) या उससे कम","ar":"41°F (5°C) أو أقل"},{"en":"45°F (7°C) or lower","es":"45°F (7°C) o menos","ru":"45°F (7°C) или ниже","tr":"45°F (7°C) veya daha düşük","hi":"45°F (7°C) या उससे कम","ar":"45°F (7°C) أو أقل"},{"en":"50°F (10°C) or lower","es":"50°F (10°C) o menos","ru":"50°F (10°C) или ниже","tr":"50°F (10°C) veya daha düşük","hi":"50°F (10°C) या उससे कम","ar":"50°F (10°C) أو أقل"},{"en":"32°F (0°C) or lower","es":"32°F (0°C) o menos","ru":"32°F (0°C) или ниже","tr":"32°F (0°C) veya daha düşük","hi":"32°F (0°C) या उससे कम","ar":"32°F (0°C) أو أقل"}],"e":{"en":"Cold TCS foods must be received at 41°F (5°C) or below to keep them out of the temperature danger zone.","es":"Los alimentos TCS fríos deben recibirse a 41°F (5°C) o menos para mantenerlos fuera de la zona de peligro de temperatura.","ru":"Холодные TCS-продукты должны приниматься при 41°F (5°C) или ниже, чтобы держать их вне опасной температурной зоны.","tr":"Soğuk TCS gıdalar, tehlikeli sıcaklık bölgesinin dışında tutmak için 41°F (5°C) veya altında teslim alınmalıdır.","hi":"ठंडे TCS भोजन को खतरनाक तापमान क्षेत्र से बाहर रखने के लिए 41°F (5°C) या उससे कम पर प्राप्त किया जाना चाहिए।","ar":"يجب استلام أطعمة TCS الباردة عند 41°F (5°C) أو أقل لإبقائها خارج منطقة الخطر الحرارية."}},{"cat":"cleaning","a":3,"q":{"en":"How should frozen food appear when it is received from a delivery?","es":"¿Cómo debe verse un alimento congelado cuando se recibe de una entrega?","ru":"Как должна выглядеть замороженная пища при получении от доставки?","tr":"Donmuş gıda bir teslimattan alındığında nasıl görünmelidir?","hi":"डिलीवरी से प्राप्त होने पर फ्रोज़न भोजन कैसा दिखना चाहिए?","ar":"كيف ينبغي أن يبدو الطعام المجمّد عند استلامه من التوصيل؟"},"o":[{"en":"Partially thawed but still cold to the touch","es":"Parcialmente descongelado pero todavía frío al tacto","ru":"Частично размороженной, но всё ещё холодной на ощупь","tr":"Kısmen çözülmüş ama hâlâ dokunulduğunda soğuk","hi":"आंशिक रूप से पिघला हुआ लेकिन फिर भी छूने पर ठंडा","ar":"مذاباً جزئياً لكنه لا يزال بارداً عند اللمس"},{"en":"Soft enough to bend the package","es":"Lo suficientemente blando para doblar el empaque","ru":"Достаточно мягкой, чтобы согнуть упаковку","tr":"Paketi bükecek kadar yumuşak","hi":"पैकेज को मोड़ने के लिए पर्याप्त नरम","ar":"ليّناً بما يكفي لثني العبوة"},{"en":"Coated in a thick layer of ice crystals","es":"Cubierto con una capa gruesa de cristales de hielo","ru":"Покрытой толстым слоем кристаллов льда","tr":"Kalın bir buz kristali tabakasıyla kaplı","hi":"बर्फ के क्रिस्टल की एक मोटी परत से ढका हुआ","ar":"مغطّى بطبقة سميكة من بلورات الثلج"},{"en":"Frozen solid, with no signs of thawing or refreezing","es":"Congelado sólido, sin señales de descongelamiento o recongelación","ru":"Полностью замороженной, без признаков размораживания или повторного замораживания","tr":"Çözülme veya yeniden donma belirtisi olmadan, katı şekilde donmuş","hi":"ठोस रूप से जमा हुआ, पिघलने या फिर से जमने के किसी संकेत के बिना","ar":"مجمّداً بالكامل، دون أي علامات على الذوبان أو إعادة التجميد"}],"e":{"en":"Frozen food must be received frozen solid; large ice crystals or fluids/stains on the packaging are signs of thawing and refreezing, and the food should be rejected.","es":"Los alimentos congelados deben recibirse congelados sólidos; los cristales de hielo grandes o los líquidos/manchas en el empaque son señales de descongelamiento y recongelación, y el alimento debe rechazarse.","ru":"Замороженная пища должна приниматься полностью замороженной; крупные кристаллы льда или жидкость/пятна на упаковке являются признаками размораживания и повторного замораживания, и такую пищу следует отклонить.","tr":"Donmuş gıda katı şekilde donmuş olarak teslim alınmalıdır; büyük buz kristalleri veya ambalajdaki sıvılar/lekeler çözülme ve yeniden donma belirtisidir ve gıda reddedilmelidir.","hi":"फ्रोज़न भोजन को ठोस रूप से जमा हुआ प्राप्त किया जाना चाहिए; बड़े बर्फ के क्रिस्टल या पैकेजिंग पर तरल/दाग पिघलने और फिर से जमने के संकेत हैं, और भोजन को अस्वीकार किया जाना चाहिए।","ar":"يجب استلام الطعام المجمّد مجمّداً بالكامل؛ فبلورات الثلج الكبيرة أو السوائل/البقع على العبوة هي علامات على الذوبان وإعادة التجميد، وينبغي رفض الطعام."}},{"cat":"cleaning","a":2,"q":{"en":"Which condition is a valid reason to REJECT a food delivery?","es":"¿Cuál condición es una razón válida para RECHAZAR una entrega de alimentos?","ru":"Какое условие является обоснованной причиной ОТКЛОНИТЬ доставку пищи?","tr":"Hangi durum bir gıda teslimatını REDDETMEK için geçerli bir nedendir?","hi":"कौन सी स्थिति किसी खाद्य डिलीवरी को अस्वीकार (REJECT) करने का एक वैध कारण है?","ar":"أي حالة تُعد سبباً صحيحاً لرفض توصيلة طعام؟"},"o":[{"en":"Boxes that are clean, dry, and intact","es":"Cajas que estén limpias, secas e intactas","ru":"Коробки, которые чистые, сухие и целые","tr":"Temiz, kuru ve sağlam kutular","hi":"ऐसे बॉक्स जो साफ, सूखे और बरकरार हों","ar":"صناديق نظيفة وجافة وسليمة"},{"en":"Cold milk delivered at 40°F","es":"Leche fría entregada a 40°F","ru":"Холодное молоко, доставленное при 40°F","tr":"40°F'de teslim edilen soğuk süt","hi":"40°F पर डिलीवर किया गया ठंडा दूध","ar":"حليب بارد يُسلَّم عند 40°F"},{"en":"Cans that are dented along the seam, swollen, or leaking","es":"Latas que estén abolladas a lo largo del borde, hinchadas o con fugas","ru":"Банки, которые вмяты по шву, вздуты или протекают","tr":"Dikiş boyunca ezik, şişmiş veya sızdıran konserveler","hi":"ऐसे कैन जो सीवन के साथ पिचके हुए, फूले हुए या रिसते हुए हों","ar":"علب مبعوجة على طول الحافة، أو منتفخة، أو مسرّبة"},{"en":"Frozen vegetables that are still solid","es":"Verduras congeladas que todavía estén sólidas","ru":"Замороженные овощи, которые всё ещё твёрдые","tr":"Hâlâ katı olan donmuş sebzeler","hi":"फ्रोज़न सब्ज़ियां जो अभी भी ठोस हों","ar":"خضروات مجمّدة لا تزال صلبة"}],"e":{"en":"Deliveries should be rejected for damaged, swollen, leaking, or seam-dented cans, as well as wrong temperatures, pests, or broken packaging.","es":"Las entregas deben rechazarse por latas dañadas, hinchadas, con fugas o abolladas en el borde, así como por temperaturas incorrectas, plagas o empaques rotos.","ru":"Доставки следует отклонять из-за повреждённых, вздутых, протекающих или вмятых по шву банок, а также из-за неправильной температуры, вредителей или повреждённой упаковки.","tr":"Teslimatlar; hasarlı, şişmiş, sızdıran veya dikişi ezik konserveler için, ayrıca yanlış sıcaklıklar, haşereler veya bozuk ambalaj için reddedilmelidir.","hi":"क्षतिग्रस्त, फूले हुए, रिसते हुए, या सीवन-पिचके हुए कैन, साथ ही गलत तापमान, कीट, या टूटी पैकेजिंग के लिए डिलीवरी को अस्वीकार किया जाना चाहिए।","ar":"ينبغي رفض التوصيلات بسبب العلب التالفة أو المنتفخة أو المسرّبة أو المبعوجة عند الحافة، وكذلك بسبب درجات الحرارة الخاطئة أو الآفات أو التغليف المكسور."}},{"cat":"cleaning","a":0,"q":{"en":"What does the FIFO (First In, First Out) method of stock rotation mean?","es":"¿Qué significa el método FIFO (Primero en Entrar, Primero en Salir) de rotación de existencias?","ru":"Что означает метод ротации запасов FIFO (First In, First Out — «первым пришёл, первым ушёл»)?","tr":"Stok rotasyonunun FIFO (İlk Giren, İlk Çıkar) yöntemi ne anlama gelir?","hi":"स्टॉक रोटेशन की FIFO (First In, First Out) विधि का क्या अर्थ है?","ar":"ماذا تعني طريقة FIFO (الوارد أولاً يخرج أولاً) في تدوير المخزون؟"},"o":[{"en":"Use the food with the earliest use-by date before newer stock","es":"Usar el alimento con la fecha de caducidad más próxima antes que las existencias más nuevas","ru":"Использовать продукт с самым ранним сроком годности раньше более новых запасов","tr":"En erken son kullanma tarihli gıdayı daha yeni stoktan önce kullanmak","hi":"नए स्टॉक से पहले सबसे पहले की use-by तारीख वाले भोजन का उपयोग करें","ar":"استخدام الطعام ذي أقرب تاريخ استخدام قبل المخزون الأحدث"},{"en":"Use the most recently delivered food first","es":"Usar primero el alimento entregado más recientemente","ru":"Использовать самый недавно доставленный продукт первым","tr":"En son teslim edilen gıdayı ilk kullanmak","hi":"सबसे हाल ही में डिलीवर किए गए भोजन का पहले उपयोग करें","ar":"استخدام الطعام الذي تم توصيله مؤخراً أولاً"},{"en":"Store the heaviest items on the lowest shelf","es":"Almacenar los artículos más pesados en el estante más bajo","ru":"Хранить самые тяжёлые предметы на нижней полке","tr":"En ağır eşyaları en alt rafa koymak","hi":"सबसे भारी वस्तुओं को सबसे निचली शेल्फ पर रखें","ar":"تخزين العناصر الأثقل على الرف الأسفل"},{"en":"Throw out all food after one week regardless of date","es":"Desechar todos los alimentos después de una semana sin importar la fecha","ru":"Выбрасывать всю пищу через неделю независимо от даты","tr":"Tarihe bakılmaksızın tüm gıdayı bir hafta sonra atmak","hi":"तारीख की परवाह किए बिना एक सप्ताह के बाद सभी भोजन फेंक दें","ar":"التخلص من كل الطعام بعد أسبوع واحد بغض النظر عن التاريخ"}],"e":{"en":"FIFO means rotating stock so the products with the soonest use-by or expiration dates are used before newer items, reducing spoilage and waste.","es":"FIFO significa rotar las existencias para que los productos con las fechas de caducidad o vencimiento más próximas se usen antes que los artículos más nuevos, reduciendo el deterioro y el desperdicio.","ru":"FIFO означает ротацию запасов так, чтобы продукты с ближайшими сроками годности или истечения использовались раньше более новых, что снижает порчу и отходы.","tr":"FIFO, stoku, en yakın son kullanma veya bitiş tarihli ürünler daha yeni eşyalardan önce kullanılacak şekilde döndürmek anlamına gelir, böylece bozulma ve israf azaltılır.","hi":"FIFO का अर्थ है स्टॉक को इस तरह घुमाना कि सबसे जल्दी की use-by या समाप्ति तारीख वाले उत्पादों का उपयोग नई वस्तुओं से पहले किया जाए, जिससे खराबी और बर्बादी कम हो।","ar":"تعني FIFO تدوير المخزون بحيث تُستخدم المنتجات ذات أقرب تواريخ الاستخدام أو انتهاء الصلاحية قبل العناصر الأحدث، مما يقلل التلف والهدر."}},{"cat":"cleaning","a":1,"q":{"en":"How far off the floor must stored food be kept in a dry or walk-in storage area?","es":"¿A qué distancia del piso deben mantenerse los alimentos almacenados en un área de almacenamiento seco o cámara de refrigeración?","ru":"На какой высоте от пола должна храниться пища в зоне сухого хранения или холодильной камере?","tr":"Kuru veya soğuk hava deposu alanında saklanan gıda zeminden ne kadar yüksekte tutulmalıdır?","hi":"सूखे या वॉक-इन भंडारण क्षेत्र में संग्रहीत भोजन को फर्श से कितना ऊपर रखा जाना चाहिए?","ar":"ما المسافة التي يجب أن يُحفظ بها الطعام المخزّن عن الأرض في منطقة تخزين جافة أو غرفة تبريد؟"},"o":[{"en":"At least 2 inches","es":"Por lo menos 2 pulgadas","ru":"Не менее 2 дюймов","tr":"En az 2 inç","hi":"कम से कम 2 इंच","ar":"2 بوصات على الأقل"},{"en":"At least 6 inches","es":"Por lo menos 6 pulgadas","ru":"Не менее 6 дюймов","tr":"En az 6 inç","hi":"कम से कम 6 इंच","ar":"6 بوصات على الأقل"},{"en":"At least 12 inches","es":"Por lo menos 12 pulgadas","ru":"Не менее 12 дюймов","tr":"En az 12 inç","hi":"कम से कम 12 इंच","ar":"12 بوصة على الأقل"},{"en":"Directly on the floor is acceptable if boxed","es":"Directamente en el piso es aceptable si está en cajas","ru":"Прямо на полу допустимо, если она в коробках","tr":"Kutuluysa doğrudan zeminde olması kabul edilebilir","hi":"यदि बॉक्स में हो तो सीधे फर्श पर रखना स्वीकार्य है","ar":"التخزين مباشرة على الأرض مقبول إذا كان في صناديق"}],"e":{"en":"Food must be stored at least 6 inches off the floor to protect it from contamination, splash, and pests, and to allow cleaning underneath.","es":"Los alimentos deben almacenarse por lo menos 6 pulgadas por encima del piso para protegerlos de la contaminación, las salpicaduras y las plagas, y para permitir la limpieza debajo de ellos.","ru":"Пища должна храниться на высоте не менее 6 дюймов от пола, чтобы защитить её от загрязнения, брызг и вредителей, а также чтобы можно было убирать под ней.","tr":"Gıda, kirlilik, sıçrama ve haşerelerden korumak ve altının temizlenmesine olanak tanımak için zeminden en az 6 inç yüksekte saklanmalıdır.","hi":"भोजन को संदूषण, छींटे और कीटों से बचाने के लिए, और नीचे सफाई की अनुमति देने के लिए फर्श से कम से कम 6 इंच ऊपर संग्रहीत किया जाना चाहिए।","ar":"يجب تخزين الطعام على ارتفاع 6 بوصات على الأقل عن الأرض لحمايته من التلوث والرذاذ والآفات، وللسماح بالتنظيف تحته."}},{"cat":"cleaning","a":3,"q":{"en":"In a cooler holding several raw and ready-to-eat foods, where should raw chicken be stored relative to the other items?","es":"En un refrigerador que contiene varios alimentos crudos y listos para comer, ¿dónde debe almacenarse el pollo crudo en relación con los demás artículos?","ru":"В холодильнике, где хранится несколько сырых и готовых к употреблению продуктов, где следует хранить сырую курицу относительно других продуктов?","tr":"Birkaç çiğ ve yemeye hazır gıda bulunan bir soğutucuda, çiğ tavuk diğer eşyalara göre nereye saklanmalıdır?","hi":"कई कच्चे और खाने के लिए तैयार भोजन रखने वाले कूलर में, कच्चे चिकन को अन्य वस्तुओं के सापेक्ष कहां संग्रहीत किया जाना चाहिए?","ar":"في ثلاجة تحتوي على عدة أطعمة نيئة وجاهزة للأكل، أين ينبغي تخزين الدجاج النيء بالنسبة إلى العناصر الأخرى؟"},"o":[{"en":"On the top shelf, above all other foods","es":"En el estante superior, por encima de todos los demás alimentos","ru":"На верхней полке, над всеми остальными продуктами","tr":"En üst rafa, tüm diğer gıdaların üstüne","hi":"सबसे ऊपरी शेल्फ पर, अन्य सभी भोजन के ऊपर","ar":"على الرف العلوي، فوق جميع الأطعمة الأخرى"},{"en":"On the same shelf as ready-to-eat salads","es":"En el mismo estante que las ensaladas listas para comer","ru":"На той же полке, что и готовые к употреблению салаты","tr":"Yemeye hazır salatalarla aynı rafa","hi":"खाने के लिए तैयार सलाद के समान शेल्फ पर","ar":"على الرف نفسه مع السلطات الجاهزة للأكل"},{"en":"Anywhere, as long as it is wrapped","es":"En cualquier lugar, siempre que esté envuelto","ru":"Где угодно, лишь бы она была завёрнута","tr":"Sarılı olduğu sürece herhangi bir yere","hi":"कहीं भी, जब तक यह लपेटा हुआ है","ar":"في أي مكان، ما دام مغلّفاً"},{"en":"On the bottom shelf, below all ready-to-eat foods","es":"En el estante inferior, por debajo de todos los alimentos listos para comer","ru":"На нижней полке, ниже всех готовых к употреблению продуктов","tr":"En alt rafa, tüm yemeye hazır gıdaların altına","hi":"सबसे निचली शेल्फ पर, सभी खाने के लिए तैयार भोजन के नीचे","ar":"على الرف السفلي، أسفل جميع الأطعمة الجاهزة للأكل"}],"e":{"en":"Raw poultry has the highest cooking temperature requirement and must be stored on the lowest shelf so its juices cannot drip onto ready-to-eat or other raw foods.","es":"El pollo crudo tiene el requisito de temperatura de cocción más alto y debe almacenarse en el estante más bajo para que sus jugos no goteen sobre los alimentos listos para comer u otros alimentos crudos.","ru":"Сырая птица требует самой высокой температуры приготовления и должна храниться на нижней полке, чтобы её соки не могли капать на готовые к употреблению или другие сырые продукты.","tr":"Çiğ kümes hayvanı en yüksek pişirme sıcaklığı gereksinimine sahiptir ve suları yemeye hazır veya diğer çiğ gıdalara damlayamaması için en alt rafa saklanmalıdır.","hi":"कच्चे पोल्ट्री की पकाने के तापमान की आवश्यकता सबसे अधिक होती है और इसे सबसे निचली शेल्फ पर संग्रहीत किया जाना चाहिए ताकि इसका रस खाने के लिए तैयार या अन्य कच्चे भोजन पर न टपके।","ar":"يتطلب الدواجن النيئة أعلى درجة حرارة طهي ويجب تخزينها على الرف الأسفل بحيث لا تستطيع عصارتها التنقيط على الأطعمة الجاهزة للأكل أو الأطعمة النيئة الأخرى."}},{"cat":"cleaning","a":2,"q":{"en":"How should cleaning chemicals and pesticides be stored in relation to food and food equipment?","es":"¿Cómo deben almacenarse los químicos de limpieza y los pesticidas en relación con los alimentos y el equipo de alimentos?","ru":"Как следует хранить чистящие химикаты и пестициды относительно пищи и пищевого оборудования?","tr":"Temizlik kimyasalları ve böcek ilaçları, gıda ve gıda ekipmanına göre nasıl saklanmalıdır?","hi":"सफाई के रसायनों और कीटनाशकों को भोजन और खाद्य उपकरण के संबंध में कैसे संग्रहीत किया जाना चाहिए?","ar":"كيف ينبغي تخزين مواد التنظيف الكيميائية والمبيدات بالنسبة إلى الطعام ومعدات الطعام؟"},"o":[{"en":"On the shelf directly above the food prep table","es":"En el estante directamente arriba de la mesa de preparación de alimentos","ru":"На полке прямо над столом для приготовления пищи","tr":"Gıda hazırlama tezgâhının tam üstündeki rafta","hi":"फूड प्रेप टेबल के ठीक ऊपर की शेल्फ पर","ar":"على الرف مباشرة فوق طاولة تحضير الطعام"},{"en":"Mixed in with dry food storage to save space","es":"Mezclados con el almacenamiento de alimentos secos para ahorrar espacio","ru":"Вперемешку с сухими продуктами, чтобы сэкономить место","tr":"Yerden tasarruf etmek için kuru gıda deposuyla karışık","hi":"जगह बचाने के लिए सूखे भोजन भंडारण के साथ मिलाकर","ar":"مخلوطة مع تخزين الطعام الجاف لتوفير المساحة"},{"en":"In a separate area, below and away from food, utensils, and equipment","es":"En un área separada, por debajo y lejos de los alimentos, los utensilios y el equipo","ru":"В отдельной зоне, ниже еды и отдельно от пищи, посуды и оборудования","tr":"Ayrı bir alanda, gıdanın, mutfak aletlerinin ve ekipmanın altında ve uzağında","hi":"एक अलग क्षेत्र में, भोजन, बर्तनों और उपकरण के नीचे और उनसे दूर","ar":"في منطقة منفصلة، أسفل الطعام والأدوات والمعدات وبعيداً عنها"},{"en":"Inside the walk-in cooler next to the produce","es":"Dentro de la cámara de refrigeración junto a los productos agrícolas","ru":"Внутри холодильной камеры рядом с продуктами","tr":"Soğuk hava deposunun içinde sebzelerin yanında","hi":"वॉक-इन कूलर के अंदर उपज के बगल में","ar":"داخل غرفة التبريد بجوار المنتجات الطازجة"}],"e":{"en":"Chemicals must be stored in a designated area physically separated from and below food, single-use items, and equipment to prevent contamination.","es":"Los químicos deben almacenarse en un área designada físicamente separada de y por debajo de los alimentos, los artículos de un solo uso y el equipo para evitar la contaminación.","ru":"Химикаты должны храниться в специально отведённой зоне, физически отделённой от пищи, одноразовых предметов и оборудования и ниже их, чтобы предотвратить загрязнение.","tr":"Kimyasallar, bulaşmayı önlemek için gıdadan, tek kullanımlık ürünlerden ve ekipmandan fiziksel olarak ayrılmış ve onların altında, belirlenmiş bir alanda saklanmalıdır.","hi":"संदूषण को रोकने के लिए रसायनों को भोजन, एकल-उपयोग वस्तुओं और उपकरण से भौतिक रूप से अलग और उनके नीचे एक निर्दिष्ट क्षेत्र में संग्रहीत किया जाना चाहिए।","ar":"يجب تخزين المواد الكيميائية في منطقة مخصصة منفصلة فيزيائياً عن الطعام والعناصر أحادية الاستخدام والمعدات وأسفلها، لمنع التلوث."}},{"cat":"cleaning","a":1,"q":{"en":"When a cleaning chemical is transferred from its original container into a spray bottle, what must be done?","es":"Cuando un químico de limpieza se transfiere de su recipiente original a una botella rociadora, ¿qué debe hacerse?","ru":"Когда чистящий химикат переливается из его оригинального контейнера в распылитель, что необходимо сделать?","tr":"Bir temizlik kimyasalı orijinal kabından bir sprey şişeye aktarıldığında ne yapılmalıdır?","hi":"जब किसी सफाई रसायन को उसके मूल कंटेनर से एक स्प्रे बोतल में स्थानांतरित किया जाता है, तो क्या किया जाना चाहिए?","ar":"عند نقل مادة كيميائية للتنظيف من حاويتها الأصلية إلى زجاجة رذاذ، ما الذي يجب فعله؟"},"o":[{"en":"Leave it unlabeled since staff will recognize it","es":"Dejarlo sin etiqueta ya que el personal lo reconocerá","ru":"Оставить его без маркировки, так как персонал его узнает","tr":"Personel tanıyacağı için etiketsiz bırakmak","hi":"इसे बिना लेबल के छोड़ दें क्योंकि स्टाफ इसे पहचान लेगा","ar":"تركها دون ملصق لأن الموظفين سيتعرّفون عليها"},{"en":"Label the working container with the common name of the chemical","es":"Etiquetar el recipiente de trabajo con el nombre común del químico","ru":"Промаркировать рабочий контейнер общепринятым названием химиката","tr":"Kullanım kabını kimyasalın yaygın adıyla etiketlemek","hi":"कार्यशील कंटेनर पर रसायन के सामान्य नाम के साथ लेबल लगाएं","ar":"وضع ملصق على حاوية العمل بالاسم الشائع للمادة الكيميائية"},{"en":"Mark it only with the date it was filled","es":"Marcarlo solo con la fecha en que se llenó","ru":"Отметить его только датой заполнения","tr":"Yalnızca dolduruldğu tarihle işaretlemek","hi":"इसे केवल उस तारीख से चिह्नित करें जिस दिन इसे भरा गया था","ar":"تمييزها فقط بتاريخ تعبئتها"},{"en":"Cover any original label so it cannot be read","es":"Cubrir cualquier etiqueta original para que no pueda leerse","ru":"Закрыть любую оригинальную этикетку, чтобы её нельзя было прочитать","tr":"Okunamayacak şekilde orijinal etiketi kapatmak","hi":"किसी भी मूल लेबल को ढक दें ताकि इसे पढ़ा न जा सके","ar":"تغطية أي ملصق أصلي بحيث لا يمكن قراءته"}],"e":{"en":"Any working container of a chemical must be clearly labeled with the common name of its contents to prevent dangerous mix-ups.","es":"Cualquier recipiente de trabajo de un químico debe estar claramente etiquetado con el nombre común de su contenido para evitar confusiones peligrosas.","ru":"Любой рабочий контейнер с химикатом должен быть чётко промаркирован общепринятым названием его содержимого, чтобы предотвратить опасную путаницу.","tr":"Bir kimyasalın herhangi bir kullanım kabı, tehlikeli karışıklıkları önlemek için içindekinin yaygın adıyla açıkça etiketlenmelidir.","hi":"किसी रसायन के किसी भी कार्यशील कंटेनर पर खतरनाक मिश्रण को रोकने के लिए उसकी सामग्री के सामान्य नाम के साथ स्पष्ट रूप से लेबल लगाया जाना चाहिए।","ar":"يجب وضع ملصق واضح على أي حاوية عمل لمادة كيميائية بالاسم الشائع لمحتوياتها لمنع الخلط الخطير."}},{"cat":"cleaning","a":0,"q":{"en":"Which approach best describes effective pest control in a food establishment?","es":"¿Cuál enfoque describe mejor el control eficaz de plagas en un establecimiento de alimentos?","ru":"Какой подход лучше всего описывает эффективную борьбу с вредителями на пищевом предприятии?","tr":"Bir gıda işletmesinde etkili haşere kontrolünü en iyi hangi yaklaşım tanımlar?","hi":"कौन सा दृष्टिकोण किसी खाद्य प्रतिष्ठान में प्रभावी कीट नियंत्रण का सबसे अच्छा वर्णन करता है?","ar":"أي نهج يصف على أفضل نحو مكافحة الآفات الفعّالة في منشأة غذائية؟"},"o":[{"en":"Deny pests access, food, water, and shelter, and work with a licensed pest control operator","es":"Negar a las plagas el acceso, el alimento, el agua y el refugio, y trabajar con un operador de control de plagas con licencia","ru":"Лишить вредителей доступа, пищи, воды и убежища и работать с лицензированным специалистом по борьбе с вредителями","tr":"Haşerelerin erişimini, gıdayı, suyu ve barınağı engellemek ve lisanslı bir haşere kontrol operatörüyle çalışmak","hi":"कीटों को प्रवेश, भोजन, पानी और आश्रय से वंचित करें, और एक लाइसेंस प्राप्त कीट नियंत्रण ऑपरेटर के साथ काम करें","ar":"منع الآفات من الوصول إلى الدخول والطعام والماء والمأوى، والعمل مع مشغّل مكافحة آفات مرخّص"},{"en":"Spray store-bought insecticide over food prep tables daily","es":"Rociar insecticida comprado en tienda sobre las mesas de preparación de alimentos a diario","ru":"Ежедневно распылять купленный в магазине инсектицид на столы для приготовления пищи","tr":"Gıda hazırlama tezgâhlarına her gün marketten alınan böcek ilacı püskürtmek","hi":"फूड प्रेप टेबल पर रोज़ाना दुकान से खरीदा हुआ कीटनाशक छिड़कें","ar":"رشّ مبيد حشري متجري فوق طاولات تحضير الطعام يومياً"},{"en":"Leave doors propped open so pests can leave on their own","es":"Dejar las puertas abiertas para que las plagas se vayan por sí solas","ru":"Оставлять двери открытыми, чтобы вредители могли уйти сами","tr":"Haşerelerin kendi başlarına çıkabilmesi için kapıları açık bırakmak","hi":"दरवाज़ों को खुला छोड़ दें ताकि कीट स्वयं चले जाएं","ar":"ترك الأبواب مفتوحة كي تخرج الآفات من تلقاء نفسها"},{"en":"Ignore droppings unless a live pest is actually seen","es":"Ignorar los excrementos a menos que realmente se vea una plaga viva","ru":"Игнорировать помёт, пока действительно не увидят живого вредителя","tr":"Canlı bir haşere gerçekten görülmedikçe dışkıları görmezden gelmek","hi":"जब तक कोई जीवित कीट वास्तव में दिखाई न दे तब तक मल को अनदेखा करें","ar":"تجاهل الفضلات ما لم تُرَ آفة حية فعلاً"}],"e":{"en":"An integrated pest management program denies pests entry, food, water, and shelter, and relies on a licensed pest control operator (PCO) for treatment; signs like droppings, gnaw marks, or egg cases indicate an infestation.","es":"Un programa de manejo integrado de plagas niega a las plagas la entrada, el alimento, el agua y el refugio, y depende de un operador de control de plagas con licencia (PCO) para el tratamiento; señales como excrementos, marcas de roeduras o cápsulas de huevos indican una infestación.","ru":"Программа интегрированной борьбы с вредителями лишает вредителей доступа, пищи, воды и убежища и полагается на лицензированного специалиста по борьбе с вредителями (PCO) для обработки; такие признаки, как помёт, следы погрызов или яйцекладки, указывают на заражение.","tr":"Entegre bir haşere yönetimi programı haşerelerin girişini, gıdayı, suyu ve barınağı engeller ve tedavi için lisanslı bir haşere kontrol operatörüne (PCO) dayanır; dışkı, kemirme izleri veya yumurta kılıfları gibi belirtiler bir istilaya işaret eder.","hi":"एक एकीकृत कीट प्रबंधन कार्यक्रम कीटों को प्रवेश, भोजन, पानी और आश्रय से वंचित करता है, और उपचार के लिए एक लाइसेंस प्राप्त कीट नियंत्रण ऑपरेटर (PCO) पर निर्भर करता है; मल, कुतरने के निशान, या अंडे के खोल जैसे संकेत संक्रमण का संकेत देते हैं।","ar":"يمنع برنامج الإدارة المتكاملة للآفات الآفات من الدخول والطعام والماء والمأوى، ويعتمد على مشغّل مكافحة آفات مرخّص (PCO) للمعالجة؛ وتشير علامات مثل الفضلات أو آثار القرض أو حافظات البيض إلى وجود إصابة."}}]};
